const nextJest = require('next/jest')

// Set test environment variables before creating Jest config
process.env.JWT_SECRET = 'test-secret-key'
process.env.JWT_REFRESH_SECRET = 'test-refresh-secret-key'
process.env.SENDGRID_API_KEY = 'test-sendgrid-key'
process.env.STATSIG_SDK_KEY = 'test-statsig-key'
process.env.DATABASE_URL = 'postgresql://testuser:testpass@localhost:5432/testdb'
process.env.NODE_ENV = 'test'

/** @type {import('jest').Config} */
const createJestConfig = nextJest({
  // Provide the path to your Next.js app to load next.config.js and .env files in your test environment
  dir: './',
})

// Add any custom config to be passed to Jest
const config = {
  coverageProvider: 'v8',
  testEnvironment: 'jsdom',
  // Load polyfills in each test worker before setupFilesAfterEnv
  setupFiles: ['<rootDir>/jest.polyfills.js'],
  // Add more setup options before each test is run
  setupFilesAfterEnv: ['<rootDir>/jest.setup.js'],
  moduleNameMapper: {
    '^@/(.*)$': '<rootDir>/src/$1',
  },
  collectCoverageFrom: [
    'src/**/*.{js,jsx,ts,tsx}',
    '!src/**/*.d.ts',
    '!src/**/*.stories.{js,jsx,ts,tsx}',
    '!src/**/__tests__/**',
    '!src/app/layout.tsx',
    '!src/main.tsx',
  ],
  coverageThreshold: {
    global: {
      branches: 70,
      functions: 70,
      lines: 70,
      statements: 70,
    },
  },
  testMatch: [
    '**/__tests__/**/*.[jt]s?(x)',
    '**/?(*.)+(spec|test).[jt]s?(x)',
  ],
  testPathIgnorePatterns: [
    '/node_modules/',
    '/.next/',
    '/dist/',
  ],
}

// createJestConfig is exported this way to ensure that next/jest can load the Next.js config which is async
module.exports = createJestConfig(config)

// Global setup runs once before all test suites
// This is the earliest place to add fetch API polyfills

module.exports = async () => {
  // Load undici and set up global fetch API
  try {
    const { Request, Response, Headers, FormData, fetch } = require('undici');
    
    global.Request = Request;
    global.Response = Response;
    global.Headers = Headers;
    global.FormData = FormData;
    global.fetch = fetch;
    
    console.log('✓ Undici fetch polyfills loaded globally');
  } catch (err) {
    console.error('Failed to load undici polyfills:', err.message);
  }
};

// This runs in each test worker BEFORE setupFilesAfterEnv
// Load undici fetch polyfills for Node test environment

try {
  const { Request, Response, Headers, FormData, fetch } = require('undici');
  
  globalThis.Request = Request;
  globalThis.Response = Response;
  globalThis.Headers = Headers;
  globalThis.FormData = FormData;
  globalThis.fetch = fetch;
} catch (err) {
  // Fail silently - tests will fail with more specific errors if fetch is truly needed
}

