'use client';

import { useState, useEffect } from 'react';
import { useToast } from '@/components/ui/use-toast';
import Link from 'next/link';

interface FeeRecord {
  id: string;
  studentName: string;
  studentId: string;
  grade: string;
  boardingType: string;
  invoiced: number;
  paid: number;
  balance: number;
  status: 'Paid' | 'Partial' | 'Overdue';
  overdueDays?: number;
  avatar?: string;
}

export default function FinanceFeeManagementPage() {
  const { toast } = useToast();
  const [records, setRecords] = useState<FeeRecord[]>([]);
  const [stats, setStats] = useState({ totalRevenue: 0, pendingFees: 0, overdueCount: 0 });
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [paymentsRes, statsRes] = await Promise.all([
            fetch('/api/admin/finance/payments', { headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` } }),
            fetch('/api/admin/finance/stats', { headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` } })
        ]);

        const paymentsJson = await paymentsRes.json();
        const statsJson = await statsRes.json();

        if (paymentsJson.success) {
          setRecords(paymentsJson.data.data || []);
        }
        
        if (statsJson.success) {
            setStats(statsJson.data);
        }

      } catch (error) {
        console.error(error);
        toast({ title: 'Error', description: 'Failed to fetch finance data', variant: 'destructive' });
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [toast]);

  /* Removed Mock Data */

  const filteredRecords = records.filter(r =>
    r.studentName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    r.studentId.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (loading) return <div className="flex items-center justify-center min-h-screen bg-gray-50">Loading...</div>;

  const totalInvoiced = stats.totalRevenue + stats.pendingFees;
  const totalCollected = stats.totalRevenue;
  const outstanding = stats.pendingFees;
  const overdueAccounts = stats.overdueCount;

  return (
    <div className="h-screen flex bg-gray-50 font-sans overflow-hidden">


      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden">
        {/* Header */}
        <header className="bg-gray-50 py-6 px-8 flex flex-col gap-4">
          <div className="flex items-center gap-2 text-sm text-gray-500">
            <Link className="hover:text-blue-600 transition-colors" href="#">Home</Link>
            <span className="material-symbols-outlined text-[14px]">chevron_right</span>
            <Link className="hover:text-blue-600 transition-colors" href="#">Finance</Link>
            <span className="material-symbols-outlined text-[14px]">chevron_right</span>
            <span className="text-gray-900 font-medium">Aging Report</span>
          </div>
          <div className="flex flex-wrap items-end justify-between gap-4">
            <div>
              <h2 className="text-3xl font-bold text-gray-900 tracking-tight">Fee Aging Report</h2>
              <p className="text-gray-500 mt-1 max-w-2xl">
