      <span className={`text-sm font-medium transition-colors ${color}`}>{label}</span>
    </label>
  );
}

function ModuleTag({ label, active }: any) {
  return (
    <span className={`px-3 py-1 rounded-full text-xs font-medium cursor-pointer border border-transparent transition-colors ${active ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300' : 'bg-gray-100 dark:bg-[#282c39] text-gray-600 dark:text-gray-400 hover:border-gray-400'}`}>
      {label}
    </span>
  );
}

function ReleaseCard({ version, date, type, typeColor, typeIcon, tags, title, desc, dots, impact, dotColor = "bg-[#1142d4]", borderColor = "border-gray-200 dark:border-[#3b4154]", bgColor = "bg-white dark:bg-[#1e232e]", warning }: any) {
  return (
    <div className="relative pl-8">
       {/* Timeline Dot */}
       <div className={`absolute -left-[5px] top-6 size-3 rounded-full ${dotColor} ring-4 ring-bg-[#f6f6f8] dark:ring-[#111318]`}></div>
       
       <div className={`flex flex-col gap-4 rounded-xl border ${borderColor} ${bgColor} p-6 shadow-sm hover:shadow-md transition-shadow`}>
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 border-b border-gray-100 dark:border-[#282c39] pb-4">
             <div className="flex flex-col gap-1">
                <div className="flex items-center gap-3">
                   <h3 className="text-xl font-bold text-[#111317] dark:text-white">{version}</h3>
                   <span className={`${typeColor} text-xs font-bold px-2 py-0.5 rounded uppercase tracking-wide flex items-center gap-1`}>
                      {typeIcon && <span className="material-symbols-outlined text-xs">{typeIcon}</span>}
                      {type}
                   </span>
                </div>
                <p className="text-sm text-[#646d87] dark:text-[#9da4b9]">Released on {date}</p>
             </div>
             {type !== 'Critical Security' && (
               <button className="flex items-center gap-2 text-sm font-medium text-[#1142d4] hover:text-blue-400 transition-colors">
                 <span>Read Documentation</span>
                 <span className="material-symbols-outlined text-base">open_in_new</span>
               </button>
             )}
              {type === 'Critical Security' && (
               <button className="flex items-center gap-2 text-sm font-medium text-red-600 dark:text-red-400 hover:text-red-500 transition-colors">
                 <span>Security Bulletin</span>
                 <span className="material-symbols-outlined text-base">shield</span>
               </button>
             )}
          </div>
          
          <div>
            <div className="flex items-center gap-2 mb-2">
               {tags.map((tag: string) => (
                  <span key={tag} className="px-2 py-1 rounded text-xs font-medium bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300">{tag}</span>
               ))}
            </div>
            <h4 className="text-lg font-semibold text-[#111317] dark:text-gray-200 mb-2">{title}</h4>
            <p className="text-[#646d87] dark:text-gray-400 leading-relaxed mb-4">{desc}</p>
            
            {dots && (
               <ul className="list-disc list-inside text-[#646d87] dark:text-gray-400 space-y-1 ml-2 mb-4 text-sm">
                  {dots.map((dot: string, i: number) => <li key={i}>{dot}</li>)}
               </ul>
            )}
          </div>

          {/* Technical Impact Box */}
          {impact && (
            <div className="mt-2 rounded-lg bg-gray-50 dark:bg-[#151921] border border-gray-200 dark:border-[#282c39] overflow-hidden">
               <div className="px-4 py-2 bg-gray-100 dark:bg-[#282c39] border-b border-gray-200 dark:border-[#3b4154] flex items-center gap-2">
                  <span className="material-symbols-outlined text-amber-500 text-sm">construction</span>
                  <span className="text-xs font-bold uppercase tracking-wider text-[#646d87] dark:text-gray-300">Technical Impact Assessment</span>
               </div>
               <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                  {impact.req && (
                    <div>
                      <p className="text-[#9da4b9] text-xs uppercase mb-1">Requirements</p>
                      <p className="text-[#111317] dark:text-gray-300 font-mono text-xs">{impact.req}</p>
                    </div>
                  )}
                  {impact.db && (
                    <div>
                       <p className="text-[#9da4b9] text-xs uppercase mb-1">Database Impact</p>
                       <p className="text-[#111317] dark:text-gray-300 font-mono text-xs">{impact.db}</p>
                    </div>
                  )}
                  {impact.trigger && (
                     <div>
                       <p className="text-[#9da4b9] text-xs uppercase mb-1">Process Trigger</p>
                       <p className="text-[#111317] dark:text-gray-300 font-mono text-xs">{impact.trigger}</p>
                    </div>
                  )}
               </div>
            </div>
          )}

          {/* Warning Box */}
          {warning && (
             <div className="mt-2 rounded-lg bg-red-100/50 dark:bg-red-950/30 border border-red-200 dark:border-red-900/40 overflow-hidden">
               <div className="px-4 py-2 bg-red-100 dark:bg-red-900/20 border-b border-red-200 dark:border-red-900/40 flex items-center gap-2">
                 <span className="material-symbols-outlined text-red-500 text-sm">warning</span>
                 <span className="text-xs font-bold uppercase tracking-wider text-red-700 dark:text-red-300">{warning.title}</span>
               </div>
               <div className="p-4 text-sm">
                 <p className="text-red-800 dark:text-red-200 text-sm mb-2 font-medium">{warning.msg}</p>
                 <p className="text-[#646d87] dark:text-gray-400 text-xs">{warning.sub}</p>
               </div>
             </div>
          )}
       </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';

export default function SetupWizardPage() {
  const router = useRouter();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  
  // Form State
  const [formData, setFormData] = useState({
    schoolName: '',
    schoolMotto: '', // Not in schema yet, but helpful for UI state
    schoolAddress: '',
    schoolPhone: '',
    schoolEmail: '',
    website: '',
    logoUrl: '',
    primaryColor: '#1e40af',
    secondaryColor: '#f59e0b',
    language: 'English (US)',
    academicYear: '2024-2025',
    currentTerm: 'Term 1',
    timezone: 'UTC',
    startStep: 1
  });

  useEffect(() => {
    async function fetchSettings() {
      try {
        const res = await fetch('/api/admin/setup', { cache: 'no-store' });
        const json = await res.json();
        if (json.success && json.data) {
           const d = json.data;
           setFormData(prev => ({
             ...prev,
             schoolName: d.schoolName || '',
             schoolAddress: d.schoolAddress || '',
             schoolPhone: d.schoolPhone || '',
             schoolEmail: d.schoolEmail || '',
             website: d.website || '',
             logoUrl: d.logoUrl || '',
             academicYear: d.academicYear || '2024-2025',
             currentTerm: d.currentTerm || 'Term 1',
             timezone: d.timezone || 'UTC',
           }));
        }
      } catch (err) {
        console.error("Failed to load settings", err);
      } finally {
        setLoading(false);
      }
    }
    fetchSettings();
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const res = await fetch('/api/admin/setup', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(formData)
      });
      
      const json = await res.json();
      if (json.success) {
        alert('Settings saved successfully!');
        // Ideally navigate to next step or dashboard if complete
      } else {
        alert('Failed to save settings: ' + json.message);
      }
    } catch (err) {
      alert('An error occurred while saving.');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center">Loading Setup...</div>;

  return (
    <div className="bg-[#f6f6f8] dark:bg-[#101522] text-slate-900 dark:text-white font-display min-h-screen flex flex-col overflow-hidden transition-colors duration-200">
      {/* Header */}
      <header className="flex-none flex items-center justify-between whitespace-nowrap border-b border-solid border-slate-200 dark:border-[#282c39] px-8 py-4 bg-white dark:bg-[#101522] z-20 transition-colors duration-200">
        <div className="flex items-center gap-4">
          <div className="size-8 rounded bg-[#1142d4]/20 flex items-center justify-center text-[#1142d4]">
            <span className="material-symbols-outlined text-xl">school</span>
          </div>
          <div>
            <h2 className="text-base font-bold leading-tight">System Initialization</h2>
            <p className="text-xs text-[#9da4b9]">{formData.schoolName || 'New School Setup'}</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:flex items-center gap-2 text-xs text-[#9da4b9] px-3 py-1.5 rounded-full bg-slate-100 dark:bg-[#1e222b] border border-slate-200 dark:border-[#282c39]">
            <span className="material-symbols-outlined text-sm">cloud_done</span>
            <span>Auto-saving enabled</span>
          </div>
          <button onClick={handleSave} disabled={saving} className="flex items-center justify-center rounded-lg h-9 px-4 bg-transparent border border-slate-200 dark:border-[#282c39] hover:bg-slate-100 dark:hover:bg-[#1e222b] text-slate-600 dark:text-white text-sm font-medium transition-colors">
            <span className="truncate">{saving ? 'Saving...' : 'Save Draft & Exit'}</span>
          </button>
        </div>
      </header>

      {/* Main Content Layout */}
      <div className="flex flex-1 overflow-hidden">
        {/* Left Sidebar: Stepper */}
        <aside className="hidden lg:flex w-80 flex-col border-r border-slate-200 dark:border-[#282c39] bg-white dark:bg-[#151923] overflow-y-auto transition-colors duration-200">
          <div className="p-6">
            <div className="mb-8">
              <h1 className="text-xl font-bold mb-1">Setup Wizard</h1>
              <p className="text-[#9da4b9] text-sm">Complete these 4 steps to launch your school portal.</p>
            </div>
            <nav className="flex flex-col gap-1 relative">
              {/* Step 1: Active */}
              <div className="group flex items-start gap-4 p-3 rounded-lg bg-[#1142d4]/10 border border-[#1142d4]/20 relative">
                <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#1142d4] rounded-l-lg"></div>
                <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-[#1142d4] text-white text-xs font-bold shadow-sm shadow-[#1142d4]/50">
                  1
                </div>
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-[#1142d4]">School Branding</span>
                  <span className="text-xs text-slate-600 dark:text-slate-400 mt-1">Logo, Name, Typography</span>
                </div>
              </div>
              {/* Connector Line */}
              <div className="ml-[27px] w-px h-6 bg-slate-200 dark:bg-[#282c39]"></div>
              {/* Other Steps (Static for now) */}
              <div className="group flex items-start gap-4 p-3 rounded-lg hover:bg-slate-50 dark:hover:bg-[#1e222b]/50 transition-colors cursor-pointer opacity-50">
                <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full border-2 border-slate-300 dark:border-slate-600 text-slate-400 dark:text-slate-500 text-xs font-medium bg-transparent">
                  2
                </div>
                <div className="flex flex-col">
                  <span className="text-sm font-medium text-slate-700 dark:text-slate-300">Campus Locations</span>
                </div>
              </div>
               <div className="ml-[27px] w-px h-6 bg-slate-200 dark:bg-[#282c39]"></div>
               <div className="group flex items-start gap-4 p-3 rounded-lg hover:bg-slate-50 dark:hover:bg-[#1e222b]/50 transition-colors cursor-pointer opacity-50">
                <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full border-2 border-slate-300 dark:border-slate-600 text-slate-400 dark:text-slate-500 text-xs font-medium bg-transparent">
                  3
                </div>
                <div className="flex flex-col">
                  <span className="text-sm font-medium text-slate-700 dark:text-slate-300">Departments</span>
                </div>
              </div>
            </nav>
          </div>
        </aside>

        {/* Main Form Area */}
        <main className="flex-1 overflow-y-auto bg-slate-50 dark:bg-[#101522] relative transition-colors duration-200">
          <div className="max-w-4xl mx-auto px-6 py-10 md:px-12 md:py-12 pb-32">
            {/* Page Title */}
            <div className="mb-10">
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-3xl font-bold tracking-tight mb-2">School Branding</h2>
                  <p className="text-[#9da4b9] text-base">Configure the visual identity that will be displayed across the student and faculty portals.</p>
                </div>
                <div className="radial-progress text-[#1142d4] text-xs font-bold hidden md:flex items-center justify-center h-12 w-12 rounded-full border-4 border-slate-200 dark:border-[#1e222b] relative">
                  <span className="absolute inset-0 flex items-center justify-center">25%</span>
                </div>
              </div>
            </div>

            <form onSubmit={handleSave} className="space-y-8">
              {/* Section: School Name & Basic Info (NEW) */}
              <div className="bg-white dark:bg-[#1e222b] rounded-xl shadow-sm border border-slate-200 dark:border-[#282c39] overflow-hidden transition-colors duration-200">
                <div className="px-6 py-4 border-b border-slate-200 dark:border-[#282c39] flex justify-between items-center bg-slate-50 dark:bg-[#1a1e26]">
                  <h3 className="text-base font-semibold">General Information</h3>
                </div>
                <div className="p-6 md:p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="col-span-2">
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">School Name</label>
                    <input name="schoolName" value={formData.schoolName} onChange={handleChange} className="block w-full px-3 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] focus:ring-[#1142d4] focus:border-[#1142d4] text-slate-900 dark:text-white" placeholder="e.g. St. Mary's Academy" type="text" required />
                  </div>
                   <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">School Email</label>
                    <input name="schoolEmail" value={formData.schoolEmail} onChange={handleChange} className="block w-full px-3 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] focus:ring-[#1142d4] focus:border-[#1142d4] text-slate-900 dark:text-white" placeholder="admin@school.edu" type="email" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">School Phone</label>
                    <input name="schoolPhone" value={formData.schoolPhone} onChange={handleChange} className="block w-full px-3 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] focus:ring-[#1142d4] focus:border-[#1142d4] text-slate-900 dark:text-white" placeholder="+1 (555) 000-0000" type="tel" />
                  </div>
                </div>
              </div>

              {/* Section: Logo Upload */}
              <div className="bg-white dark:bg-[#1e222b] rounded-xl shadow-sm border border-slate-200 dark:border-[#282c39] overflow-hidden transition-colors duration-200">
                <div className="px-6 py-4 border-b border-slate-200 dark:border-[#282c39] flex justify-between items-center bg-slate-50 dark:bg-[#1a1e26]">
                  <h3 className="text-base font-semibold">Logos & Assets</h3>
                  <span className="material-symbols-outlined text-[#9da4b9] text-lg" title="Required for reports and header">info</span>
                </div>
                <div className="p-6 md:p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                  {/* Primary Logo */}
                  <div className="flex flex-col gap-3">
                    <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Primary Crest / Logo URL</label>
                    {/* Simplified for demo: Text Input for URL instead of Upload */}
                    <input name="logoUrl" value={formData.logoUrl} onChange={handleChange} className="block w-full px-3 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] focus:ring-[#1142d4] focus:border-[#1142d4] text-slate-900 dark:text-white" placeholder="https://example.com/logo.png" type="text" />
                    <p className="text-xs text-[#9da4b9] mt-1">Paste a public URL for the school logo.</p>
                  </div>
                  {/* Logo Preview */}
                  <div className="flex flex-col gap-3">
                    <label className="text-sm font-medium text-slate-700 dark:text-slate-300">Preview</label>
                    <div className="flex-1 rounded-lg bg-slate-100 dark:bg-[#101522] border border-slate-200 dark:border-[#282c39] p-4 flex items-center justify-center relative overflow-hidden h-32">
                      {formData.logoUrl ? (
                          <img src={formData.logoUrl} alt="Logo Preview" className="h-full object-contain" onError={(e) => (e.currentTarget.style.display = 'none')} />
                      ) : (
                          <span className="text-xs text-[#9da4b9] italic">No file selected</span>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              {/* Section: Color Palette */}
              <div className="bg-white dark:bg-[#1e222b] rounded-xl shadow-sm border border-slate-200 dark:border-[#282c39] overflow-hidden transition-colors duration-200">
                <div className="px-6 py-4 border-b border-slate-200 dark:border-[#282c39] flex justify-between items-center bg-slate-50 dark:bg-[#1a1e26]">
                  <h3 className="text-base font-semibold">Theme Colors</h3>
                </div>
                <div className="p-6 md:p-8 space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    {/* Primary Color */}
                    <div>
                      <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Primary Brand Color</label>
                      <div className="flex gap-3">
                        <div className="h-10 w-10 rounded-lg shadow-sm ring-1 ring-white/10" style={{ backgroundColor: formData.primaryColor }}></div>
                        <input name="primaryColor" value={formData.primaryColor} onChange={handleChange} className="block w-full px-3 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] font-mono uppercase" placeholder="#1E40AF" type="text" />
                      </div>
                    </div>
                    {/* Secondary Color */}
                    <div>
                      <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Secondary Accent Color</label>
                       <div className="flex gap-3">
                        <div className="h-10 w-10 rounded-lg shadow-sm ring-1 ring-white/10" style={{ backgroundColor: formData.secondaryColor }}></div>
                        <input name="secondaryColor" value={formData.secondaryColor} onChange={handleChange} className="block w-full px-3 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] font-mono uppercase" placeholder="#F59E0B" type="text" />
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Section: Typography & Localization */}
               <div className="bg-white dark:bg-[#1e222b] rounded-xl shadow-sm border border-slate-200 dark:border-[#282c39] overflow-hidden transition-colors duration-200">
                <div className="px-6 py-4 border-b border-slate-200 dark:border-[#282c39] flex justify-between items-center bg-slate-50 dark:bg-[#1a1e26]">
                  <h3 className="text-base font-semibold">Academic Settings</h3>
                </div>
                <div className="p-6 md:p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Current Academic Year</label>
                    <input name="academicYear" value={formData.academicYear} onChange={handleChange} className="block w-full px-3 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] focus:ring-[#1142d4] focus:border-[#1142d4] text-slate-900 dark:text-white" placeholder="2024-2025" type="text"/>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Current Term</label>
                    <select name="currentTerm" value={formData.currentTerm} onChange={handleChange} className="block w-full pl-3 pr-10 py-2.5 sm:text-sm rounded-lg border-slate-300 dark:border-[#282c39] bg-white dark:bg-[#101522] focus:ring-[#1142d4] focus:border-[#1142d4] text-slate-900 dark:text-white appearance-none">
                      <option>Term 1</option>
                      <option>Term 2</option>
                      <option>Term 3</option>
                      <option>Semester 1</option>
                      <option>Semester 2</option>
                    </select>
                  </div>
                </div>
              </div>
            </form>
          </div>
        </main>

        {/* Footer Actions (Fixed at bottom) */}
        <footer className="flex-none bg-white dark:bg-[#1e222b] border-t border-slate-200 dark:border-[#282c39] px-8 py-4 z-20 transition-colors duration-200">
          <div className="max-w-4xl mx-auto w-full flex items-center justify-between">
            <button className="px-6 py-2.5 rounded-lg border border-slate-300 dark:border-[#282c39] text-slate-700 dark:text-slate-300 font-medium text-sm hover:bg-slate-50 dark:hover:bg-white/5 transition-colors">
              Back
            </button>
            <div className="flex items-center gap-4">
              <span className="text-sm text-[#9da4b9] hidden sm:inline-block">Unsaved changes</span>
              <button onClick={handleSave} disabled={saving} className="flex items-center gap-2 px-8 py-2.5 rounded-lg bg-[#1142d4] hover:bg-[#0e34a5] text-white font-bold text-sm shadow-lg shadow-[#1142d4]/25 transition-all transform hover:scale-[1.02] active:scale-[0.98]">
                {saving ? 'Saving...' : 'Save & Continue'}
                <span className="material-symbols-outlined text-lg">arrow_forward</span>
              </button>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';

interface StaffProfile {
  id: string;
  name: string;
  role: string;
  department: string;
  status: string;
  lastActive: string;
  email: string;
}

interface ActivityLogItem {
    id: number;
    text: string;
    time: string;
    type: string;
}

interface HRAdminData {
  metrics: {
    totalStaff: number;
    activeStaff: number;
    academicPercentage: number;
    attendanceToday: number;
    pendingLeaves: number;
    renewalsDue: number;
  };
  staffList: StaffProfile[];
  activityLog: ActivityLogItem[];
}

export default function StaffPage() {
  const [data, setData] = useState<HRAdminData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [filterDepartment, setFilterDepartment] = useState('All Departments');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('/api/hr/dashboard/admin');
        if (!response.ok) throw new Error('Failed to fetch HR data');
        const result = await response.json();
        if (result.success) {
          setData(result.data);
        } else {
          setError(result.message);
        }
      } catch (err) {
        setError('An error occurred while loading data');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex-1 p-8 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex-1 p-8 flex items-center justify-center text-red-500">
        Error: {error}
      </div>
    );
  }

  if (!data) return null;

  // Filter Logic
  const filteredStaff = data.staffList.filter(staff => {
      if (filterDepartment !== 'All Departments' && staff.department !== filterDepartment) return false;
      // Role filtering would need more complex logic based on role string, skipping for MVP simplicity or add basic check
      return true;
  });

  return (
    <div className="min-h-screen bg-[#f6f6f8] dark:bg-[#111521] text-[#111318] dark:text-[#e2e8f0] font-sans">
      
      <main className="flex-1 w-full max-w-[1440px] mx-auto p-4 md:p-8">
        {/* Page Header */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 mb-8">
          <div>
            <div className="flex items-center gap-2 text-sm text-[#616b89] mb-1">
              <span>Admin Portal</span>
              <span className="material-symbols-outlined text-[14px]">chevron_right</span>
              <span className="text-[#1349ec] font-medium">HR Dashboard</span>
            </div>
            <h1 className="text-3xl font-black tracking-tight text-[#0a192f] dark:text-white">Staff Command Center</h1>
            <p className="text-[#616b89] mt-2">Manage personnel, track attendance, and oversee contract renewals.</p>
          </div>
          <div className="flex gap-3">
            <button className="flex items-center gap-2 px-4 py-2.5 bg-white dark:bg-[#1a202c] border border-gray-200 dark:border-gray-700 rounded-lg text-sm font-semibold text-[#111318] dark:text-white hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors shadow-sm">
              <span className="material-symbols-outlined text-[18px]">download</span>
              Export Report
            </button>
            <button className="flex items-center gap-2 px-4 py-2.5 bg-[#1349ec] hover:bg-[#0c32a6] rounded-lg text-sm font-bold text-white transition-colors shadow-sm shadow-blue-500/30">
              <span className="material-symbols-outlined text-[18px]">person_add</span>
              Onboard New Staff
            </button>
          </div>
        </div>

        {/* KPI Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6 mb-8">
          {/* Card 1: Total Staff */}
          <div className="bg-white dark:bg-[#1a202c] p-5 rounded-xl border border-gray-200 dark:border-gray-800 shadow-sm relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-1 h-full bg-[#1349ec]"></div>
            <div className="flex justify-between items-start mb-4">
              <div>
                <p className="text-[#616b89] text-xs font-bold uppercase tracking-wider">Total Staff</p>
                <h3 className="text-2xl font-black text-[#111318] dark:text-white mt-1">{data.metrics.totalStaff}</h3>
              </div>
              <div className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-[#1349ec]">
                <span className="material-symbols-outlined">groups</span>
              </div>
            </div>
            <div className="flex items-center gap-4 mt-2">
              <div className="flex-1">
                <div className="flex justify-between text-xs mb-1">
                  <span className="text-gray-500">Active</span>
                  <span className="font-bold text-[#111318] dark:text-gray-200">{Math.round((data.metrics.activeStaff / data.metrics.totalStaff) * 100) || 0}%</span>
                </div>
                <div className="w-full bg-gray-100 dark:bg-gray-700 rounded-full h-1.5 overflow-hidden">
                  <div className="bg-[#1349ec] h-1.5 rounded-full" style={{ width: `${(data.metrics.activeStaff / data.metrics.totalStaff) * 100}%` }}></div>
                </div>
              </div>
            </div>
          </div>

          {/* Card 2: Attendance */}
          <div className="bg-white dark:bg-[#1a202c] p-5 rounded-xl border border-gray-200 dark:border-gray-800 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-green-500"></div>
            <div className="flex justify-between items-start mb-4">
              <div>
                <p className="text-[#616b89] text-xs font-bold uppercase tracking-wider">Attendance Today</p>
                <div className="flex items-baseline gap-2 mt-1">
                  <h3 className="text-2xl font-black text-[#111318] dark:text-white">{data.metrics.attendanceToday}%</h3>
                  <span className="text-sm font-medium text-green-600 flex items-center">
                    <span className="material-symbols-outlined text-[16px] mr-0.5">trending_up</span>+2%
                  </span>
                </div>
              </div>
              <div className="p-2 bg-green-50 dark:bg-green-900/20 rounded-lg text-green-600">
                <span className="material-symbols-outlined">calendar_today</span>
              </div>
            </div>
            <p className="text-xs text-[#616b89]">{data.metrics.totalStaff - Math.round((data.metrics.attendanceToday/100) * data.metrics.totalStaff)} staff members absent today</p>
          </div>

          {/* Card 3: Pending Leave */}
          <div className="bg-white dark:bg-[#1a202c] p-5 rounded-xl border border-gray-200 dark:border-gray-800 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-amber-500"></div>
            <div className="flex justify-between items-start mb-4">
              <div>
                <p className="text-[#616b89] text-xs font-bold uppercase tracking-wider">Pending Leave</p>
                <h3 className="text-2xl font-black text-[#111318] dark:text-white mt-1">{data.metrics.pendingLeaves}</h3>
              </div>
              <div className="p-2 bg-amber-50 dark:bg-amber-900/20 rounded-lg text-amber-600 relative">
                {data.metrics.pendingLeaves > 0 && <span className="absolute top-0 right-0 size-2 bg-red-500 rounded-full border border-white"></span>}
                <span className="material-symbols-outlined">rule</span>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <span className="bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300 text-[10px] font-bold px-2 py-0.5 rounded uppercase">Action Required</span>
            </div>
          </div>

          {/* Card 4: Renewals */}
          <div className="bg-white dark:bg-[#1a202c] p-5 rounded-xl border border-gray-200 dark:border-gray-800 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-purple-500"></div>
            <div className="flex justify-between items-start mb-4">
              <div>
                <p className="text-[#616b89] text-xs font-bold uppercase tracking-wider">Renewals Due</p>
                <h3 className="text-2xl font-black text-[#111318] dark:text-white mt-1">{data.metrics.renewalsDue}</h3>
              </div>
              <div className="p-2 bg-purple-50 dark:bg-purple-900/20 rounded-lg text-purple-600">
                <span className="material-symbols-outlined">contract</span>
              </div>
            </div>
            <div className="flex -space-x-2 overflow-hidden mt-1">
               {data.metrics.renewalsDue > 0 ? (
                 <span className="text-xs text-purple-600 font-medium">{data.metrics.renewalsDue} contracts expiring soon</span>
               ) : (
                 <span className="text-xs text-green-600 font-medium">All contracts up to date</span>
               )}
            </div>
          </div>
        </div>

        {/* Main Workspace (Table + Sidebar) */}
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">
          {/* Staff Directory Section (Left) */}
          <div className="xl:col-span-9 bg-white dark:bg-[#1a202c] border border-gray-200 dark:border-gray-800 rounded-xl shadow-sm flex flex-col">
            {/* Toolbar */}
            <div className="p-5 border-b border-gray-100 dark:border-gray-800 flex flex-wrap gap-4 items-center justify-between">
              <h3 className="text-lg font-bold text-[#111318] dark:text-white">Staff Directory</h3>
              <div className="flex flex-wrap items-center gap-3">
                {/* Filters */}
                <div className="flex items-center gap-2">
                  <div className="relative">
                    <select 
                      value={filterDepartment}
                      onChange={(e) => setFilterDepartment(e.target.value)}
                      className="appearance-none pl-3 pr-8 py-2 bg-[#f0f1f4] dark:bg-gray-800 text-sm font-medium rounded-lg border-none focus:ring-0 text-[#111318] dark:text-white cursor-pointer hover:bg-gray-200 transition-colors"
                    >
                      <option>All Departments</option>
                      {Array.from(new Set(data.staffList.map(s => s.department))).map(d => <option key={d}>{d}</option>)}
                    </select>
                    <span className="material-symbols-outlined text-gray-500 absolute right-2 top-2 pointer-events-none text-[20px]">expand_more</span>
                  </div>
                </div>
                {/* Table Search */}
                <div className="relative">
                  <span className="material-symbols-outlined absolute left-3 top-2 text-gray-400 text-[20px]">search</span>
                  <input className="pl-9 pr-4 py-2 bg-white dark:bg-[#101522] border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:border-[#1349ec] focus:ring-1 focus:ring-[#1349ec] w-48 lg:w-64" placeholder="Search name or ID..." type="text" />
                </div>
              </div>
            </div>

            {/* Table */}
            <div className="overflow-x-auto flex-1">
              <table className="w-full text-left border-collapse">
                <thead className="bg-[#f9fafb] dark:bg-gray-800/50 sticky top-0 z-10 text-xs uppercase text-[#616b89] font-bold tracking-wider">
                  <tr>
                    <th className="px-6 py-4 border-b border-gray-100 dark:border-gray-700">Staff Member</th>
                    <th className="px-6 py-4 border-b border-gray-100 dark:border-gray-700">Role</th>
                    <th className="px-6 py-4 border-b border-gray-100 dark:border-gray-700">Department</th>
