'use client'

import React, { useState, useEffect } from 'react'

interface Student {
    id: string;
    studentId: string;
    firstName: string;
    lastName: string;
    email: string;
    grade: string;
    className: string;
    status: string;
    parentInfo: {
        name: string;
        email: string;
        phone: string;
        relationship: string;
    };
    // Include other fields as needed
}

export default function StudentRecordsPage() {
    const [searchTerm, setSearchTerm] = useState('')
    const [students, setStudents] = useState<Student[]>([])
    const [stats, setStats] = useState({ totalEnrollment: 0, newStudents: 0, activeStudents: 0, graduatingClass: 0 })
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState('')
    const [page, setPage] = useState(1)
    const [totalPages, setTotalPages] = useState(1)

    // Filters
    const [selectedGrade, setSelectedGrade] = useState('All Grades')
    const [selectedStatus, setSelectedStatus] = useState('All Status')

    useEffect(() => {
        const fetchStudents = async () => {
            setLoading(true)
            try {
                const params = new URLSearchParams({
                    page: page.toString(),
                    limit: '10',
                    search: searchTerm,
                })
                
                if (selectedGrade !== 'All Grades') params.append('grade', selectedGrade)
                if (selectedStatus !== 'All Status') params.append('status', selectedStatus)

                const res = await fetch(`/api/admin/students?${params.toString()}`, {
                    headers: {
                        'Authorization': `Bearer ${localStorage.getItem('token')}` // Ensure we send the token
                    }
                })
                
                if (!res.ok) {
                    if (res.status === 401) throw new Error("Unauthorized")
                    throw new Error("Failed to fetch")
                }

                const json = await res.json()
                if (json.success) {
                    setStudents(json.data.data)
                    setTotalPages(json.data.totalPages)
                    if (json.data.stats) setStats(json.data.stats)
                } else {
                    setError(json.message)
                }
            } catch (err) {
                console.error(err)
                setError('Failed to load students')
            } finally {
                setLoading(false)
            }
        }

        // Debounce search slightly
        const timeoutId = setTimeout(() => {
            fetchStudents()
        }, 300)

        return () => clearTimeout(timeoutId)
    }, [searchTerm, page, selectedGrade, selectedStatus])

    return (
        <div className="flex flex-col h-full">
            {/* Header */}
            <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Student Records</h1>
                    <p className="text-sm text-gray-500">Manage enrollment and academic records</p>
                </div>
                <div className="flex gap-3">
                    <button className="px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 flex items-center gap-2">
                        <span className="material-symbols-outlined text-[20px]">upload</span>
                        Import CSV
                    </button>
                    <button className="px-4 py-2 bg-brand-navy text-white rounded-lg text-sm font-medium hover:bg-navy-900 flex items-center gap-2">
                        <span className="material-symbols-outlined text-[20px]">add</span>
                        Add Student
                    </button>
                </div>
            </header>

            <main className="flex-1 p-6 md:p-8 max-w-[1600px] mx-auto w-full">
                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
                    <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                <span className="material-symbols-outlined">school</span>
                            </div>
                        </div>
                        <h3 className="text-2xl font-bold text-gray-900">{stats.totalEnrollment}</h3>
                        <p className="text-sm text-gray-500">Total Enrollment</p>
                    </div>
                    <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-2 bg-green-50 text-green-600 rounded-lg">
                                <span className="material-symbols-outlined">person_add</span>
                            </div>
                            <span className="text-xs font-semibold text-green-600 bg-green-50 px-2 py-1 rounded">New</span>
                        </div>
                        <h3 className="text-2xl font-bold text-gray-900">{stats.newStudents}</h3>
                        <p className="text-sm text-gray-500">New Students (30d)</p>
                    </div>
                    <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-2 bg-purple-50 text-purple-600 rounded-lg">
                                <span className="material-symbols-outlined">how_to_reg</span>
                            </div>
                        </div>
                        <h3 className="text-2xl font-bold text-gray-900">{stats.activeStudents}</h3>
                        <p className="text-sm text-gray-500">Active Students</p>
                    </div>
                     <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-2 bg-orange-50 text-orange-600 rounded-lg">
                                <span className="material-symbols-outlined">workspace_premium</span>
                            </div>
                        </div>
                        <h3 className="text-2xl font-bold text-gray-900">{stats.graduatingClass}</h3>
                        <p className="text-sm text-gray-500">Graduating Class</p>
                    </div>
                </div>

                {/* Table Section */}
                <div className="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
                    {/* Toolbar */}
                    <div className="p-4 border-b border-gray-200 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                        <div className="relative w-full sm:w-96">
                            <span className="material-symbols-outlined absolute left-3 top-2.5 text-gray-400 text-[20px]">search</span>
                            <input 
                                type="text" 
                                placeholder="Search by name, ID, or email..." 
                                className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-brand-navy/20 focus:border-brand-navy"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="flex items-center gap-2">
                            <select 
                                value={selectedGrade}
                                onChange={(e) => setSelectedGrade(e.target.value)}
                                className="pl-3 pr-8 py-2 border border-gray-200 rounded-lg text-sm bg-white focus:outline-none focus:ring-2 focus:ring-brand-navy/20"
                            >
                                <option>All Grades</option>
                                <option>Form 1</option>
                                <option>Form 2</option>
                                <option>Form 3</option>
                                <option>Form 4</option>
                                <option>Lower 6</option>
                                <option>Upper 6</option>
                            </select>
                            <select 
                                value={selectedStatus}
                                onChange={(e) => setSelectedStatus(e.target.value)}
                                className="pl-3 pr-8 py-2 border border-gray-200 rounded-lg text-sm bg-white focus:outline-none focus:ring-2 focus:ring-brand-navy/20"
                            >
                                <option>All Status</option>
                                <option>Active</option>
                                <option>Pending</option>
                                <option>Suspended</option>
                            </select>
                        </div>
                    </div>

                    {/* Table */}
                    <div className="overflow-x-auto min-h-[400px]">
                        {loading ? (
                             <div className="flex justify-center items-center h-64 text-gray-400">Loading...</div>
                        ) : error ? (
                             <div className="flex justify-center items-center h-64 text-red-500">{error}</div>
                        ) : (
                        <table className="w-full text-left text-sm">
                            <thead className="bg-gray-50 border-b border-gray-200 text-gray-600 font-semibold">
                                <tr>
                                    <th className="px-6 py-4">Student Name</th>
                                    <th className="px-6 py-4">Grade/Form</th>
                                    <th className="px-6 py-4">House</th>
                                    <th className="px-6 py-4">Guardian</th>
                                    <th className="px-6 py-4">Status</th>
                                    <th className="px-6 py-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {students.map((student) => (
                                    <tr key={student.id} className="hover:bg-gray-50 transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-full bg-brand-navy text-white flex items-center justify-center font-bold text-xs uppercase">
                                                    {student.firstName[0]}{student.lastName[0]}
                                                </div>
                                                <div>
                                                    <div className="font-medium text-gray-900">{student.firstName} {student.lastName}</div>
                                                    <div className="text-xs text-gray-500">{student.email}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-gray-700">{student.grade}</td>
                                        <td className="px-6 py-4 text-gray-700">{'Blue'}</td> {/* Default House for now */}
                                        <td className="px-6 py-4 text-gray-700">{student.parentInfo?.name || 'N/A'}</td>
                                        <td className="px-6 py-4">
                                            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${
                                                student.status === 'ACTIVE' || student.status === 'Active' ? 'bg-green-50 text-green-700 border-green-100' :
                                                student.status === 'PENDING' ? 'bg-yellow-50 text-yellow-700 border-yellow-100' :
                                                student.status === 'SUSPENDED' ? 'bg-red-50 text-red-700 border-red-100' :
                                                'bg-gray-50 text-gray-700 border-gray-100'
                                            }`}>
                                                {student.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <button className="text-gray-400 hover:text-brand-navy transition-colors p-1 rounded-full hover:bg-gray-100">
                                                <span className="material-symbols-outlined text-[20px]">more_vert</span>
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                                {students.length === 0 && (
                                    <tr>
                                        <td colSpan={6} className="text-center py-8 text-gray-500">
                                            No students found.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                        )}
                    </div>
                    
                    {/* Pagination - Simple Implementation */}
                    <div className="px-6 py-4 border-t border-gray-200 flex justify-center gap-2">
                        <button 
                            disabled={page === 1}
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            className="px-3 py-1 border rounded disabled:opacity-50"
                        >
                            Previous
                        </button>
                        <span className="px-3 py-1">Page {page} of {totalPages}</span>
                        <button 
                             disabled={page === totalPages}
                             onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                             className="px-3 py-1 border rounded disabled:opacity-50"
                        >
                            Next
                        </button>
                    </div>
                </div>
            </main>
        </div>
    )
}

'use client';

import React, { useState, useEffect } from 'react';

interface ClassItem {
  id: string;
  name: string;
  grade: string;
}

interface SubjectItem {
  id: string;
  name: string;
  teacher?: { firstName: string; lastName: string };
}

interface ScheduleItem {
  id: string;
  dayOfWeek: string;
  startTime: string;
  endTime: string;
  room?: string;
  subject: {
    name: string;
    teacher?: { firstName: string; lastName: string };
  };
}

export default function TimetablePage() {
  const [classes, setClasses] = useState<ClassItem[]>([]);
  const [subjects, setSubjects] = useState<SubjectItem[]>([]);
  const [selectedClassId, setSelectedClassId] = useState<string>('');
  const [schedule, setSchedule] = useState<Record<string, ScheduleItem[]>>({});
  const [loading, setLoading] = useState(true);

  const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];
  const timeSlots = ['08:00', '09:00', '10:00', '11:00', '12:00', '13:00', '14:00', '15:00'];

  useEffect(() => {
    const fetchMetadata = async () => {
      try {
        const [classesRes, subjectsRes] = await Promise.all([
          fetch('/api/admin/classes', { headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` } }),
          fetch('/api/admin/subjects', { headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` } })
        ]);

        const classesJson = await classesRes.json();
        const subjectsJson = await subjectsRes.json();

        if (classesJson.success) {
          setClasses(classesJson.data);
          if (classesJson.data.length > 0) {
            setSelectedClassId(classesJson.data[0].id);
          }
        }

        if (subjectsJson.success) {
          setSubjects(subjectsJson.data);
        }
      } catch (error) {
        console.error('Error fetching metadata:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchMetadata();
  }, []);

  useEffect(() => {
    if (!selectedClassId) return;

    const fetchSchedule = async () => {
      try {
        const res = await fetch(`/api/admin/timetable?classId=${selectedClassId}`, {
          headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
        });
        const json = await res.json();
        if (json.success) {
          setSchedule(json.data);
        } else {
          setSchedule({});
        }
      } catch (error) {
        console.error('Error fetching schedule:', error);
        setSchedule({}); // Clear on error
      }
    };
    fetchSchedule();
  }, [selectedClassId]);

  const getScheduleForSlot = (day: string, time: string) => {
    const daySchedule = schedule[day] || [];
    // Simple matching for now: find entry starting at this time (or close to it?)
    // Assuming strict slot matching based on API data usually being aligned.
    // In a real app, we'd check ranges.
    return daySchedule.find(item => item.startTime.startsWith(time.substring(0, 2))); // Match "08" from "08:30" if strictly bucketed, or just strict match.
    // Let's assume strict match for the "start" of the block for this simple grid.
    // If API returns "08:00", checking "08:00" works.
  };

  if (loading) return <div className="flex items-center justify-center min-h-screen bg-gray-50">Loading timetable...</div>;

  return (
    <div className="flex h-screen w-full flex-col overflow-hidden bg-[#f6f6f8] dark:bg-[#111521] text-[#111317] dark:text-[#e2e8f0]">
      
      <main className="flex flex-1 overflow-hidden">
        {/* Sidebar: Subjects & Tools */}
        <aside className="w-80 flex-shrink-0 flex flex-col border-r border-[#dcdee5] dark:border-[#334155] bg-white dark:bg-[#1e293b] overflow-y-auto z-10">
          <div className="p-6 border-b border-[#dcdee5] dark:border-[#334155]">
            <h1 className="text-xl font-bold tracking-tight mb-1">Timetable Engine</h1>
            <p className="text-sm text-[#646d87] dark:text-[#94a3b8]">Manage Schedules</p>
            
            <div className="mt-6">
                <label className="block text-xs font-bold text-[#646d87] dark:text-[#94a3b8] uppercase mb-2">Select Class</label>
                <select 
                    value={selectedClassId} 
                    onChange={(e) => setSelectedClassId(e.target.value)}
                    className="w-full rounded-lg border-[#dcdee5] dark:border-[#334155] bg-[#f6f6f8] dark:bg-[#111521] text-sm py-2 px-3"
                >
                    {classes.map(cls => (
                        <option key={cls.id} value={cls.id}>{cls.name} ({cls.grade})</option>
                    ))}
                    {classes.length === 0 && <option value="">No classes found</option>}
                </select>
            </div>
          </div>
          
          <div className="flex-1 p-4 space-y-6">
            {/* Subjects List (Draggables placeholder) */}
            <div>
              <div className="flex items-center justify-between mb-3 px-2">
                <h3 className="text-xs font-bold uppercase tracking-wider text-[#646d87] dark:text-[#94a3b8]">Available Subjects</h3>
                <span className="bg-gray-200 dark:bg-gray-700 text-[#646d87] dark:text-[#94a3b8] text-[10px] font-bold px-1.5 py-0.5 rounded">{subjects.length}</span>
              </div>
              <div className="space-y-2">
                {subjects.map((item) => (
                  <div key={item.id} className="group flex items-center gap-3 p-3 rounded-lg bg-[#f6f6f8] dark:bg-[#111521] border border-transparent hover:border-[#2957e0]/30 cursor-grab active:cursor-grabbing transition-all hover:shadow-sm">
                    <div className={`flex items-center justify-center size-8 rounded bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400`}>
                      <span className="material-symbols-outlined text-lg">book</span>
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-[#111317] dark:text-[#e2e8f0]">{item.name}</p>
                      {item.teacher && <p className="text-xs text-[#646d87] dark:text-[#94a3b8]">{item.teacher.firstName} {item.teacher.lastName}</p>}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </aside>

        {/* Main Workspace: Calendar Grid */}
        <section className="flex-1 flex flex-col min-w-0 bg-[#f6f6f8] dark:bg-[#111521] relative">
          {/* Context Bar */}
          <div className="flex items-center justify-between px-6 py-4 bg-white dark:bg-[#1e293b] border-b border-[#dcdee5] dark:border-[#334155]">
            <div className="flex items-center gap-4">
              <p className="text-sm text-[#646d87] dark:text-[#94a3b8]">Editing Schedule for: <span className="text-[#111317] dark:text-[#e2e8f0] font-medium">{classes.find(c => c.id === selectedClassId)?.name || '...'}</span></p>
            </div>
            {/* Actions removed for brevity/scope of audit - keeping layout clean */}
          </div>

          {/* Calendar Grid Container */}
          <div className="flex-1 overflow-auto p-6">
            <div className="min-w-[1000px] bg-white dark:bg-[#1e293b] rounded-xl shadow-sm border border-[#dcdee5] dark:border-[#334155] overflow-hidden">
              {/* Table Header */}
              <div className="grid grid-cols-[100px_repeat(5,1fr)] bg-gray-50 dark:bg-gray-800/50 border-b border-[#dcdee5] dark:border-[#334155]">
                <div className="p-4 text-xs font-bold text-[#646d87] dark:text-[#94a3b8] uppercase tracking-wider text-center flex items-center justify-center">Time</div>
                {days.map((day, i) => (
                  <div key={day} className={`p-4 text-center ${i > 0 ? 'border-l border-[#dcdee5] dark:border-[#334155]' : ''}`}>
                    <span className="block text-sm font-bold text-[#111317] dark:text-[#e2e8f0]">{day}</span>
                  </div>
                ))}
              </div>

              {/* Table Body */}
              <div className="divide-y divide-[#dcdee5] dark:divide-[#334155]">
                {timeSlots.map((time) => (
                    <div key={time} className="grid grid-cols-[100px_repeat(5,1fr)] min-h-[120px]">
                        <div className="p-4 text-xs font-medium text-[#646d87] dark:text-[#94a3b8] text-right bg-gray-50/50 dark:bg-gray-800/30">
                            {time}
                        </div>
                        {days.map((day) => {
                            const entry = getScheduleForSlot(day, time);
                            return (
                                <div key={`${day}-${time}`} className="p-2 border-l border-[#dcdee5] dark:border-[#334155] relative group hover:bg-gray-50 dark:hover:bg-gray-800/20 transition-colors">
                                    {entry ? (
                                        <div className="h-full w-full rounded-lg bg-blue-50 dark:bg-blue-900/20 border-l-4 border-blue-500 p-2 cursor-pointer hover:shadow-md transition-all">
                                            <div className="flex justify-between items-start">
                                                <span className="text-xs font-bold text-blue-700 dark:text-blue-300">{entry.subject.name}</span>
                                                <span className="material-symbols-outlined text-[16px] text-blue-400">more_horiz</span>
                                            </div>
                                            <div className="mt-1 text-xs text-blue-600/80 dark:text-blue-400/80">
                                                {entry.room && <div className="flex items-center gap-1"><span className="material-symbols-outlined text-[14px]">location_on</span> {entry.room}</div>}
                                                {entry.subject.teacher && <div className="flex items-center gap-1"><span className="material-symbols-outlined text-[14px]">person</span> {entry.subject.teacher.lastName}</div>}
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="h-full w-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                            <span className="material-symbols-outlined text-gray-300">add</span>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ))}
              </div>
            </div>
          </div>
        </section>
      </main>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';

interface TransportStats {
  totalVehicles: { value: number; subtext: string };
  activeRoutes: { value: number; subtext: string };
  fuelEfficiency: { current: number; unit: string; trend: string };
  nextService: { value: number; subtext: string };
}

interface Vehicle {
  id: string;
  vehicleId: string;
  driver: { name: string; image: string | null };
  route: string;
  status: string;
  fuel: string;
  odometer: string;
  lastService: string;
}

interface TransportData {
  stats: TransportStats;
  fleet: Vehicle[];
}

export default function TransportPage() {
  const [data, setData] = useState<TransportData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('All Status');
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('/api/transport/dashboard');
        if (!response.ok) throw new Error('Failed to fetch transport data');
        const result = await response.json();
        if (result.success) {
          setData(result.data);
        } else {
          setError(result.message);
        }
      } catch (err) {
        setError('An error occurred while loading data');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex-1 p-8 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex-1 p-8 flex items-center justify-center text-red-500">
        Error: {error}
      </div>
    );
  }

  if (!data) return null;

  const filteredFleet = data.fleet.filter(vehicle => {
    const matchesStatus = filterStatus === 'All Status' || vehicle.status === filterStatus;
    const matchesSearch = vehicle.vehicleId.toLowerCase().includes(searchQuery.toLowerCase()) ||
                          vehicle.driver.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  return (
    <div className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8">
      <div className="mx-auto max-w-[1400px] flex flex-col gap-6">
        {/* Page Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex flex-col gap-1">
            <h1 className="text-slate-900 dark:text-white text-3xl font-black leading-tight tracking-[-0.033em]">
              Fleet Management
            </h1>
            <p className="text-slate-500 dark:text-[#9dabb9] text-base font-normal">
              Real-time transport command center
            </p>
          </div>
          <div className="flex gap-3">
            <button className="flex items-center justify-center rounded-lg h-10 px-4 bg-white dark:bg-[#283039] border border-slate-200 dark:border-[#3b4754] text-slate-700 dark:text-white text-sm font-bold hover:bg-slate-50 dark:hover:bg-[#323b46] transition-colors">
              <span className="mr-2 material-symbols-outlined text-[18px]">history</span>
              <span>History</span>
            </button>
            <button className="flex items-center justify-center rounded-lg h-10 px-4 bg-primary hover:bg-primary/90 text-white text-sm font-bold shadow-lg shadow-blue-500/20 transition-colors">
              <span className="mr-2 material-symbols-outlined text-[18px]">download</span>
              <span>Download Report</span>
            </button>
          </div>
        </div>

        {/* KPI Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {/* Card 1 */}
          <div className="flex flex-col gap-2 rounded-xl p-6 bg-white dark:bg-[#1c242f] border border-slate-200 dark:border-[#283039] shadow-sm">
            <div className="flex items-center justify-between">
              <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">
                Total Vehicles
              </p>
              <div className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-primary">
                <span className="material-symbols-outlined">directions_bus</span>
              </div>
            </div>
            <div className="flex items-end gap-3 mt-2">
              <p className="text-slate-900 dark:text-white text-3xl font-bold leading-none">{data.stats.totalVehicles.value}</p>
              <p className="text-slate-400 dark:text-[#9dabb9] text-sm font-medium mb-1">
                {data.stats.totalVehicles.subtext}
              </p>
            </div>
          </div>
          {/* Card 2 */}
          <div className="flex flex-col gap-2 rounded-xl p-6 bg-white dark:bg-[#1c242f] border border-slate-200 dark:border-[#283039] shadow-sm">
            <div className="flex items-center justify-between">
              <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">
                Active Routes
              </p>
              <div className="p-2 bg-emerald-50 dark:bg-emerald-900/20 rounded-lg text-emerald-500">
                <span className="material-symbols-outlined">route</span>
              </div>
            </div>
            <div className="flex items-end gap-3 mt-2">
              <p className="text-slate-900 dark:text-white text-3xl font-bold leading-none">{data.stats.activeRoutes.value}</p>
              <div className="flex items-center text-emerald-500 text-sm font-medium mb-1 gap-1">
                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                {data.stats.activeRoutes.subtext}
              </div>
            </div>
          </div>
          {/* Card 3 */}
          <div className="flex flex-col gap-2 rounded-xl p-6 bg-white dark:bg-[#1c242f] border border-slate-200 dark:border-[#283039] shadow-sm">
            <div className="flex items-center justify-between">
              <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">
                Fuel Efficiency
              </p>
              <div className="p-2 bg-indigo-50 dark:bg-indigo-900/20 rounded-lg text-indigo-500">
                <span className="material-symbols-outlined">trending_up</span>
              </div>
            </div>
            <div className="flex items-end gap-3 mt-2">
              <p className="text-slate-900 dark:text-white text-3xl font-bold leading-none">
                {data.stats.fuelEfficiency.current} <span className="text-lg font-normal text-slate-400">{data.stats.fuelEfficiency.unit}</span>
              </p>
              <p className="text-emerald-500 text-sm font-medium mb-1">{data.stats.fuelEfficiency.trend} vs last month</p>
            </div>
          </div>
          {/* Card 4 */}
          <div className="flex flex-col gap-2 rounded-xl p-6 bg-white dark:bg-[#1c242f] border border-slate-200 dark:border-[#283039] shadow-sm">
            <div className="flex items-center justify-between">
              <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">
                Next Service
              </p>
              <div className="p-2 bg-amber-50 dark:bg-amber-900/20 rounded-lg text-amber-500">
                <span className="material-symbols-outlined">car_repair</span>
              </div>
            </div>
            <div className="flex items-end gap-3 mt-2">
              <p className="text-slate-900 dark:text-white text-3xl font-bold leading-none">{data.stats.nextService.value}</p>
              <p className="text-amber-500 text-sm font-medium mb-1">{data.stats.nextService.subtext}</p>
            </div>
          </div>
        </div>

        {/* Main Content Split */}
        <div className="grid lg:grid-cols-3 gap-6 h-full min-h-[600px]">
          {/* Map Section (Takes up 2/3 on large screens) */}
          <div className="lg:col-span-2 flex flex-col rounded-xl overflow-hidden border border-slate-200 dark:border-[#283039] bg-white dark:bg-[#1c242f] shadow-sm relative group">
            {/* Toolbar overlaid on map */}
            <div className="absolute top-4 left-4 right-4 z-10 flex flex-col sm:flex-row justify-between gap-4 pointer-events-none">
              <label className="pointer-events-auto flex flex-col min-w-[200px] sm:min-w-[300px] shadow-lg">
                <div className="flex w-full items-stretch rounded-lg h-10 md:h-12 bg-white dark:bg-[#101922] border border-slate-200 dark:border-transparent">
                  <div className="text-slate-500 dark:text-[#9dabb9] flex items-center justify-center pl-4 rounded-l-lg">
                    <span className="material-symbols-outlined">search</span>
                  </div>
                  <input
                    className="form-input flex w-full min-w-0 flex-1 resize-none overflow-hidden rounded-lg text-slate-900 dark:text-white focus:outline-0 focus:ring-0 border-none bg-transparent focus:border-none h-full placeholder:text-slate-400 dark:placeholder:text-[#9dabb9] px-4 rounded-l-none pl-2 text-sm md:text-base font-normal"
                    placeholder="Search vehicle or route ID"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
              </label>
              <div className="flex flex-col gap-2 items-end pointer-events-auto">
                <div className="flex flex-col shadow-lg rounded-lg overflow-hidden bg-white dark:bg-[#101922] border border-slate-200 dark:border-transparent">
                  <button className="flex size-10 items-center justify-center text-slate-700 dark:text-white hover:bg-slate-50 dark:hover:bg-[#1c242f] border-b border-slate-100 dark:border-[#283039]">
                    <span className="material-symbols-outlined">add</span>
                  </button>
                  <button className="flex size-10 items-center justify-center text-slate-700 dark:text-white hover:bg-slate-50 dark:hover:bg-[#1c242f]">
                    <span className="material-symbols-outlined">remove</span>
                  </button>
                </div>
                <button className="flex size-10 items-center justify-center rounded-lg bg-white dark:bg-[#101922] text-primary shadow-lg border border-slate-200 dark:border-transparent hover:bg-slate-50 dark:hover:bg-[#1c242f]">
                  <span className="material-symbols-outlined">navigation</span>
                </button>
              </div>
            </div>

            {/* Map Background */}
            <div className="w-full h-full bg-slate-100 dark:bg-[#0f151c] relative min-h-[500px]">
              {/* Static Map Image Representation */}
              <div
                className="absolute inset-0 bg-cover bg-center opacity-80 dark:opacity-60"
                data-alt="Dark themed map of city streets"
                data-location="New York City"
                style={{
                  backgroundImage:
                    'url("https://lh3.googleusercontent.com/aida-public/AB6AXuCJRlrNY0EhNDafyx2Z4Vf7hQ8tBIBCWGZBxwUXSwkB-e9lZzcm3Nd__68F1TRLtt-G2dxf4D8dwJgZ6UpCopI3qKx-spBz7GPR5bUm7MR538YZTO5Hu2Mb3Pv4kwgGBTtvoSLaUugZ9TOMT27O4G2gexeKvoRZk9xeK843IFGY7y7U5Hi18DCwUDcAGv8oQVd0ZLzAnZUjEqhdgCEW8LwwScEA8np8lCPwuC798HdAUbue-_U8sPj_REL7gyEFOM1DFU1CDEsGYoc")',
                }}
              ></div>
              
              {/* Markers for first 5 vehicles to avoid overcrowding */}
              {data.fleet.slice(0, 5).map((vehicle, index) => {
                // Generate pseudo-random positions for demo visual
                const top = 20 + ((index * 15) % 60); 
                const left = 20 + ((index * 25) % 60); 
                
                return (
                  <div 
                    key={vehicle.id} 
                    className="absolute flex flex-col items-center gap-1 group/marker cursor-pointer"
                    style={{ top: `${top}%`, left: `${left}%` }}
                  >
                    <div className="px-2 py-1 bg-white dark:bg-[#1c242f] rounded shadow text-xs font-bold text-slate-900 dark:text-white opacity-0 group-hover/marker:opacity-100 transition-opacity whitespace-nowrap border border-slate-200 dark:border-[#3b4754]">
                      {vehicle.vehicleId} ({vehicle.status})
                    </div>
                    <div className={`size-8 rounded-full border-2 border-white dark:border-[#1c242f] shadow-lg flex items-center justify-center text-white transform hover:scale-110 transition-transform ${
                      vehicle.status === 'On Time' ? 'bg-emerald-500' :
                      vehicle.status === 'Delayed' ? 'bg-amber-500 animate-bounce' :
                      vehicle.status === 'Maintenance' ? 'bg-red-500' : 'bg-slate-400'
                    }`}>
                      <span className="material-symbols-outlined text-[16px]">
                        {vehicle.status === 'Maintenance' ? 'build' : vehicle.status === 'Idle' ? 'local_parking' : 'directions_bus'}
                      </span>
                    </div>
                  </div>
                );
              })}

            </div>

            {/* Bottom Info Bar inside Map */}
            <div className="absolute bottom-0 left-0 right-0 bg-white/95 dark:bg-[#1c242f]/95 backdrop-blur-sm border-t border-slate-200 dark:border-[#283039] p-4 flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 rounded-full bg-emerald-500"></span>
                  <span className="text-xs font-medium text-slate-600 dark:text-slate-300">
                    On Route
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 rounded-full bg-amber-500"></span>
                  <span className="text-xs font-medium text-slate-600 dark:text-slate-300">
                    Delayed
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 rounded-full bg-slate-400"></span>
                  <span className="text-xs font-medium text-slate-600 dark:text-slate-300">
                    Idle
                  </span>
                </div>
              </div>
              <div className="text-xs text-slate-400 dark:text-slate-500 font-mono">
                Last Updated: Just now
              </div>
            </div>
          </div>

          {/* Side Panel / Fleet List */}
          <div className="flex flex-col rounded-xl border border-slate-200 dark:border-[#283039] bg-white dark:bg-[#1c242f] shadow-sm overflow-hidden">
            <div className="p-4 border-b border-slate-200 dark:border-[#283039] flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-900 dark:text-white">Active Fleet</h3>
              <button className="text-primary text-sm font-bold hover:underline">View All</button>
            </div>
            <div className="flex-1 overflow-y-auto">
              {filteredFleet.length === 0 ? (
                <div className="p-4 text-center text-slate-500">No vehicles found.</div>
              ) : (
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-[#202a36] text-slate-500 dark:text-[#9dabb9] font-medium sticky top-0 z-10">
                    <tr>
                      <th className="px-4 py-3">Vehicle</th>
                      <th className="px-4 py-3">Status</th>
                      <th className="px-4 py-3 text-right">Cap.</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100 dark:divide-[#283039]">
                    {filteredFleet.map((vehicle) => (
                      <tr key={vehicle.id} className="hover:bg-slate-50 dark:hover:bg-[#242d38] transition-colors cursor-pointer group">
                        <td className="px-4 py-3">
                          <div className="flex items-center gap-3">
                            <div className="bg-slate-100 dark:bg-[#283039] rounded-full p-2 text-slate-500 dark:text-slate-300">
                              <span className="material-symbols-outlined text-[18px]">
                                directions_bus
                              </span>
                            </div>
                            <div>
                              <p className="font-bold text-slate-900 dark:text-white">{vehicle.vehicleId}</p>
                              <p className="text-xs text-slate-500 dark:text-slate-400">
                                {vehicle.route} • {vehicle.driver.name}
                              </p>
                            </div>
                          </div>
                        </td>
                        <td className="px-4 py-3">
                          <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                            vehicle.status === 'On Time' ? 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-400' :
                            vehicle.status === 'Delayed' ? 'bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-400' :
                            vehicle.status === 'Maintenance' ? 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400' :
                            'bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300'
                          }`}>
                            {vehicle.status}
                          </span>
                        </td>
                        <td className="px-4 py-3 text-right">
                          <div className="flex flex-col items-end gap-1">
                            <span className="text-slate-700 dark:text-slate-200 font-medium">32/40</span>
                            <div className="w-16 h-1.5 bg-slate-100 dark:bg-[#3b4754] rounded-full overflow-hidden">
                              <div className="h-full bg-emerald-500 w-[80%]"></div>
                            </div>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
            <div className="p-4 border-t border-slate-200 dark:border-[#283039]">
              <button className="w-full py-2 rounded-lg border border-slate-200 dark:border-[#3b4754] text-slate-600 dark:text-slate-300 text-sm font-bold hover:bg-slate-50 dark:hover:bg-[#323b46] transition-colors">
                Dispatch New Vehicle
              </button>
            </div>
          </div>
        </div>

        {/* Detailed Data Table Section */}
        <div className="flex flex-col rounded-xl border border-slate-200 dark:border-[#283039] bg-white dark:bg-[#1c242f] shadow-sm mb-8">
          <div className="p-5 border-b border-slate-200 dark:border-[#283039] flex flex-wrap gap-4 justify-between items-center">
            <h3 className="text-lg font-bold text-slate-900 dark:text-white">
              Detailed Fleet Roster
            </h3>
            <div className="flex items-center gap-2">
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 material-symbols-outlined text-slate-400 text-[18px]">
                  filter_list
                </span>
                <select 
                  className="pl-9 pr-8 py-2 bg-slate-50 dark:bg-[#283039] border-none rounded-lg text-sm font-medium text-slate-700 dark:text-slate-300 focus:ring-1 focus:ring-primary outline-none"
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value)}
                >
                  <option value="All Status">All Status</option>
                  <option value="On Time">On Time</option>
                  <option value="Delayed">Delayed</option>
                  <option value="Idle">Idle</option>
                  <option value="Maintenance">Maintenance</option>
                </select>
              </div>
              <button className="flex items-center justify-center p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-[#283039] text-slate-500 dark:text-slate-400">
                <span className="material-symbols-outlined">more_vert</span>
              </button>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 dark:bg-[#202a36] text-slate-500 dark:text-[#9dabb9] text-xs uppercase tracking-wider font-semibold">
                <tr>
                  <th className="px-6 py-4 border-b border-slate-200 dark:border-[#283039]">
                    Vehicle ID
                  </th>
                  <th className="px-6 py-4 border-b border-slate-200 dark:border-[#283039]">
                    Driver
                  </th>
                  <th className="px-6 py-4 border-b border-slate-200 dark:border-[#283039]">
                    Route
                  </th>
                  <th className="px-6 py-4 border-b border-slate-200 dark:border-[#283039]">
                    Fuel Level
                  </th>
                  <th className="px-6 py-4 border-b border-slate-200 dark:border-[#283039]">
                    Odometer
                  </th>
                  <th className="px-6 py-4 border-b border-slate-200 dark:border-[#283039]">
                    Last Service
                  </th>
                  <th className="px-6 py-4 border-b border-slate-200 dark:border-[#283039] text-right">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-[#283039] text-sm">
                {filteredFleet.length === 0 ? (
                    <tr>
                        <td colSpan={7} className="px-6 py-4 text-center text-slate-500">
                            No vehicles found.
                        </td>
                    </tr>
                ) : (
                    filteredFleet.map((vehicle) => (
                    <tr key={vehicle.id} className="hover:bg-slate-50 dark:hover:bg-[#242d38] transition-colors">
                      <td className="px-6 py-4 text-slate-900 dark:text-white font-medium">
                        {vehicle.vehicleId}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <div
                            className="size-6 rounded-full bg-slate-200 dark:bg-slate-600 flex items-center justify-center text-xs font-bold text-slate-600 dark:text-slate-200"
                          >
                            {vehicle.driver.name.charAt(0)}
                          </div>
                          <span className="text-slate-700 dark:text-slate-300">{vehicle.driver.name}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-600 dark:text-slate-400">
                        {vehicle.route}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <span className={`material-symbols-outlined text-[18px] ${parseInt(vehicle.fuel) < 40 ? 'text-amber-500' : 'text-emerald-500'}`}>
                            local_gas_station
                          </span>
                          <span className="text-slate-900 dark:text-white font-medium">{vehicle.fuel}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{vehicle.odometer}</td>
                      <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{vehicle.lastService}</td>
                      <td className="px-6 py-4 text-right">
                        <button className="text-primary font-medium hover:text-primary/80">
                          Manage
                        </button>
                      </td>
                    </tr>
                    ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useToast } from '@/components/ui/use-toast';
;

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  roleColor: string;
  accessModules: string[];
  status: 'Active' | 'Away' | 'Disabled';
  lastLogin: string;
  lastIP: string;
  avatar?: string;
}

// Default permissions structure
const DEFAULT_PERMISSIONS = {
  finance: {
    view_reports: true,
    process_payments: false,
    manage_payroll: false,
  },
  students: {
    view_profiles: true,
    edit_records: false,
    delete_records: false,
  }
};

const SYSTEM_ROLES = ['Super Admin', 'Teacher', 'Registrar', 'Accountant'];

export default function SystemUserManagementPage() {
  const { toast } = useToast();
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedTab, setSelectedTab] = useState('staff');
  
  // Permissions State
  const [selectedRoleToEdit, setSelectedRoleToEdit] = useState('Accountant');
  const [permissionSettings, setPermissionSettings] = useState(DEFAULT_PERMISSIONS);
  const [isSavingPermissions, setIsSavingPermissions] = useState(false);

  useEffect(() => {
    const fetchUsers = async () => {
      try {
        const res = await fetch('/api/admin/users', {
          headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
        });
        const json = await res.json();
        if (json.success) {
          // Normalize user data from API if needed, for now assuming simpler shape or mock fallback
          const apiUsers = json.users.map((u: any) => ({
             id: u.id,
             name: `${u.firstName} ${u.lastName}`,
             email: u.email,
             role: u.role,
             roleColor: getRoleColor(u.role),
             accessModules: [], // API doesn't return this yet
             status: u.status === 'active' ? 'Active' : 'Disabled',
             lastLogin: 'N/A',
             lastIP: 'N/A'
          }));
          setUsers(apiUsers.length ? apiUsers : []);
        } else {
          setUsers([]);
        }
      } catch (error) {
        console.error(error);
        setUsers([]);
      } finally {
        setLoading(false);
      }
    };
    fetchUsers();
  }, []);

  const getRoleColor = (role: string) => {
    switch(role.toLowerCase()) {
        case 'super admin': return 'purple';
        case 'teacher': return 'blue';
        case 'registrar': return 'indigo';
        case 'accountant': return 'teal';
        default: return 'gray';
    }
  };

  /* Removed Mock Users */

  const filteredUsers = users.filter(u =>
    u.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    u.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
    u.role.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const togglePermission = (category: keyof typeof DEFAULT_PERMISSIONS, key: string) => {
    setPermissionSettings(prev => ({
      ...prev,
      [category]: {
        ...prev[category],
        [key]: !prev[category][key as keyof typeof prev[typeof category]]
      }
    }));
  };

  const handleSavePermissions = async () => {
    setIsSavingPermissions(true);
    try {
      const res = await fetch('/api/admin/roles/permissions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify({
          role: selectedRoleToEdit,
          permissions: permissionSettings
        })
      });

      const json = await res.json();
      
      if (res.ok) {
        toast({
          title: "Permissions Saved",
          description: `Access rights for ${selectedRoleToEdit} have been updated.`,
        });
      } else {
        throw new Error(json.message || 'Failed to update');
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to save permissions. Please try again.",
        variant: "destructive"
      });
    } finally {
      setIsSavingPermissions(false);
    }
  };

  if (loading) return <div className="flex items-center justify-center min-h-screen bg-gray-50">Loading...</div>;

  return (
    <div className="overflow-hidden flex h-screen w-full bg-gray-50 font-sans">
      {/* Sidebar removed - using AdminLayout sidebar */}


      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden bg-gray-50">
        {/* Page Header */}
        <div className="px-6 py-8 md:px-10 w-full bg-white border-b border-gray-200">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 max-w-7xl mx-auto">
            <div>
              <h1 className="text-3xl md:text-4xl font-black tracking-tight text-gray-900 mb-2">User & Role Management</h1>
              <p className="text-gray-500 text-base max-w-2xl">Manage system access, define roles, and configure granular permissions for staff members.</p>
            </div>
            <div className="flex gap-3">
              <button className="flex items-center justify-center gap-2 h-10 px-4 rounded-lg bg-white border border-gray-200 text-gray-900 hover:bg-gray-50 transition-colors text-sm font-bold shadow-sm">
                <span className="material-symbols-outlined text-[20px]">history</span>
                <span>Audit Logs</span>
              </button>
              <button className="flex items-center justifycenter gap-2 h-10 px-4 rounded-lg bg-blue-600 text-white hover:bg-blue-700 transition-colors text-sm font-bold shadow-sm">
                <span className="material-symbols-outlined text-[20px]">add</span>
                <span>Add New User</span>
              </button>
            </div>
          </div>
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto px-6 md:px-10 py-6 max-w-7xl mx-auto w-full">
          {/* Tabs */}
          <div className="border-b border-gray-200 mb-6">
            <div className="flex gap-8">
              <button
                onClick={() => setSelectedTab('staff')}
                className={`flex items-center gap-2 border-b-[3px] pb-3 px-1 transition-colors ${
                  selectedTab === 'staff' ? 'border-blue-600 text-gray-900' : 'border-transparent text-gray-500 hover:text-blue-600'
                }`}
              >
                <span className="material-symbols-outlined text-[20px]">badge</span>
                <span className="text-sm font-bold">Staff Users</span>
              </button>
              <button
                onClick={() => setSelectedTab('roles')}
                className={`flex items-center gap-2 border-b-[3px] pb-3 px-1 transition-colors ${
                  selectedTab === 'roles' ? 'border-blue-600 text-gray-900' : 'border-transparent text-gray-500 hover:text-blue-600'
                }`}
              >
                <span className="material-symbols-outlined text-[20px]">shield_person</span>
                <span className="text-sm font-bold">Role Permissions</span>
              </button>
              <button
                onClick={() => setSelectedTab('security')}
                className={`flex items-center gap-2 border-b-[3px] pb-3 px-1 transition-colors ${
                  selectedTab === 'security' ? 'border-blue-600 text-gray-900' : 'border-transparent text-gray-500 hover:text-blue-600'
                }`}
              >
                <span className="material-symbols-outlined text-[20px]">lock</span>
                <span className="text-sm font-bold">Security Policies</span>
              </button>
            </div>
          </div>

          {selectedTab === 'staff' && (
            <>
              {/* Filters & Search */}
              <div className="flex flex-col sm:flex-row justify-between gap-4 mb-6 bg-white p-4 rounded-xl shadow-sm border border-gray-200">
                <div className="relative flex-1 max-w-md">
                  <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">search</span>
                  <input
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-10 pr-4 h-10 rounded-lg bg-gray-50 border-none focus:ring-2 focus:ring-blue-600 text-sm text-gray-900 placeholder-gray-500"
                    placeholder="Search by name, email, or role..."
                    type="text"
                  />
                </div>
                <div className="flex gap-2">
                  <button className="flex items-center gap-2 h-10 px-3 rounded-lg bg-gray-50 border-none text-gray-900 hover:bg-gray-100 transition-colors text-sm font-medium">
                    <span className="material-symbols-outlined text-[20px]">filter_list</span>
                    <span>Filter</span>
                  </button>
                  <button className="flex items-center gap-2 h-10 px-3 rounded-lg bg-gray-50 border-none text-gray-900 hover:bg-gray-100 transition-colors text-sm font-medium">
                    <span className="material-symbols-outlined text-[20px]">download</span>
                    <span>Export</span>
                  </button>
                </div>
              </div>

              {/* Users Table */}
              <div className="rounded-xl border border-gray-200 bg-white overflow-hidden shadow-sm mb-8">
                <div className="overflow-x-auto">
                  <table className="w-full min-w-[800px]">
                    <thead>
                      <tr className="bg-gray-50 border-b border-gray-200">
                        <th className="px-6 py-4 text-left text-xs font-semibold uppercase tracking-wider text gray-500 w-1/4">Name / Email</th>
                        <th className="px-6 py-4 text-left text-xs font-semibold uppercase tracking-wider text-gray-500">Role</th>
                        <th className="px-6 py-4 text-left text-xs font-semibold uppercase tracking-wider text-gray-500">Access Level</th>
                        <th className="px-6 py-4 text-left text-xs font-semibold uppercase tracking-wider text-gray-500">Status</th>
                        <th className="px-6 py-4 text-left text-xs font-semibold uppercase tracking-wider text-gray-500">Last Login</th>
                        <th className="px-6 py-4 text-right text-xs font-semibold uppercase tracking-wider text-gray-500">Actions</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {filteredUsers.map((user) => (
                        <tr key={user.id} className="hover:bg-gray-50 transition-colors group">
                          <td className="px-6 py-4">
                            <div className="flex items-center gap-3">
                              {user.avatar ? (
                                <img src={user.avatar} alt={user.name} className="size-10 rounded-full object-cover" />
                              ) : (
                                <div className={`size-10 rounded-full bg-${user.roleColor}-100 flex items-center justify-center text-${user.roleColor}-600 font-bold`}>
                                  {user.name.substring(0, 2)}
                                </div>
                              )}
                              <div>
                                <p className="text-sm font-semibold text-gray-900">{user.name}</p>
                                <p className="text-xs text-gray-500">{user.email}</p>
                              </div>
                            </div>
                          </td>
                          <td className="px-6 py-4">
                            <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-${user.roleColor}-100 text-${user.roleColor}-800`}>
                              <span className={`w-1.5 h-1.5 rounded-full bg-${user.roleColor}-500`}></span>
                              {user.role}
                            </span>
                          </td>
                          <td className="px-6 py-4">
                            <div className="flex -space-x-2">
                              {user.accessModules.slice(0, 3).map((module, idx) => (
                                <div key={idx} className="size-6 rounded-full bg-gray-100 border border-white flex items-center justify-center text-[10px] text-gray-500" title={module}>
                                  {module.substring(0, 2)}
                                </div>
                              ))}
                              {user.accessModules.length > 3 && (
                                <div className="size-6 rounded-full bg-gray-100 border border-white flex items-center justify-center text-[10px] text-gray-500">
                                  +{user.accessModules.length - 3}
                                </div>
                              )}
                            </div>
                          </td>
                          <td className="px-6 py-4">
                            <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium ${
                              user.status === 'Active' ? 'bg-green-100 text-green-800' :
                              user.status === 'Away' ? 'bg-yellow-100 text-yellow-800' :
                              'bg-gray-100 text-gray-800'
                            }`}>
                              {user.status}
                            </span>
                          </td>
                          <td className="px-6 py-4">
                            <p className="text-sm text-gray-900">{user.lastLogin}</p>
                            <p className="text-xs text-gray-500">IP: {user.lastIP}</p>
                          </td>
                          <td className="px-6 py-4 text-right">
                            <button className="text-gray-500 hover:text-blue-600 p-1 rounded-md hover:bg-gray-100 transition-colors">
                              <span className="material-symbols-outlined text-[20px]">more_vert</span>
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                {/* Pagination */}
                <div className="px-6 py-4 border-t border-gray-200 flex items-center justify-between">
                  <p className="text-sm text-gray-500">
                    Showing <span className="font-bold text-gray-900">1-{filteredUsers.length}</span> of <span className="font-bold text-gray-900">{users.length}</span> users
                  </p>
                  <div className="flex gap-2">
                    <button className="px-3 py-1 rounded border border-gray-200 text-sm text-gray-500 hover:bg-gray-50 disabled:opacity-50" disabled>
                      Previous
                    </button>
                    <button className="px-3 py-1 rounded border border-gray-200 text-sm text-gray-500 hover:bg-gray-50">
                      Next
                    </button>
                  </div>
                </div>
              </div>
            </>
          )}

          {selectedTab === 'roles' && (
            /* Granular Permissions Panel */
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
              {/* Role Info */}
              <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm h-fit">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="p-2 rounded-lg bg-teal-100 text-teal-600">
                      <span className="material-symbols-outlined">calculate</span>
                    </div>
                    <div>
                      <h3 className="font-bold text-lg text-gray-900">{selectedRoleToEdit}</h3>
                      <p className="text-sm text-gray-500">Select role to edit</p>
                    </div>
                  </div>
                </div>
                
                <div className="mb-6">
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Select Role</label>
                  <select 
                    value={selectedRoleToEdit}
                    onChange={(e) => setSelectedRoleToEdit(e.target.value)}
                    className="w-full p-2 border border-gray-200 rounded-lg text-sm font-medium focus:ring-2 focus:ring-blue-600"
                  >
                    {SYSTEM_ROLES.map(role => (
                      <option key={role} value={role}>{role}</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-3">
                  <div className="flex items-center justify-between p-3 rounded-lg bg-gray-50 border border-gray-200">
                    <span className="text-sm font-medium">Require 2FA</span>
                    <div className="relative inline-flex h6 w-11 items-center rounded-full bg-blue-600">
                      <span className="inline-block h-4 w-4 transform rounded-full bg-white transition translate-x-6"></span>
                    </div>
                  </div>
                  <div className="flex items-center justify-between p-3 rounded-lg bg-gray-50 border border-gray-200">
                    <span className="text-sm font-medium">Session Timeout</span>
                    <span className="text-sm font-bold text-blue-600">30 Mins</span>
                  </div>
                </div>
              </div>

              {/* Permission Toggles */}
              <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="font-bold text-lg text-gray-900">Module Access Permissions</h3>
                  <div className="flex items-center gap-2">
                     <span className="px-2 py-1 bg-yellow-100 text-yellow-800 text-xs font-bold rounded">Unsaved Changes</span>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
                  {/* Finance Module */}
                  <div className="space-y-4">
                    <h4 className="text-xs font-bold uppercase tracking-wider text-gray-500 border-b border-gray-200 pb-2">Finance Module</h4>
                    {[
                      { key: 'view_reports', name: 'View Reports', desc: 'Access to financial dashboards' },
                      { key: 'process_payments', name: 'Process Payments', desc: 'Charge cards and record checks' },
                      { key: 'manage_payroll', name: 'Manage Payroll', desc: 'Edit salaries and disburse funds' },
                    ].map((perm) => (
                      <div key={perm.key} className="flex items-center justify-between group">
                        <div className="flex flex-col">
                          <span className="text-sm font-medium text-gray-900">{perm.name}</span>
                          <span className="text-xs text-gray-500">{perm.desc}</span>
                        </div>
                        <div 
                          onClick={() => togglePermission('finance', perm.key)}
                          className={`relative inline-flex h-5 w-9 items-center rounded-full cursor-pointer transition-colors ${permissionSettings.finance[perm.key as keyof typeof permissionSettings.finance] ? 'bg-blue-600' : 'bg-gray-200'}`}
                        >
                          <span className={`inline-block h-3 w-3 transform rounded-full bg-white transition shadow ${permissionSettings.finance[perm.key as keyof typeof permissionSettings.finance] ? 'translate-x-5' : 'translate-x-1'}`} />
                        </div>
                      </div>
                    ))}
                  </div>

                  {/* Student Records */}
                  <div className="space-y-4">
                    <h4 className="text-xs font-bold uppercase tracking-wider text-gray-500 border-b border-gray-200 pb-2">Student Records</h4>
                    {[
                      { key: 'view_profiles', name: 'View Profiles', desc: 'Read-only access to student info' },
                      { key: 'edit_records', name: 'Edit Academic Records', desc: 'Change grades and attendance' },
                      { key: 'delete_records', name: 'Delete Records', desc: 'Permanently remove student data' },
                    ].map((perm) => (
                      <div key={perm.key} className="flex items-center justify-between group">
                        <div className="flex flex-col">
                          <span className="text-sm font-medium text-gray-900">{perm.name}</span>
                          <span className="text-xs text-gray-500">{perm.desc}</span>
                        </div>
                        <div 
                          onClick={() => togglePermission('students', perm.key)}
                          className={`relative inline-flex h-5 w-9 items-center rounded-full cursor-pointer transition-colors ${permissionSettings.students[perm.key as keyof typeof permissionSettings.students] ? 'bg-blue-600' : 'bg-gray-200'}`}
                        >
                          <span className={`inline-block h-3 w-3 transform rounded-full bg-white transition shadow ${permissionSettings.students[perm.key as keyof typeof permissionSettings.students] ? 'translate-x-5' : 'translate-x-1'}`} />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="mt-8 pt-6 border-t border-gray-200 flex justify-end gap-3">
                  <button 
                    onClick={() => setPermissionSettings(DEFAULT_PERMISSIONS)}
                    className="px-4 py-2 text-sm font-bold text-gray-500 hover:text-gray-900"
                  >
                    Reset Defaults
                  </button>
                  <button 
                    onClick={handleSavePermissions}
                    disabled={isSavingPermissions}
                    className="px-6 py-2 rounded-lg bg-blue-600 text-white text-sm font-bold hover:bg-blue-700 transition-colors shadow-sm disabled:opacity-70 flex items-center gap-2"
                  >
                    {isSavingPermissions && <span className="material-symbols-outlined animate-spin text-sm">progress_activity</span>}
                    Save Permissions
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

'use client';

import Link from 'next/link';
import { useState } from 'react';
import PremiumHeader from '@/components/layout/PremiumHeader';
import PremiumFooter from '@/components/layout/PremiumFooter';

const FORM_STEPS = ['Student Information', 'Parent/Guardian Details', 'Academic History', 'Submit'];

export default function ApplicationFormPage() {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    // Student info
    firstName: '',
    lastName: '',
    dateOfBirth: '',
    gender: '',
    // Parent info
    parentName: '',
    parentEmail: '',
    parentPhone: '',
    // Academic
    currentSchool: '',
    gradeApplying: '',
    startDate: '',
  });

  const handleNext = () => {
    if (currentStep < FORM_STEPS.length - 1) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handlePrev = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch('/api/admissions/apply', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });
      const json = await res.json();
      
      if (json.success) {
        alert('Application submitted successfully! We will review your application soon.');
        // Reset form or redirect
        window.location.href = '/'; 
      } else {
        alert('Submission failed: ' + json.message);
      }
    } catch (err) {
      console.error(err);
      alert('An error occurred. Please try again.');
    }
  };

  return (
    <div className="relative flex min-h-screen w-full flex-col bg-gray-50">
      <PremiumHeader />

      <main className="flex-grow py-12">
        <div className="max-w-[900px] mx-auto px-4 sm:px-10">
          {/* Progress Steps */}
          <div className="mb-10">
            <div className="flex items-center justify-between mb-8">
              {FORM_STEPS.map((step, index) => (
                <div key={index} className="flex items-center flex-1">
                  <div className="flex flex-col items-center flex-1">
                    <div
                      className={`w-10 h-10 rounded-full flex items-center justify-center font-bold transition-all ${
                        index <= currentStep
                          ? 'bg-brand-navy text-white'
                          : 'bg-gray-200 text-gray-500'
                      }`}
                    >
                      {index + 1}
                    </div>
                    <span className="text-xs mt-2 font-medium text-gray-600 hidden sm:block">
                      {step}
                    </span>
                  </div>
                  {index < FORM_STEPS.length - 1 && (
                    <div
                      className={`h-1 flex-1 mx-2 transition-all ${
                        index < currentStep ? 'bg-brand-navy' : 'bg-gray-200'
                      }`}
                    />
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Form Card */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-8">
            <h1 className="text-3xl font-black text-gray-900 mb-6">
              Online Enrollment Application
            </h1>

            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Step 0: Student Information */}
              {currentStep === 0 && (
                <div className="space-y-6">
                  <h2 className="text-xl font-bold text-brand-navy mb-4">Student Information</h2>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-bold text-gray-700 mb-2">
