    if (status) where.status = status;

    const [payments, total] = await prisma.$transaction([
      prisma.feePayment.findMany({
        where,
        include: {
          student: {
            include: {
              user: {
                select: { firstName: true, lastName: true, email: true }
              }
            }
          }
        },
        skip,
        take: limit,
