import { NextRequest } from 'next/server'
import { requireAdmin } from '@/lib/api/auth-middleware'
import { secureResponse } from '@/lib/api/security-headers'
import { checkRateLimit, rateLimitPresets } from '@/lib/rate-limit'
import {
  generateUniqueRegistrationNumber,
  getRegistrationStats,
  bulkGenerateRegistrationNumbers,
  isValidRegistrationNumber,
  parseRegistrationNumber,
  RegNumberConfig,
  UserRole
} from '@/lib/utils/registration-number'

/**
 * GET /api/admin/registration-numbers
 * Get registration number statistics
 */
export async function GET(request: NextRequest) {
  try {
    // Rate limiting
    const rateLimitResponse = checkRateLimit(request, rateLimitPresets.api)
    if (rateLimitResponse) return rateLimitResponse

    // Verify admin access
    const { error } = await requireAdmin(request)
    if (error) return error

    // Get year from query params
    const { searchParams } = new URL(request.url)
    const yearParam = searchParams.get('year')
    const year = yearParam ? parseInt(yearParam, 10) : undefined

    // Get statistics
    const stats = await getRegistrationStats(year)

    return secureResponse({
      success: true,
      data: {
        ...stats,
        currentYear: year || new Date().getFullYear(),
      },
    })
  } catch (error) {
    console.error('Error fetching registration stats:', error)
    return secureResponse(
      { success: false, message: 'Failed to fetch registration statistics' },
      { status: 500 }
    )
  }
}

/**
 * POST /api/admin/registration-numbers
 * Generate new registration number(s)
 * 
 * Body:
 * - count?: number (default: 1)
 * - role?: 'student' | 'teacher' | 'staff' (default: 'student')
 * - yearFormat?: 'full' | 'short' (default: 'short')
 */
export async function POST(request: NextRequest) {
  try {
    // Rate limiting
    const rateLimitResponse = checkRateLimit(request, rateLimitPresets.api)
    if (rateLimitResponse) return rateLimitResponse

    // Verify admin access
    const { error } = await requireAdmin(request)
    if (error) return error

    const body = await request.json()
    const {
      count = 1,
      role = 'student',
      yearFormat = 'short',
    } = body

    // Validate count
    if (count < 1 || count > 100) {
      return secureResponse(
        { success: false, message: 'Count must be between 1 and 100' },
        { status: 400 }
      )
    }

    // Generate registration numbers
    const config: RegNumberConfig = { role: role as UserRole, yearFormat }

    if (count === 1) {
      const registrationNumber = await generateUniqueRegistrationNumber(config)
      return secureResponse({
        success: true,
        data: {
          registrationNumber,
          config,
        },
      })
    } else {
      const registrationNumbers = await bulkGenerateRegistrationNumbers(count, config)
      return secureResponse({
        success: true,
        data: {
          registrationNumbers,
          count: registrationNumbers.length,
          config,
        },
      })
    }
  } catch (error) {
    console.error('Error generating registration numbers:', error)
    return secureResponse(
      { success: false, message: 'Failed to generate registration numbers' },
      { status: 500 }
    )
  }
}

/**
 * PUT /api/admin/registration-numbers/validate
 * Validate registration number format
 */
export async function PUT(request: NextRequest) {
  try {
    // Rate limiting
    const rateLimitResponse = checkRateLimit(request, rateLimitPresets.api)
    if (rateLimitResponse) return rateLimitResponse

    // Verify admin access
    const { error } = await requireAdmin(request)
    if (error) return error

    const body = await request.json()
    const {
      registrationNumber,
      role = 'student',
      yearFormat = 'short'
    } = body

    if (!registrationNumber) {
      return secureResponse(
        { success: false, message: 'Registration number is required' },
        { status: 400 }
      )
    }

    // Validate format
    const config: RegNumberConfig = { role: role as UserRole, yearFormat }
    const isValid = isValidRegistrationNumber(registrationNumber)
    const parsed = parseRegistrationNumber(registrationNumber)

    return secureResponse({
      success: true,
      data: {
        registrationNumber,
        isValid,
        parsed,
        config,
      },
    })
  } catch (error) {
    console.error('Error validating registration number:', error)
    return secureResponse(
      { success: false, message: 'Failed to validate registration number' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { startOfDay, endOfDay, subDays } from 'date-fns';

export async function GET(request: NextRequest) {
  try {
    // 1. Student Stats
    const totalStudents = await prisma.student.count();
    const studentsByGrade = await prisma.student.groupBy({
      by: ['currentGrade'],
      _count: {
        id: true
      }
    });

    // 2. Staff Stats
    const totalTeachers = await prisma.user.count({
      where: { role: 'teacher' }
    });

    // 3. Attendance Stats (Today)
    const today = new Date();
    const attendanceToday = await prisma.attendance.groupBy({
      by: ['status'],
      where: {
        date: {
          gte: startOfDay(today),
          lte: endOfDay(today)
        }
      },
      _count: {
        id: true
      }
    });
    
    // Calculate attendance rate for today
    const presentCount = attendanceToday.find(a => a.status === 'present')?.['_count'].id || 0;
    const lateCount = attendanceToday.find(a => a.status === 'late')?.['_count'].id || 0;
    // const absentCount = attendanceToday.find(a => a.status === 'absent')?.['_count'].id || 0;
    
    // Total marked attendance today (to calculate rate based on marked, or based on total students?)
    // Usually rate = (Present + Late) / Total Active Students
    const attendanceRate = totalStudents > 0 
      ? Math.round(((presentCount + lateCount) / totalStudents) * 100) 
      : 0;

    // 4. Financial Stats
    const financials = await prisma.feePayment.aggregate({
      _sum: {
        paidAmount: true,
        balance: true
      }
    });

    return NextResponse.json({
      success: true,
      data: {
        students: {
            total: totalStudents,
            byGrade: studentsByGrade.map(g => ({ grade: g.currentGrade, count: g._count.id }))
        },
        staff: {
            teachers: totalTeachers
        },
        attendance: {
            rate: attendanceRate,
            breakdown: attendanceToday.map(a => ({ status: a.status, count: a._count.id }))
        },
        finance: {
            revenue: financials._sum.paidAmount || 0,
            pending: financials._sum.balance || 0
        }
      }
    });

  } catch (error) {
    console.error('Error fetching stats:', error);
    return NextResponse.json(
      { success: false, message: 'Failed to fetch statistics' },
      { status: 500 }
    );
  }
}

