import { requireAdmin } from '@/lib/api/auth-middleware';

// GET /api/admin/students - List all students with filters
export async function GET(request: NextRequest) {
  try {
    const authResult = await requireAdmin(request);
    if (authResult.error) return authResult.error;

    const searchParams = request.nextUrl.searchParams;
    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '10');
    const search = searchParams.get('search') || '';
    const grade = searchParams.get('grade');
    const status = searchParams.get('status');

    const skip = (page - 1) * limit;

    const where: any = {};

    if (search) {
      where.OR = [
        { user: { firstName: { contains: search } } }, // SQLite doesn't support mode: 'insensitive' with contains easily basically
        { user: { lastName: { contains: search } } },
        { user: { email: { contains: search } } },
        { rollNumber: { contains: search } },
      ];
    }

    if (grade) {
      where.currentGrade = grade;
    }

    // Status is on the User model
    if (status) {
      where.user = { ...where.user, status };
    }

    const [students, total] = await prisma.$transaction([
      prisma.student.findMany({
        where,
        skip,
        take: limit,
        include: {
          user: {
            select: {
              id: true,
              email: true,
              firstName: true,
              lastName: true,
              status: true,
              phoneNumber: true,
            },
          },
        },
        orderBy: { createdAt: 'desc' },
      }),
      prisma.student.count({ where }),
    ]);

    // Flatten response structure to match frontend expectations
    const flattenedStudents = students.map((student) => ({
      id: student.id,
      studentId: student.userId, // Mapping userId to studentId for frontend
      firstName: student.user.firstName,
      lastName: student.user.lastName,
      email: student.user.email,
      dateOfBirth: student.dateOfBirth?.toISOString(),
      grade: student.currentGrade,
      className: student.section || '',
      enrollmentDate: student.enrollmentDate.toISOString(),
      status: student.user.status, // user status
      phoneNumber: student.user.phoneNumber,
      address: student.address,
      parentInfo: {
        name: student.parentName,
        email: student.parentEmail,
        phone: student.parentPhone,
        relationship: 'Parent', // Default for now
      },
      rollNumber: student.rollNumber,
    }));

    return NextResponse.json({
      success: true,
      data: {
        data: flattenedStudents,
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
        stats: {
          totalEnrollment: total,
          newStudents: await prisma.student.count({ where: { createdAt: { gte: new Date(new Date().setMonth(new Date().getMonth() - 1)) } } }),
          activeStudents: await prisma.student.count({ where: { user: { status: 'ACTIVE' } } }),
          graduatingClass: await prisma.student.count({ where: { currentGrade: 'Grade 12' } })
        }
      },
    });
  } catch (error) {
    console.error('Error fetching students:', error);
    return NextResponse.json(
      { success: false, message: 'Failed to fetch students' },
      { status: 500 }
    );
  }
}

