import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { verifyAccessToken } from '@/lib/auth';

export async function GET(
    request: NextRequest,
    { params }: { params: Promise<{ classId: string }> }
) {
    const { classId } = await params;
    try {
        const authHeader = request.headers.get('authorization');
        if (!authHeader || !authHeader.startsWith('Bearer ')) {
            return NextResponse.json({ success: false, message: 'Unauthorized' }, { status: 401 });
        }
        
        const { searchParams } = new URL(request.url);
        const dateString = searchParams.get('date');
        
        if (!dateString) {
            return NextResponse.json({ success: false, message: 'Date required' }, { status: 400 });
        }
        
        const date = new Date(dateString);

        // 1. Get Class details to confirm it exists and maybe verify teacher assignment?
        // For now, just simplistic RBAC (any teacher/admin can view)
        
        // 2. Fetch Students in Class
        // We need to know which students belong to this class.
        // Schema Analysis: 
        // Class has `grade`. Student has `currentGrade`.
        // We can match Student.currentGrade == Class.grade (and Class.name/section if applicable?)
        // The schema shows Student.currentGrade and Class.grade. 
        // Let's first fetch the Class to get its grade.
        const classObj = await prisma.class.findUnique({
             where: { id: classId }
        });

        if (!classObj) {
            return NextResponse.json({ success: false, message: 'Class not found' }, { status: 404 });
        }

        const students = await prisma.student.findMany({
            where: {
                currentGrade: classObj.grade
            },
            include: {
                user: {
                    select: { firstName: true, lastName: true }
                }
            },
            orderBy: {
                 user: { lastName: 'asc' }
            }
        });

        // 3. Fetch Attendance for these students on this date
        // Since we have a strict date match (check if time part needs stripping)
        // With `date: DateTime` in Prisma/SQLite, it often stores full timestamp.
        // We rely on the frontend sending a clean date, and the previous POST logic 
        // using `new Date(date)` from the same string format. 
        // Ideally we should use a string YYYY-MM-DD or ensure midnight normalization.
        // For safety, let's verify if `date` is stored as YYYY-MM-DD string would be safer in future refactors,
        // but current schema uses DateTime.
        
        // Let's assume the POST stores whatever date object is created from the string.
        // To be safe regarding time components, usually we range query or ensure strict midnight.
        // But since we used `new Date(date)` in POST, if client sends "2024-01-01", it's UTC midnight.
        
        const attendanceRecords = await prisma.attendance.findMany({
            where: {
                studentId: { in: students.map(s => s.id) },
                date: date 
            }
        });

        // 4. Merge
        const result = students.map(student => {
            const record = attendanceRecords.find(r => r.studentId === student.id);
            return {
                studentId: student.id,
                name: `${student.user.firstName} ${student.user.lastName}`,
                rollNumber: student.rollNumber,
                status: record?.status || 'UNMARKED',
                notes: record?.notes || ''
            };
        });

        return NextResponse.json({
            success: true,
            data: {
                class: classObj.name,
                date: dateString,
                students: result
            }
        });

    } catch (error) {
        console.error('Attendance Fetch Error:', error);
        return NextResponse.json({ success: false, message: 'Internal Server Error' }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { verifyAccessToken } from '@/lib/auth';

export async function POST(request: NextRequest) {
    try {
        const authHeader = request.headers.get('authorization');
        if (!authHeader || !authHeader.startsWith('Bearer ')) {
            return NextResponse.json({ success: false, message: 'Unauthorized' }, { status: 401 });
        }
        const token = authHeader.substring(7);
        const payload = await verifyAccessToken(token);
        // Allow teachers and admins
        if (!payload || (payload.role !== 'teacher' && payload.role !== 'admin' && payload.role !== 'administrator')) {
            return NextResponse.json({ success: false, message: 'Unauthorized' }, { status: 401 });
        }

        const body = await request.json();
        const { date, records } = body; 
        // records: { studentId: string, status: string, notes?: string }[]

        if (!date || !records || !Array.isArray(records)) {
             return NextResponse.json({ success: false, message: 'Invalid data format' }, { status: 400 });
        }

        const attendanceDate = new Date(date);

        // Perform upserts in a transaction or Promise.all
        // Using Promise.all for simplicity as SQLite writes might be locked sequentially anyway, 
        // but prisma.$transaction is safer.
        
        await prisma.$transaction(
            records.map((record: any) => 
                prisma.attendance.upsert({
                    where: {
                        studentId_date: {
                            studentId: record.studentId,
                            date: attendanceDate
                        }
                    },
                    update: {
                        status: record.status,
                        notes: record.notes,
                        markedBy: payload.userId,
                        markedAt: new Date()
                    },
                    create: {
                        studentId: record.studentId,
                        date: attendanceDate,
                        status: record.status,
                        notes: record.notes,
                        markedBy: payload.userId
                    }
                })
            )
        );

        return NextResponse.json({
            success: true,
            message: 'Attendance marked successfully'
        });

    } catch (error) {
        console.error('Attendance Mark Error:', error);
        return NextResponse.json({ success: false, message: 'Internal Server Error' }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server'
import { withRateLimit, addSecurityHeaders, validateEmail, sanitizeInput } from '@/lib/security'
import { prisma } from '@/lib/db'
import { comparePassword, generateAccessToken, generateRefreshToken } from '@/lib/auth'

async function loginHandler(request: NextRequest) {
  try {
    const body = await request.json()
    const { email, password } = body

    // Validate input with enhanced security checks
    if (!email || typeof email !== 'string' || !validateEmail(email)) {
      const response = NextResponse.json(
        { success: false, message: 'Valid email is required' },
        { status: 400 }
      )
      return addSecurityHeaders(response)
    }

    if (!password || typeof password !== 'string') {
      const response = NextResponse.json(
        { success: false, message: 'Password is required' },
        { status: 400 }
      )
      return addSecurityHeaders(response)
    }

    // Sanitize email to prevent injection
    const sanitizedEmail = sanitizeInput(email.toLowerCase())

    // Use secure database query
    const user = await secureDbQuery(
      () => prisma.user.findUnique({
        where: { email: sanitizedEmail },
        select: {
          id: true,
          email: true,
          password: true,
          firstName: true,
          lastName: true,
          role: true,
          status: true,
          createdAt: true,
          updatedAt: true
        }
      }),
      'user_lookup_by_email'
    )

    if (!user) {
      const response = NextResponse.json(
        { success: false, message: 'Invalid credentials' },
        { status: 401 }
      )
      return addSecurityHeaders(response)
    }

    // Verify password
    const isValidPassword = await comparePassword(password, user.password)
    if (!isValidPassword) {
      const response = NextResponse.json(
        { success: false, message: 'Invalid credentials' },
        { status: 401 }
      )
      return addSecurityHeaders(response)
    }

    // Check if user is active
    if (user.status !== 'ACTIVE') {
      const response = NextResponse.json(
        { success: false, message: 'Account is not active' },
        { status: 403 }
      )
      return addSecurityHeaders(response)
    }

    // Generate tokens
    const payload = {
      userId: user.id,
      email: user.email,
      role: user.role,
    }

    const [accessToken, refreshToken] = await Promise.all([
      generateAccessToken(payload),
      generateRefreshToken(payload)
    ])

    // Update last login time (commented out until schema is updated)
    // await secureDbQuery(
    //   () => prisma.user.update({
    //     where: { id: user.id },
    //     data: { lastLoginAt: new Date() }
    //   }),
    //   'update_last_login'
    // )

    // Remove password from response
    const { password: _, ...userWithoutPassword } = user

    const response = NextResponse.json({
      success: true,
      message: 'Login successful',
      user: userWithoutPassword,
      accessToken,
      refreshToken,
    })

    return addSecurityHeaders(response)
  } catch (error) {
    console.error('Login error:', error)
    const response = NextResponse.json(
      { success: false, message: 'Internal server error' },
      { status: 500 }
    )
    return addSecurityHeaders(response)
  }
}

// Import secureDbQuery function
async function secureDbQuery<T>(
  query: () => Promise<T>,
  operation: string
): Promise<T> {
  try {
    const result = await query()
    
    if (process.env.NODE_ENV === 'development') {
      console.log(`✅ DB Operation successful: ${operation}`)
    }
    
    return result
  } catch (error) {
    console.error(`❌ DB Operation failed: ${operation}`, error)
    throw error
  }
}

