      },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db'

// Simple protected cron endpoint.
// Configure a CRON_SECRET in Vercel (Production, Preview, Development) and
// set the Authorization header to `Bearer ${CRON_SECRET}` in the Vercel cron job.
export async function GET(request: NextRequest) {
  try {
    const auth = request.headers.get('authorization') || ''
    const token = auth.startsWith('Bearer ') ? auth.slice('Bearer '.length) : ''

    if (!process.env.CRON_SECRET) {
      return NextResponse.json(
        { success: false, message: 'CRON_SECRET is not configured' },
        { status: 500 }
      )
    }

    if (token !== process.env.CRON_SECRET) {
      return NextResponse.json(
        { success: false, message: 'Unauthorized' },
        { status: 401 }
      )
    }

    // Daily tasks: Attendance summary, pending grading notifications, cleanup
    const now = new Date();
    const tasks = [];

    try {
      // Task 1: Count today's attendance records
      const attendanceCount = await prisma.attendance.count({
        where: {
          date: {
            gte: new Date(now.getFullYear(), now.getMonth(), now.getDate()),
            lt: new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1)
          }
        }
      });
      tasks.push({ task: 'attendance_check', count: attendanceCount });

      // Task 2: Count pending grade assignments
      const pendingGrades = await prisma.assignment.count({
        where: {
          status: 'ACTIVE',
          dueDate: { lt: now }
        }
      });
      tasks.push({ task: 'pending_grades', count: pendingGrades });

      // Task 3: Cleanup old sessions (example)
      // await prisma.session.deleteMany({ where: { expiresAt: { lt: now } } });
      tasks.push({ task: 'session_cleanup', status: 'skipped' });

    } catch (err) {
      console.error('Daily task error:', err);
    }

    return NextResponse.json(
      {
        success: true,
        message: 'Daily cron executed',
        timestamp: now.toISOString(),
        env: process.env.VERCEL_ENV || process.env.NODE_ENV || 'production',
        tasks
      },
      { status: 200 }
    )
  } catch (err: any) {
    return NextResponse.json(
      { success: false, message: err?.message || 'Cron failed' },
      { status: 500 }
    )
  }
}

