import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { requireParent } from '@/lib/api/auth-middleware';

export async function GET(request: NextRequest) {
    try {
        const { user, error } = await requireParent(request);
        if (error) return error;

        if (!user) {
             return NextResponse.json({ success: false, message: 'Unauthorized' }, { status: 401 });
        }

        // Fetch children linked to this parent's email
        // We assume the user.email provided in token matches the Student.parentEmail
        const children = await prisma.student.findMany({
            where: {
                parentEmail: user.email
            },
            include: {
                user: { select: { firstName: true, lastName: true } },
                attendance: { 
                    take: 1, 
                    orderBy: { date: 'desc' } 
                },
                _count: {
                    select: { attendance: { where: { status: 'present' } } }
                }
            }
        });

        // Loop through children to get more specific stats (e.g. pending fees, recent grades)
        const childrenData = await Promise.all(children.map(async (child) => {
             // Recent Grades
             const recentGrades = await prisma.grade.findMany({
                 where: { studentId: child.id },
                 orderBy: { gradedAt: 'desc' },
                 take: 3,
                 include: { subject: { select: { name: true } } }
             });

             // Pending Fees
             const pendingFees = await prisma.feePayment.groupBy({
                 by: ['status'],
                 where: { 
                     studentId: child.id,
                     status: 'PENDING'
                 },
                 _sum: { balance: true }
             });
             
             const totalDue = pendingFees.reduce((acc, curr) => acc + (curr._sum.balance || 0), 0);

             return {
                 id: child.id,
                 name: `${child.user.firstName} ${child.user.lastName}`,
                 grade: child.currentGrade,
                 rollNumber: child.rollNumber,
                 avatar: `https://ui-avatars.com/api/?name=${child.user.firstName}+${child.user.lastName}&background=random`,
                 stats: {
                     attendance: '92%', // Mocked for now, or calc from _count
                     gpa: '3.5', // Mocked
                     feesDue: totalDue
                 },
                 recentGrades: recentGrades.map(g => ({
                     subject: g.subject.name,
                     grade: g.letterGrade
                 })),
                 lastAttendance: child.attendance[0]?.status || 'N/A'
             };
        }));

        return NextResponse.json({
            success: true,
            data: childrenData
        });

    } catch (error) {
        console.error('Parent Dashboard Error:', error);
        return NextResponse.json(
            { success: false, message: 'Failed to fetch parent dashboard' },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { requireStudent } from '@/lib/api/auth-middleware';

export async function GET(request: NextRequest) {
    try {
        const { user, error } = await requireStudent(request);
        if (error) return error;
        if (!user) return NextResponse.json({ success: false, message: 'Unauthorized' }, { status: 401 });

        // Get Student Profile
        const student = await prisma.student.findUnique({
            where: { userId: user.userId }
        });

        if (!student) return NextResponse.json({ success: false, message: 'Profile not found' }, { status: 404 });

        // Get Assignments for their grade
        const assignments = await prisma.assignment.findMany({
            where: {
                grade: student.currentGrade,
                status: 'ACTIVE'
            },
            include: {
                subject: { select: { name: true } }
            },
            orderBy: { dueDate: 'asc' }
        });

        // Get Submissions by this student
        const submissions = await prisma.assignmentSubmission.findMany({
            where: {
                studentId: student.id,
                assignmentId: { in: assignments.map(a => a.id) }
            }
        });

        const submissionMap = new Map(submissions.map(s => [s.assignmentId, s]));

        const data = assignments.map(a => {
            const sub = submissionMap.get(a.id);
            return {
                id: a.id,
                title: a.title,
                subject: a.subject.name,
                description: a.description,
                dueDate: a.dueDate,
                status: sub ? 'SUBMITTED' : (new Date(a.dueDate) < new Date() ? 'OVERDUE' : 'PENDING'),
                grade: sub?.score ? `${sub.score}/${a.totalPoints}` : null,
                feedback: sub?.feedback || null,
                submissionDate: sub?.submittedAt || null
            };
        });

        return NextResponse.json({ success: true, data });

    } catch (error) {
        console.error('Student Assignments Error:', error);
        return NextResponse.json({ success: false, message: 'Failed to fetch assignments' }, { status: 500 });
    }
}

export async function POST(request: NextRequest) {
    try {
        const { user, error } = await requireStudent(request);
        if (error) return error;
        if (!user) return NextResponse.json({ success: false, message: 'Unauthorized' }, { status: 401 });

        const student = await prisma.student.findUnique({ where: { userId: user.userId } });
        if (!student) return NextResponse.json({ success: false, message: 'Profile not found' }, { status: 404 });

        const body = await request.json();
        const { assignmentId, content } = body;

        if (!assignmentId || !content) {
            return NextResponse.json({ success: false, message: 'Missing fields' }, { status: 400 });
        }

        // Upsert submission
        await prisma.assignmentSubmission.upsert({
            where: {
                assignmentId_studentId: {
                    assignmentId,
                    studentId: student.id
                }
            },
            update: {
                content,
                submittedAt: new Date(),
                status: 'SUBMITTED' // Re-submit if allowed
            },
            create: {
                assignmentId,
                studentId: student.id,
                content,
                status: 'SUBMITTED'
            }
        });

        return NextResponse.json({ success: true, message: 'Assignment submitted' });

    } catch (error) {
        console.error('Assignment Submission Error:', error);
        return NextResponse.json({ success: false, message: 'Failed to submit' }, { status: 500 });
    }
}

