        });

        const gradeRecords = students.map(student => {
            // Get relevant grades (assessment, midterm, final)
            const assessmentGrade = student.grades.find(g => g.assessmentType === 'ASSESSMENT');
            const midtermGrade = student.grades.find(g => g.assessmentType === 'MIDTERM');
            const finalGrade = student.grades.find(g => g.assessmentType === 'FINAL');

            const assessment = assessmentGrade?.score || 0;
            const midterm = midtermGrade?.score || 0;
            const final = finalGrade?.score || 0;
            const total = assessment + midterm + final;

            const letterGrade = calculateLetterGrade(total);

            return {
                studentId: student.id,
                rollNumber: student.rollNumber || 'N/A',
                name: `${student.user.firstName} ${student.user.lastName}`,
                assessment,
                midterm,
                final,
                total,
                letterGrade,
                status: (assessmentGrade || midtermGrade || finalGrade) ? 'APPROVED' : 'DRAFT',
                comments: assessmentGrade?.remarks || ''
            };
        });

        // Calculate stats
        const totals = gradeRecords.map(r => r.total);
        const average = totals.length > 0 ? Math.round(totals.reduce((a, b) => a + b, 0) / totals.length) : 0;
        const highest = totals.length > 0 ? Math.max(...totals) : 0;
        const lowest = totals.length > 0 ? Math.min(...totals) : 0;
        const passRate = totals.length > 0 ? Math.round((totals.filter(t => t >= 50).length / totals.length) * 100) : 0;

        return NextResponse.json({
            success: true,
            data: gradeRecords,
            stats: { average, highest, lowest, passRate }
        });

    } catch (error) {
        console.error('Grades Fetch Error:', error);
        return NextResponse.json({ success: false, message: 'Failed to fetch grades' }, { status: 500 });
    }
}

function calculateLetterGrade(total: number): string {
    if (total >= 90) return 'A';
    if (total >= 80) return 'B';
    if (total >= 70) return 'B';
    if (total >= 60) return 'C';
    if (total >= 50) return 'D';
    return 'F';
}

// Keep existing POST endpoint
export async function POST(request: NextRequest) {
    try {
        const { user, error } = await requireTeacher(request);
        if (error) return error;
        if (!user) return NextResponse.json({ success: false, message: 'Unauthorized' }, { status: 401 });

        const body = await request.json();
        const { classId, subjectId, term, academicYear, grades } = body; 

        if (!classId || !subjectId || !Array.isArray(grades)) {
             return NextResponse.json({ success: false, message: 'Invalid data' }, { status: 400 });
        }

        const safeTerm = term || 'Term 1';
        const safeYear = academicYear || '2025-2026';

        const ops = grades.map((g: any) => {
            const score = parseFloat(g.score);
            const maxScore = parseFloat(g.maxScore) || 100;
            const percentage = (score / maxScore) * 100;
            
            let letterGrade = 'F';
            if (percentage >= 90) letterGrade = 'A+';
            else if (percentage >= 80) letterGrade = 'A';
            else if (percentage >= 70) letterGrade = 'B';
            else if (percentage >= 60) letterGrade = 'C';
            else if (percentage >= 50) letterGrade = 'D';

            return prisma.grade.upsert({
                where: {
                    studentId_subjectId_term_academicYear: {
                        studentId: g.studentId,
                        subjectId: subjectId,
                        term: safeTerm,
                        academicYear: safeYear
                    }
                },
                update: {
                    score,
                    maxScore,
                    percentage,
                    letterGrade,
                    remarks: g.remarks,
                    gradedBy: user.userId,
                    gradedAt: new Date()
                },
                create: {
                    studentId: g.studentId,
                    subjectId: subjectId,
                    term: safeTerm,
                    academicYear: safeYear,
                    score,
                    maxScore,
                    percentage,
                    letterGrade,
                    assessmentType: 'ASSIGNMENT',
                    remarks: g.remarks,
                    gradedBy: user.userId
                }
            });
        });

        await prisma.$transaction(ops);

        return NextResponse.json({ success: true, message: 'Grades saved successfully' });

    } catch (error) {
        console.error('Grades Save Error:', error);
        return NextResponse.json({ success: false, message: 'Failed to save grades' }, { status: 500 });
    }
}

