                  {child.name.split(' ')[0]}
                </span>
              </button>
            ))}
          </div>
        </div>

        {/* Dashboard Grid */}
        {selectedChild && (
          <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
            {/* Fee Status Card */}
            <div className="md:col-span-4 flex flex-col gap-4">
              <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200 h-full flex flex-col justify-between">
                <div>
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                      <span className="material-symbols-outlined text-amber-500">payments</span>
                      Fee Status
                    </h3>
                    <span className="bg-red-100 text-red-600 text-xs font-bold px-2 py-1 rounded-full uppercase tracking-wide">Action Required</span>
                  </div>
                  <div className="flex flex-col gap-1 mb-2">
                    <span className="text-sm text-gray-500">Total Outstanding</span>
                    <span className="text-4xl font-black text-gray-900 tracking-tight">${selectedChild.feeStatus.outstanding.toLocaleString()}.00</span>
                  </div>
                  <p className="text-sm text-amber-600 font-medium flex items-center gap-1">
                    <span className="material-symbols-outlined text-sm">warning</span>
                    Due by {selectedChild.feeStatus.dueDate}
                  </p>
                </div>
                <div className="mt-8">
                  <button className="w-full flex items-center justify-center h-12 rounded-lg bg-blue-600 hover:bg-blue-700 text-white text-base font-bold shadow-lg shadow-blue-600/20 transition-all transform active:scale-[0.98]">
                    Pay Now
                  </button>
                  <p className="text-center text-xs text-gray-400 mt-3">Secure payment via Stripe</p>
                </div>
              </div>
            </div>

            {/* Academic Achievements */}
            <div className="md:col-span-8">
              <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200 h-full">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                    <span className="material-symbols-outlined text-amber-500">military_tech</span>
                    Academic Achievements
                  </h3>
                  <Link className="text-sm font-medium text-blue-600 hover:underline" href="/parent/academics">View Full Report</Link>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                  {selectedChild.achievements.map((achievement, idx) => (
                    <div key={idx} className={`flex flex-col items-center text-center gap-3 p-4 rounded-lg bg-${achievement.color}-50 border border-${achievement.color}-100`}>
                      <div className={`size-12 rounded-full bg-gradient-to-br from-${achievement.color}-300 to-${achievement.color}-500 flex items-center justify-center text-white shadow-md`}>
                        <span className="material-symbols-outlined text-2xl">{achievement.icon}</span>
                      </div>
                      <div>
                        <p className="font-bold text-gray-900 text-sm">{achievement.title}</p>
                        <p className={`text-xs text-${achievement.color}-700 font-medium`}>{achievement.subtitle}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Upcoming Events */}
            <div className="md:col-span-6 lg:col-span-4">
              <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200 h-full">
                <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                  <span className="material-symbols-outlined text-blue-600">event</span>
                  Upcoming Events
                </h3>
                <div className="flex flex-col gap-4">
                  {selectedChild.upcomingEvents.map((event, idx) => (
                    <div key={idx} className="flex items-center gap-4 p-3 rounded-lg hover:bg-gray-50 transition-colors cursor-pointer group">
                      <div className="flex flex-col items-center justify-center min-w-[50px] h-[50px] bg-blue-50 rounded-lg text-blue-600">
                        <span className="text-xs font-bold uppercase">{event.month}</span>
                        <span className="text-lg font-bold leading-none">{event.date}</span>
                      </div>
                      <div className="flex flex-col">
                        <span className="text-gray-900 font-semibold group-hover:text-blue-600 transition-colors">{event.title}</span>
                        <span className="text-sm text-gray-500">{event.time}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Teacher Comments */}
            <div className="md:col-span-6 lg:col-span-4">
              <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200 h-full">
                <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                  <span className="material-symbols-outlined text-blue-600">comment</span>
                  Teacher Comments
                </h3>
                <div className="flex flex-col gap-4">
                  {selectedChild.teacherComments.map((comment, idx) => (
                    <div key={idx} className="flex gap-3">
                      <div className="bg-blue-100 rounded-full min-w-[40px] h-[40px] flex items-center justify-center text-blue-600 font-bold">
                        {comment.teacher.substring(0, 2)}
                      </div>
                      <div className="bg-gray-50 p-3 rounded-lg rounded-tl-none flex-1">
                        <div className="flex justify-between items-baseline mb-1">
                          <span className="text-xs font-bold text-gray-900">{comment.teacher} ({comment.subject})</span>
                          <span className="text-[10px] text-gray-500">{comment.time}</span>
                        </div>
                        <p className="text-sm text-gray-700 leading-relaxed">{comment.comment}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Quick Message */}
            <div className="md:col-span-12 lg:col-span-4">
              <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200 h-full flex flex-col">
                <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                  <span className="material-symbols-outlined text-blue-600">mail</span>
                  Quick Message
                </h3>
                <div className="flex-1 flex flex-col gap-3">
                  <div>
                    <label className="text-xs font-semibold text-gray-500 mb-1 block">To:</label>
                    <select
                      value={messageTo}
                      onChange={(e) => setMessageTo(e.target.value)}
                      className="w-full h-10 px-3 bg-gray-50 border-none rounded-lg text-sm text-gray-900 focus:ring-2 focus:ring-blue-600"
                    >
                      <option value="">Select recipient</option>
                      <option value="Mrs. Roberts (Homeroom)">Mrs. Roberts (Homeroom)</option>
                      <option value="Mr. Chen (Science)">Mr. Chen (Science)</option>
                      <option value="Administration Office">Administration Office</option>
                    </select>
                  </div>
                  <div className="flex-1">
                    <label className="text-xs font-semibold text-gray-500 mb-1 block">Message:</label>
                    <textarea
                      value={messageText}
                      onChange={(e) => setMessageText(e.target.value)}
                      className="w-full h-24 p-3 bg-gray-50 border-none rounded-lg text-sm text-gray-900 focus:ring-2 focus:ring-blue-600 resize-none"
                      placeholder="Type your message here..."
                    ></textarea>
                  </div>
                  <button
                    onClick={sendMessage}
                    className="w-full flex items-center justify-center gap-2 h-10 rounded-lg bg-blue-600 text-white text-sm font-bold hover:bg-blue-700 transition-colors"
                  >
                    <span className="material-symbols-outlined text-lg">send</span>
                    Send Message
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import Link from 'next/link';
import PremiumHeader from '@/components/layout/PremiumHeader';
import { StatBarList, NoticeBoard } from '@/components';

interface StaffMetrics {
  studentsEnrolled: number;
  averageAttendance: string;
  pendingReviews: number;
  meetings: number;
}

interface ClassSchedule {
  id: string;
  time: string;
  class: string;
  subject: string;
  room: string;
  students: number;
}

interface Notice {
  id: string;
  date: string;
  dateLabel?: string;
  title: string;
  time?: string;
  location?: string;
  description?: string;
  priority: 'high' | 'normal';
}

interface StaffDashboardData {
  metrics: StaffMetrics;
  todaysClasses: ClassSchedule[];
  notices: Notice[];
}

const GRADE_STATS = [
  { label: 'Reports Submitted', value: 85, maxValue: 100, color: 'gold' as const },
  { label: 'Attendance Recorded', value: 100, maxValue: 100, color: 'green' as const },
  { label: 'Lesson Plans Updated', value: 75, maxValue: 100, color: 'gold' as const },
];

export default function StaffPortalPage() {
  const [data, setData] = useState<StaffDashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('/api/hr/dashboard/staff');
        if (!response.ok) {
             // For safety, if unauthorized/not found, we might want to redirect or show placeholder
             // But for now, just show error
             throw new Error('Failed to fetch dashboard data');
        }
        const result = await response.json();
        if (result.success) {
          setData(result.data);
        } else {
          setError(result.message);
        }
      } catch (err) {
        setError('An error occurred while loading data');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-brand-navy"></div>
      </div>
    );
  }

  // Fallback to placeholder if error (optional, but good for demo if API fails)
  // For now, I'll render the error state
  if (error) {
     return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 text-red-500">
        Error: {error}
      </div>
    );
  }

  if (!data) return null;

  const STAFF_STATS = [
    { stat: data.metrics.studentsEnrolled.toString(), label: 'Students Enrolled' },
    { stat: data.metrics.averageAttendance, label: 'Average Attendance' },
    { stat: data.metrics.pendingReviews.toString(), label: 'Pending Reviews' },
    { stat: data.metrics.meetings.toString(), label: 'Staff Meetings This Month' },
  ];

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <PremiumHeader />

      <div className="flex-1 flex">
        {/* Sidebar */}
        <aside className="hidden lg:block w-64 bg-brand-navy text-white p-6">
          <div className="mb-8">
            <h2 className="text-2xl font-bold">Staff Portal</h2>
            <p className="text-sm text-gray-300 mt-1">Welcome</p>
          </div>

          <nav className="space-y-2">
            {[
              { icon: 'home', label: 'Dashboard', href: '/staff', active: true },
              { icon: 'groups', label: 'My Classes', href: '/staff/classes' },
              { icon: 'assignment', label: 'Grades & Reports', href: '/staff/grades' },
              { icon: 'event', label: 'Schedule', href: '/staff/schedule' },
              { icon: 'folder', label: 'Resources', href: '/staff/resources' },
              { icon: 'settings', label: 'Settings', href: '/staff/settings' },
            ].map((item) => (
              <Link
                key={item.label}
                href={item.href}
                className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                  item.active
                    ? 'bg-white/20 text-white'
                    : 'text-gray-300 hover:bg-white/10 hover:text-white'
                }`}
              >
                <span className="material-symbols-outlined text-[20px]">{item.icon}</span>
                <span className="font-medium">{item.label}</span>
              </Link>
            ))}
          </nav>
        </aside>

        {/* Main Content */}
        <main className="flex-1 p-4 md:p-8">
          <div className="max-w-[1400px] mx-auto">
            {/* Header */}
            <div className="mb-8">
              <h1 className="text-3xl font-bold text-gray-900">Dashboard</h1>
              <p className="text-gray-600 mt-1">Overview of your teaching schedule and responsibilities</p>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6 mb-8">
              {STAFF_STATS.map((stat, index) => (
                <div key={index} className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 text-center">
                  <div className="text-3xl font-black text-brand-navy mb-2">{stat.stat}</div>
                  <div className="text-sm text-gray-600">{stat.label}</div>
                </div>
              ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Left Column */}
              <div className="lg:col-span-2 space-y-6">
                {/* Today's Classes */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                  <h3 className="text-xl font-bold text-gray-900 mb-4">Today's Classes</h3>
                  {data.todaysClasses.length === 0 ? (
                      <p className="text-gray-500 text-center py-4">No classes scheduled for today.</p>
                  ) : (
                    <div className="space-y-4">
                        {data.todaysClasses.map((lesson, index) => (
                        <div key={lesson.id} className="flex items-center gap-4 p-4 bg-gray-50 rounded-lg">
                            <div className="w-16 text-center">
                            <div className="text-sm font-bold text-brand-navy">{lesson.time}</div>
                            </div>
                            <div className="flex-1">
                            <h4 className="font-bold text-gray-900">{lesson.class}</h4>
                            <p className="text-xs text-gray-500 mb-1">{lesson.subject}</p>
                            <div className="flex gap-4 text-sm text-gray-600 mt-1">
                                <span className="flex items-center gap-1">
                                <span className="material-symbols-outlined text-[16px]">door_front</span>
                                {lesson.room}
                                </span>
                                <span className="flex items-center gap-1">
                                <span className="material-symbols-outlined text-[16px]">groups</span>
                                {lesson.students} students
                                </span>
                            </div>
                            </div>
                            <Link
                            href={`/staff/classes/${index}`}
                            className="px-4 py-2 bg-brand-navy text-white rounded-lg font-medium hover:bg-brand-navy-dark transition-colors text-sm"
                            >
                            View Class
                            </Link>
                        </div>
                        ))}
                    </div>
                  )}
                </div>

                {/* Task Progress */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                  <h3 className="text-xl font-bold text-gray-900 mb-4">Task Progress</h3>
                  <StatBarList stats={GRADE_STATS} />
                </div>

                {/* Recent Activity */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                  <h3 className="text-xl font-bold text-gray-900 mb-4">Recent Activity</h3>
                  <div className="space-y-3">
                    {[
                      { type: 'grade', text: 'Submitted grades for Year 11 Math Test', time: '2 hours ago' },
                      { type: 'message', text: 'New message from Sarah Chen (Parent)', time: '5 hours ago' },
                      { type: 'document', text: 'Updated lesson plan for Unit 5', time: '1 day ago' },
                    ].map((activity, i) => (
                      <div key={i} className="flex items-start gap-3 pb-3 border-b border-gray-100 last:border-0">
                        <span className="material-symbols-outlined text-brand-navy mt-1">
                          {activity.type === 'grade' ? 'fact_check' : activity.type === 'message' ? 'mail' : 'description'}
                        </span>
                        <div className="flex-1">
                          <p className="text-gray-900">{activity.text}</p>
                          <p className="text-sm text-gray-500">{activity.time}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Right Column */}
              <div className="space-y-6">
                <NoticeBoard notices={data.notices} />

                {/* Quick Actions */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                  <h3 className="text-lg font-bold text-gray-900 mb-4">Quick Actions</h3>
                  <div className="space-y-2">
                    {[
                      { icon: 'add', label: 'Create Assignment', href: '/staff/assignments/new' },
                      { icon: 'grade', label: 'Enter Grades', href: '/staff/grades' },
                      { icon: 'event', label: 'Book Meeting Room', href: '/staff/rooms' },
                      { icon: 'upload', label: 'Upload Resources', href: '/staff/resources' },
                    ].map((action) => (
                      <Link
                        key={action.label}
                        href={action.href}
                        className="flex items-center gap-3 px-4 py-3 rounded-lg border border-gray-200 hover:border-brand-navy hover:bg-brand-navy/5 transition-all group"
                      >
                        <span className="material-symbols-outlined text-gray-600 group-hover:text-brand-navy text-[20px]">
                          {action.icon}
                        </span>
                        <span className="font-medium text-gray-700 group-hover:text-brand-navy">{action.label}</span>
                      </Link>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useToast } from '@/components/ui/use-toast';


export default function StudentAssignmentsPage() {
    const { toast } = useToast();
    const [assignments, setAssignments] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedAssignment, setSelectedAssignment] = useState<any | null>(null);
    const [submissionContent, setSubmissionContent] = useState('');

    useEffect(() => {
        fetchAssignments();
    }, []);

    const fetchAssignments = async () => {
        try {
            const res = await fetch('/api/assignments', {
                headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
            });
            const json = await res.json();
            if (json.success) {
                // Ideally we merge with submission status.
                // For MVP, we display all.
                setAssignments(json.data);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedAssignment) return;

        try {
            const res = await fetch(`/api/assignments/${selectedAssignment.id}/submit`, {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('token')}` 
                },
                body: JSON.stringify({ content: submissionContent })
            });
            const json = await res.json();
            if (json.success) {
                toast({ title: 'Success', description: 'Work submitted successfully' });
                setSelectedAssignment(null);
                setSubmissionContent('');
                // Refresh?
            } else {
                toast({ title: 'Error', description: json.message, variant: 'destructive' });
            }
        } catch (error) {
            toast({ title: 'Error', description: 'Failed to submit', variant: 'destructive' });
        }
    };

    return (
        <div className="p-8 max-w-6xl mx-auto">
            <h1 className="text-2xl font-bold text-gray-900 mb-8">My Assignments</h1>

            {loading ? <div className="text-center py-8 text-gray-500">Loading...</div> : (
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {assignments.map(assignment => (
                        <div key={assignment.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-200 hover:border-brand-gold transition-all flex flex-col">
                             <div className="flex justify-between items-start mb-2">
                                <span className="text-xs font-bold text-brand-navy bg-brand-navy/10 px-2 py-1 rounded">
                                    {assignment.subject?.name}
                                </span>
                                <span className="text-xs text-gray-500">
                                    Due: {new Date(assignment.dueDate).toLocaleDateString()}
                                </span>
                            </div>
                            <h3 className="font-semibold text-lg text-gray-900 mb-2">{assignment.title}</h3>
                            <p className="text-sm text-gray-600 line-clamp-3 mb-4 flex-grow">
                                {assignment.description || 'No description provided.'}
                            </p>
                            <button 
                                onClick={() => setSelectedAssignment(assignment)}
                                className="w-full py-2 bg-gray-50 text-brand-navy font-medium rounded-md hover:bg-gray-100 border border-gray-200"
                            >
                                View & Submit
                            </button>
                        </div>
                    ))}
                    {assignments.length === 0 && (
                        <div className="col-span-full text-center py-12 bg-gray-50 rounded-lg text-gray-500">
                            No assignments due.
                        </div>
                    )}
                </div>
            )}

            {/* Submission Modal */}
            {selectedAssignment && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
                    <div className="bg-white rounded-lg max-w-lg w-full p-6 shadow-xl animate-in zoom-in-95">
                        <div className="flex justify-between items-center mb-4">
                            <h2 className="text-xl font-bold text-gray-900">{selectedAssignment.title}</h2>
                            <button onClick={() => setSelectedAssignment(null)} className="text-gray-500 hover:text-gray-700">
                                <span className="material-symbols-outlined">close</span>
                            </button>
                        </div>
                        
                        <div className="mb-6 bg-gray-50 p-4 rounded-md text-sm text-gray-700 max-h-40 overflow-y-auto">
                            {selectedAssignment.description}
                        </div>

                        <form onSubmit={handleSubmit}>
                            <label className="block text-sm font-medium text-gray-700 mb-2">Your Answer / Link</label>
                            <textarea 
                                required 
                                className="w-full p-3 border border-gray-300 rounded-md h-32 mb-4 focus:ring-2 focus:ring-brand-navy focus:border-transparent outline-none"
                                placeholder="Type your answer here or paste a Google Doc link..."
                                value={submissionContent}
                                onChange={e => setSubmissionContent(e.target.value)}
                            />
                            <div className="flex justify-end gap-2">
                                <button type="button" onClick={() => setSelectedAssignment(null)} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-md">
                                    Cancel
                                </button>
                                <button type="submit" className="px-4 py-2 bg-brand-navy text-white rounded-md hover:bg-opacity-90">
                                    Submit
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';

interface AttendanceRecord {
    id: string;
    date: string;
    status: string;
    notes?: string;
}

interface Stats {
    total: number;
    present: number;
    absent: number;
    late: number;
    excused: number;
    rate: string;
}

export default function StudentAttendancePage() {
    const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
    const [stats, setStats] = useState<Stats | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchAttendance = async () => {
            try {
                const res = await fetch('/api/student/attendance', {
                    headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
                });
                const json = await res.json();
                if (json.success) {
                    setAttendance(json.attendance);
                    setStats(json.statistics);
                }
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        fetchAttendance();
    }, []);

    if (loading) return <div className="p-8 text-center text-gray-500">Loading attendance records...</div>;

    return (
        <div className="p-4 md:p-8 max-w-5xl mx-auto">
            <h1 className="text-2xl font-bold mb-6 text-gray-900">My Attendance</h1>

            {/* Stats Cards */}
            {stats && (
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
                    <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200">
                        <div className="text-sm text-gray-500 mb-1">Attendance Rate</div>
                        <div className="text-2xl font-bold text-brand-navy">{stats.rate}%</div>
                    </div>
                    <div className="bg-white p-4 rounded-lg shadow-sm border border-green-200 bg-green-50">
                        <div className="text-sm text-green-700 mb-1">Present</div>
                        <div className="text-2xl font-bold text-green-800">{stats.present}</div>
                    </div>
                     <div className="bg-white p-4 rounded-lg shadow-sm border border-red-200 bg-red-50">
                        <div className="text-sm text-red-700 mb-1">Absent</div>
                        <div className="text-2xl font-bold text-red-800">{stats.absent}</div>
                    </div>
                    <div className="bg-white p-4 rounded-lg shadow-sm border border-yellow-200 bg-yellow-50">
                        <div className="text-sm text-yellow-700 mb-1">Late</div>
                        <div className="text-2xl font-bold text-yellow-800">{stats.late}</div>
                    </div>
                </div>
            )}

            {/* Attendance List */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b border-gray-200">
                        <tr>
                            <th className="p-4 font-medium text-gray-600">Date</th>
                            <th className="p-4 font-medium text-gray-600">Status</th>
                            <th className="p-4 font-medium text-gray-600">Notes</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {attendance.length > 0 ? attendance.map(record => (
                            <tr key={record.id} className="hover:bg-gray-50/50">
                                <td className="p-4 text-gray-900">
                                    {new Date(record.date).toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                                </td>
                                <td className="p-4">
                                     <span className={`inline-block px-3 py-1 rounded-full text-xs font-bold ${getStatusColor(record.status)}`}>
                                        {record.status}
                                     </span>
                                </td>
                                <td className="p-4 text-gray-500 text-sm">{record.notes || '-'}</td>
                            </tr>
                        )) : (
                            <tr>
                                <td colSpan={3} className="p-8 text-center text-gray-500">
                                    No attendance records found.
                                </td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

function getStatusColor(status: string) {
    switch (status) {
        case 'PRESENT': return 'bg-green-100 text-green-700';
        case 'ABSENT': return 'bg-red-100 text-red-700';
        case 'LATE': return 'bg-yellow-100 text-yellow-700';
        case 'EXCUSED': return 'bg-blue-100 text-blue-700';
        default: return 'bg-gray-100 text-gray-500';
    }
}

