                Next
              </button>
            </div>
          </div>
        </div>

        {/* Summary Cards */}
        <div className="mt-8 grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
          {[
            { icon: 'warning', color: 'red', title: 'Flagged for Math', subtitle: '12 Students' },
            { icon: 'running_with_errors', color: 'yellow', title: 'Low Attendance', subtitle: '8 Students' },
            { icon: 'event_note', color: 'blue', title: 'Pending Interventions', subtitle: '5 Drafts' },
          ].map((stat, idx) => (
            <div key={idx} className={`relative flex items-center space-x-3 rounded-lg border border-gray-300 bg-white px-6 py-5 shadow-sm`}>
              <div className="flex-shrink-0">
                <span className={`inline-flex h-10 w-10 items-center justify-center rounded-full bg-${stat.color}-100 text-${stat.color}-600`}>
                  <span className="material-symbols-outlined">{stat.icon}</span>
                </span>
              </div>
              <div className="min-w-0 flex-1">
                <p className="text-sm font-medium text-gray-900">{stat.title}</p>
                <p className="truncate text-sm text-gray-500">{stat.subtitle}</p>
              </div>
            </div>
          ))}
          <div className="relative flex items-center space-x-3 rounded-lg border border-dashed border-gray-300 bg-transparent px-6 py-5 hover:bg-gray-50 cursor-pointer transition-colors">
            <div className="min-w-0 flex-1 text-center">
              <p className="text-sm font-medium text-blue-600">View Full Report History</p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useToast } from '@/components/ui/use-toast';
import { useParams, useRouter } from 'next/navigation';

interface Submission {
    id: string;
    studentId: string;
    student: {
        user: { firstName: string; lastName: string };
        rollNumber: string;
    };
    submittedAt: string;
    content: string;
    fileUrl?: string;
    score?: number;
    feedback?: string;
    status: string;
}

interface AssignmentDetail {
    id: string;
    title: string;
    description: string;
    totalPoints: number;
    dueDate: string;
    submissions: Submission[];
}

export default function AssignmentGradingPage() {
    const params = useParams();
    const router = useRouter();
    const { toast } = useToast();
    const [assignment, setAssignment] = useState<AssignmentDetail | null>(null);
    const [loading, setLoading] = useState(true);

    // Grading State
    const [selectedSubmission, setSelectedSubmission] = useState<Submission | null>(null);
    const [score, setScore] = useState('');
    const [feedback, setFeedback] = useState('');

    useEffect(() => {
        if (params.id) fetchAssignment();
    }, [params.id]);

    const fetchAssignment = async () => {
        try {
            const res = await fetch(`/api/assignments/${params.id}`, {
                headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
            });
            const json = await res.json();
            if (json.success) {
                setAssignment(json.data);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleOpenGrading = (submission: Submission) => {
        setSelectedSubmission(submission);
        setScore(submission.score?.toString() || '');
        setFeedback(submission.feedback || '');
    };

    const handleSaveGrade = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedSubmission || !assignment) return;

        try {
            const res = await fetch(`/api/assignments/${assignment.id}/grade`, {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('token')}` 
                },
                body: JSON.stringify({
                    studentId: selectedSubmission.studentId,
                    score: Number(score),
                    feedback
                })
            });
            const json = await res.json();
            if (json.success) {
                toast({ title: 'Success', description: 'Grade saved successfully' });
                setSelectedSubmission(null);
                fetchAssignment(); // Refresh list
            } else {
                toast({ title: 'Error', description: json.message, variant: 'destructive' });
            }
        } catch (error) {
            toast({ title: 'Error', description: 'Failed to save grade', variant: 'destructive' });
        }
    };

    if (loading) return <div className="p-8 text-center">Loading assignment details...</div>;
    if (!assignment) return <div className="p-8 text-center text-red-500">Assignment not found</div>;

    return (
        <div className="p-8 max-w-6xl mx-auto h-[calc(100vh-4rem)] flex flex-col">
            <div className="flex items-center gap-4 mb-6">
                <button onClick={() => router.back()} className="text-gray-500 hover:text-gray-900">
                    <span className="material-symbols-outlined">arrow_back</span>
                </button>
                <div>
                     <h1 className="text-2xl font-bold text-gray-900">{assignment.title}</h1>
                     <p className="text-sm text-gray-500">Total Points: {assignment.totalPoints} • Due: {new Date(assignment.dueDate).toLocaleDateString()}</p>
                </div>
            </div>

            <div className="flex gap-6 flex-1 overflow-hidden">
                {/* Submissions List */}
                <div className="w-1/3 bg-white border border-gray-200 rounded-lg overflow-y-auto">
                    <div className="p-4 bg-gray-50 border-b border-gray-200 font-medium text-gray-700">
                        Submissions ({assignment.submissions.length})
                    </div>
                    <div>
                        {assignment.submissions.length > 0 ? assignment.submissions.map(sub => (
                             <div 
                                key={sub.id} 
                                onClick={() => handleOpenGrading(sub)}
                                className={`p-4 border-b border-gray-100 cursor-pointer hover:bg-blue-50 transition-colors ${selectedSubmission?.id === sub.id ? 'bg-blue-50 border-l-4 border-l-brand-navy' : ''}`}
                            >
                                <div className="font-medium text-gray-900">{sub.student.user.firstName} {sub.student.user.lastName}</div>
                                <div className="flex justify-between items-center text-xs mt-1">
                                    <span className="text-gray-500">{new Date(sub.submittedAt).toLocaleDateString()}</span>
                                    {sub.score !== null && sub.score !== undefined ? (
                                        <span className="text-green-600 font-bold">{sub.score}/{assignment.totalPoints}</span>
                                    ) : (
                                        <span className="text-yellow-600 italic">Ungraded</span>
                                    )}
                                </div>
                            </div>
                        )) : (
                            <div className="p-8 text-center text-gray-500 italic">No submissions yet.</div>
                        )}
                    </div>
                </div>

                {/* Grading Area */}
                <div className="flex-1 bg-white border border-gray-200 rounded-lg p-6 flex flex-col">
                    {selectedSubmission ? (
                        <>
                            <div className="mb-6 flex-1 overflow-y-auto">
                                <h2 className="text-lg font-bold mb-4 border-b pb-2">Student Submission</h2>
                                <div className="bg-gray-50 p-6 rounded-lg border border-gray-100 font-mono text-sm whitespace-pre-wrap">
                                    {selectedSubmission.content || (
                                        <span className="text-gray-400 italic">No text content submitted. File URL: {selectedSubmission.fileUrl}</span>
                                    )}
                                </div>
                            </div>

                            <div className="border-t pt-6">
                                <h3 className="font-bold text-gray-900 mb-4">Grade & Feedback</h3>
                                <form onSubmit={handleSaveGrade} className="space-y-4">
                                    <div className="flex gap-4">
                                        <div className="w-32">
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Score</label>
                                            <div className="flex items-center gap-2">
                                                <input 
                                                    type="number" 
                                                    required
                                                    max={assignment.totalPoints}
                                                    value={score}
                                                    onChange={e => setScore(e.target.value)}
                                                    className="w-full p-2 border rounded-md" 
                                                />
                                                <span className="text-gray-500">/ {assignment.totalPoints}</span>
                                            </div>
                                        </div>
                                    </div>
                                    <div>
                                         <label className="block text-sm font-medium text-gray-700 mb-1">Feedback</label>
                                         <textarea 
                                            value={feedback}
                                            onChange={e => setFeedback(e.target.value)}
                                            className="w-full p-2 border rounded-md h-24"
                                            placeholder="Great work, but check..."
                                        />
                                    </div>
                                    <div className="flex justify-end">
                                        <button type="submit" className="px-6 py-2 bg-brand-navy text-white rounded-md hover:bg-opacity-90">
                                            Save Grade
                                        </button>
                                    </div>
                                </form>
                            </div>
                        </>
                    ) : (
                        <div className="flex items-center justify-center h-full text-gray-400 flex-col">
                            <span className="material-symbols-outlined text-4xl mb-2">assignment_turned_in</span>
                            <p>Select a student to grade their submission.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useToast } from '@/components/ui/use-toast';

interface Assignment {
    id: string;
    title: string;
    dueDate: string;
    grade: string;
    subject: { name: string };
    _count: { submissions: number };
    status: string;
}


export default function TeacherAssignmentsPage() {
    const { toast } = useToast();
    const [assignments, setAssignments] = useState<Assignment[]>([]);
    const [loading, setLoading] = useState(true);
    const [showCreate, setShowCreate] = useState(false);
    
    // Form State
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [grade, setGrade] = useState('');
    const [subjectId, setSubjectId] = useState('');
    const [dueDate, setDueDate] = useState('');
    const [totalPoints, setTotalPoints] = useState('100');

    // Data for dropdowns
    const [subjects, setSubjects] = useState<{id: string, name: string, code: string}[]>([]);

    useEffect(() => {
        fetchAssignments();
        fetchTeacherData(); // To get subjects/classes for dropdowns
    }, []);

    const fetchAssignments = async () => {
        try {
            const res = await fetch('/api/assignments', {
                headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
            });
            const json = await res.json();
            if (json.success) {
                setAssignments(json.data);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const fetchTeacherData = async () => {
        try {
            const res = await fetch('/api/teacher/subjects', {
                 headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
            });
            const json = await res.json();
             if (json.success) {
                setSubjects(json.data || []);
            }
        } catch (e) { console.error(e) }
    };
    
    // Helper to get subjects. 
    // Since we don't have a dedicated "my subjects" API handy, let's create a quick one or modify dashboard.
    // Actually, `GET /api/teacher/dashboard` returns generic stats.
    // Let's just create a quick client-side fetch for common subjects or Assume user types it? No.
    // Let's simply add a `Subject` Input for now to unblock, or a hardcoded list if we are verifying.
    // BETTER: The `classes` from dashboard has names like "10A - Math". 
    // We can't easily extract SubjectID from that string without the ID being in the object.
    
    // Let's assume for MVP validation we just want to create data.
    // I will add a mock subject selector or try to match.
    
    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
             const res = await fetch('/api/assignments', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('token')}` 
                },
                body: JSON.stringify({
                    title, description, grade, subjectId, dueDate, totalPoints
                })
            });
            const json = await res.json();
            if (json.success) {
                toast({ title: 'Success', description: 'Assignment created successfully' });
                setShowCreate(false);
                fetchAssignments();
                // Reset form
                setTitle(''); setDescription('');
            } else {
                toast({ title: 'Error', description: json.message, variant: 'destructive' });
            }
        } catch (error) {
             toast({ title: 'Error', description: 'Failed to create assignment', variant: 'destructive' });
        }
    };

    return (
        <div className="p-8 max-w-6xl mx-auto">
            <div className="flex justify-between items-center mb-8">
                <h1 className="text-2xl font-bold text-gray-900">Assignments</h1>
                <button 
                    onClick={() => setShowCreate(!showCreate)}
                    className="flex items-center gap-2 bg-brand-navy text-white px-4 py-2 rounded-lg hover:bg-opacity-90 transition-colors"
                >
                    <span className="material-symbols-outlined">add</span>
                    Create Assignment
                </button>
            </div>

            {/* Create Form (Expandable) */}
            {showCreate && (
                <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200 mb-8 animate-in fade-in slide-in-from-top-4">
                    <h2 className="text-lg font-semibold mb-4">New Assignment</h2>
                    <form onSubmit={handleCreate} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
                            <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full p-2 border rounded-md" placeholder="e.g. Algebra Homework 1" />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                             <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Grade / Class</label>
                                {/* Simply text input for Grade for now to match API expectation of 'String' */}
                                <input required value={grade} onChange={e => setGrade(e.target.value)} className="w-full p-2 border rounded-md" placeholder="e.g. 10" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Subject</label>
                                <select 
                                    required 
                                    value={subjectId} 
                                    onChange={e => setSubjectId(e.target.value)} 
                                    className="w-full p-2 border rounded-md"
                                >
                                    <option value="">Select a subject</option>
                                    {subjects.map(subject => (
                                        <option key={subject.id} value={subject.id}>
                                            {subject.name} ({subject.code})
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                             <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Due Date</label>
                                <input required type="date" value={dueDate} onChange={e => setDueDate(e.target.value)} className="w-full p-2 border rounded-md" />
                            </div>
                             <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Total Points</label>
                                <input required type="number" value={totalPoints} onChange={e => setTotalPoints(e.target.value)} className="w-full p-2 border rounded-md" />
                            </div>
                        </div>
                         <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                            <textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full p-2 border rounded-md h-24" placeholder="Instructions..." />
                        </div>
                        <div className="flex justify-end gap-2">
                             <button type="button" onClick={() => setShowCreate(false)} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-md">Cancel</button>
                             <button type="submit" className="px-4 py-2 bg-brand-navy text-white rounded-md hover:bg-opacity-90">Create Assignment</button>
                        </div>
                    </form>
                </div>
            )}

            {/* List */}
             <div className="grid gap-4">
                {loading ? <div className="text-center py-8 text-gray-500">Loading assignments...</div> : (
                    assignments.length > 0 ? assignments.map(assignment => (
                        <div key={assignment.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-200 flex justify-between items-center hover:border-brand-gold transition-colors group">
                            <div>
                                <div className="flex items-center gap-2 mb-1">
                                    <h3 className="font-semibold text-lg text-gray-900 group-hover:text-brand-navy">{assignment.title}</h3>
                                    <span className={`text-xs px-2 py-0.5 rounded-full ${assignment.status === 'ACTIVE' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'}`}>
                                        {assignment.status}
                                    </span>
                                </div>
                                <div className="text-sm text-gray-500 flex gap-4">
                                    <span>{assignment.subject?.name} • Grade {assignment.grade}</span>
                                    <span>Due: {new Date(assignment.dueDate).toLocaleDateString()}</span>
                                </div>
                            </div>
                            <div className="text-right flex flex-col items-end gap-2">
                                <div>
                                    <div className="text-2xl font-bold text-gray-900">{assignment._count.submissions}</div>
                                    <div className="text-xs text-gray-500 uppercase tracking-wider">Submissions</div>
                                </div>
                                <a href={`/teacher/assignments/${assignment.id}`} className="text-sm text-brand-navy hover:underline font-medium">
                                    Grade &raquo;
                                </a>
                            </div>
                        </div>
                    )) : (
                        <div className="text-center py-12 bg-gray-50 rounded-lg text-gray-500">
                            No assignments found. Create one to get started.
                        </div>
                    )
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useToast } from '@/components/ui/use-toast';

interface StudentAttendance {
    studentId: string;
    name: string;
    rollNumber: string;
    status: string; // PRESENT, ABSENT, LATE, EXCUSED
    notes: string;
}

export default function TeacherAttendancePage() {
    const { toast } = useToast();
    const [classes, setClasses] = useState<any[]>([]);
    const [selectedClassId, setSelectedClassId] = useState('');
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [students, setStudents] = useState<StudentAttendance[]>([]);
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        const fetchClasses = async () => {
            try {
                const res = await fetch('/api/teacher/dashboard', {
                    headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
                });
                const json = await res.json();
                if (json.success && json.data.classes) {
                    // Remove duplicates just in case
                    const uniqueClasses = Array.from(new Map(json.data.classes.map((item:any) => [item.id, item])).values());
                    setClasses(uniqueClasses);
                }
            } catch (error) {
                console.error(error);
            }
        };
        fetchClasses(); 
    }, []);

    // Fetch Students when Class + Date selected
    const fetchAttendance = async () => {
        if (!selectedClassId || !date) return;
        setLoading(true);
        try {
            const res = await fetch(`/api/attendance/class/${selectedClassId}?date=${date}`, {
                headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
            });
            const json = await res.json();
            if (json.success) {
                setStudents(json.data.students);
            } else {
                toast({ title: 'Error', description: json.message, variant: 'destructive' });
            }
        } catch (error) {
            console.error(error);
            toast({ title: 'Error', description: 'Failed to load students', variant: 'destructive' });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchAttendance();
    }, [selectedClassId, date]);

    const handleMarkChange = (studentId: string, status: string) => {
        setStudents(prev => prev.map(s => s.studentId === studentId ? { ...s, status } : s));
    };

    const handleNoteChange = (studentId: string, notes: string) => {
        setStudents(prev => prev.map(s => s.studentId === studentId ? { ...s, notes } : s));
    };

    const handleSave = async () => {
        setSaving(true);
        try {
            const res = await fetch('/api/attendance/mark', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('token')}` 
                },
                body: JSON.stringify({
                    classId: selectedClassId, // Not strictly used by backend validation yet but good to pass
                    date,
                    records: students.map(s => ({
                        studentId: s.studentId,
                        status: s.status,
                        notes: s.notes
                    }))
                })
            });
            const json = await res.json();
            if (json.success) {
                toast({ title: 'Success', description: 'Attendance saved successfully' });
            } else {
                 toast({ title: 'Error', description: json.message, variant: 'destructive' });
            }
        } catch (error) {
            console.error(error);
            toast({ title: 'Error', description: 'Failed to save attendance', variant: 'destructive' });
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="p-4 md:p-8 max-w-5xl mx-auto">
            <h1 className="text-2xl font-bold mb-6">Daily Attendance Register</h1>
            
            {/* Controls */}
            <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 mb-6 flex flex-wrap gap-4 items-end">
                <div className="flex-1 min-w-[200px]">
                    <label className="block text-sm font-medium text-gray-700 mb-1">Select Class</label>
                    <select 
                        className="w-full p-2 border border-gray-300 rounded-md"
                        value={selectedClassId}
                        onChange={(e) => setSelectedClassId(e.target.value)}
                    >
                        <option value="">-- Select Class --</option>
                        {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                </div>

                <div className="flex-1 min-w-[200px]">
                    <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
                    <input 
                        type="date" 
                        className="w-full p-2 border border-gray-300 rounded-md"
                        value={date}
                        onChange={(e) => setDate(e.target.value)}
                    />
                </div>

                <button 
                    onClick={fetchAttendance}
                    className="bg-gray-100 text-gray-700 px-4 py-2 rounded-md hover:bg-gray-200"
                >
                    Reload
                </button>
            </div>

            {/* List */}
            {loading ? (
                <div className="text-center py-10">Loading class list...</div>
            ) : selectedClassId ? (
                <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                     <table className="w-full">
                        <thead className="bg-gray-50 border-b border-gray-200">
                            <tr>
                                <th className="text-left p-4 font-medium text-gray-600">Student</th>
                                <th className="text-center p-4 font-medium text-gray-600">Status</th>
                                <th className="text-left p-4 font-medium text-gray-600">Notes</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {students.length > 0 ? students.map(student => (
                                <tr key={student.studentId} className="hover:bg-gray-50/50">
                                    <td className="p-4">
                                        <div className="font-medium text-gray-900">{student.name}</div>
                                        <div className="text-sm text-gray-500">{student.rollNumber}</div>
                                    </td>
                                    <td className="p-4">
                                        <div className="flex justify-center gap-2">
                                            {['PRESENT', 'ABSENT', 'LATE', 'EXCUSED'].map(status => (
                                                <button
                                                    key={status}
                                                    onClick={() => handleMarkChange(student.studentId, status)}
                                                    className={`px-3 py-1 rounded-full text-xs font-bold transition-colors ${
                                                        student.status === status
                                                            ? getStatusColor(status)
                                                            : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
                                                    }`}
                                                >
                                                    {status.charAt(0)}
                                                </button>
                                            ))}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <input
                                            type="text"
                                            placeholder="Optional notes..."
                                            className="w-full text-sm p-1 border-b border-gray-200 focus:border-brand-navy outline-none bg-transparent"
                                            value={student.notes || ''}
                                            onChange={(e) => handleNoteChange(student.studentId, e.target.value)}
                                        />
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan={3} className="p-8 text-center text-gray-500">
                                        No students found in this class.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                     </table>
                     
                     <div className="p-4 bg-gray-50 border-t border-gray-200 flex justify-end">
                        <button
                            onClick={handleSave}
                            disabled={saving}
                            className="bg-brand-navy text-white px-6 py-2 rounded-lg hover:bg-brand-navy/90 disabled:opacity-50"
                        >
                            {saving ? 'Saving...' : 'Save Register'}
                        </button>
                     </div>
                </div>
            ) : (
                <div className="text-center py-12 text-gray-500 bg-white rounded-lg border border-dashed border-gray-300">
                    Please select a class to mark attendance.
                </div>
            )}
        </div>
    );
}

function getStatusColor(status: string) {
    switch (status) {
        case 'PRESENT': return 'bg-green-100 text-green-700 border border-green-200';
        case 'ABSENT': return 'bg-red-100 text-red-700 border border-red-200';
        case 'LATE': return 'bg-yellow-100 text-yellow-700 border border-yellow-200';
        case 'EXCUSED': return 'bg-blue-100 text-blue-700 border border-blue-200';
        default: return 'bg-gray-100 text-gray-500';
    }
}

'use client';

import { useEffect, useState } from 'react';
import { MaterialIcon } from '@/components/ui/material-icon';
import { useToast } from '@/components/ui/use-toast';
import { useRouter } from 'next/navigation';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table"
import { Button } from '@/components/ui/button';

interface Student {
    id: string;
    name: string;
    rollNumber: string;
    attendance: string;
    status: string;
}

interface ClassDetails {
    id: string;
    name: string;
    grade: string;
    tutor: string;
}

export default function ClassDetailsPage({ params }: { params: { id: string } }) {
    const { toast } = useToast();
    const router = useRouter();
    const [details, setDetails] = useState<ClassDetails | null>(null);
    const [students, setStudents] = useState<Student[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchClassData = async () => {
            try {
                const res = await fetch(`/api/teacher/classes/${params.id}`, {
                    headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
                });
                const json = await res.json();
                if (json.success) {
                    setDetails(json.data.class);
                    setStudents(json.data.students);
                } else {
                    toast({ title: 'Error', description: json.message || 'Failed to load class', variant: 'destructive' });
                }
            } catch (error) {
                console.error(error);
                toast({ title: 'Error', description: 'Failed to load data', variant: 'destructive' });
            } finally {
                setLoading(false);
            }
        };
        fetchClassData();
    }, [params.id, toast]);

    if (loading) return <div className="p-8 text-center">Loading class details...</div>;
    if (!details) return <div className="p-8 text-center">Class not found</div>;

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-background-dark p-6">
             <header className="mb-8 flex justify-between items-center">
                <div>
                    <Button variant="ghost" onClick={() => router.back()} className="mb-2 pl-0 hover:bg-transparent hover:text-design-primary">
                        <MaterialIcon icon="arrow_back" className="mr-2" />
                        Back to Classes
                    </Button>
                    <h1 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
                        {details.name} (Grade {details.grade})
                    </h1>
                    <p className="text-gray-600 dark:text-gray-400">Form Tutor: {details.tutor}</p>
                </div>
                <div className="flex gap-3">
                     <Button variant="outline">
                        <MaterialIcon icon="download" className="mr-2" />
                        Export List
                     </Button>
                     <Button onClick={() => router.push(`/teacher/attendance?class=${details.id}`)}>
                        <MaterialIcon icon="edit_note" className="mr-2" />
                        Mark Attendance
                     </Button>
                </div>
            </header>

            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Roll Number</TableHead>
                            <TableHead>Name</TableHead>
                            <TableHead>Attendance Rate</TableHead>
                            <TableHead>Status</TableHead>
                            <TableHead className="text-right">Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {students.length > 0 ? students.map((bg) => (
                            <TableRow key={bg.id}>
                                <TableCell className="font-mono text-xs">{bg.rollNumber}</TableCell>
                                <TableCell className="font-medium">{bg.name}</TableCell>
                                <TableCell>{bg.attendance}</TableCell>
                                <TableCell>
                                    <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
                                        {bg.status}
                                    </span>
                                </TableCell>
                                <TableCell className="text-right">
                                    <Button variant="ghost" size="sm">
                                        View Profile
                                    </Button>
                                </TableCell>
                            </TableRow>
                        )) : (
                            <TableRow>
                                <TableCell colSpan={5} className="text-center py-8 text-gray-500">
                                    No students found in this class.
                                </TableCell>
                            </TableRow>
                        )}
                    </TableBody>
                </Table>
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { MaterialIcon } from '@/components/ui/material-icon';
import { BadgeNew } from '@/components/ui/badge-new';
import { useToast } from '@/components/ui/use-toast';

interface ClassItem {
    id: string;
    name: string;
    grade: string;
    role: string;
    subject: string;
    studentsCount: number;
    room?: string;
}

export default function MyClassesPage() {
    const { toast } = useToast();
    const [classes, setClasses] = useState<ClassItem[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchClasses = async () => {
            try {
                const res = await fetch('/api/teacher/classes', {
                    headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
                });
                const json = await res.json();
                if (json.success) {
                    setClasses(json.data);
                } else {
                    toast({ title: 'Error', description: json.message || 'Failed to load classes', variant: 'destructive' });
                }
            } catch (error) {
                console.error(error);
                toast({ title: 'Error', description: 'Failed to load classes', variant: 'destructive' });
            } finally {
                setLoading(false);
            }
        };
        fetchClasses();
    }, [toast]);

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-background-dark p-6">
             <header className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
                    <MaterialIcon icon="class" className="text-design-primary" />
                    My Classes
                </h1>
                <p className="text-gray-600 dark:text-gray-400">View and manage the classes you teach.</p>
            </header>

            {loading ? (
                <div>Loading classes...</div>
            ) : classes.length === 0 ? (
                <div className="text-center p-12 bg-white rounded-xl border border-dashed border-gray-300">
                    <MaterialIcon icon="school" className="text-gray-300 mx-auto mb-4" size="4xl" />
                    <h3 className="text-lg font-medium text-gray-900">No Classes Assigned</h3>
                    <p className="text-gray-500">You haven't been assigned to any classes or subjects yet.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {classes.map((cls) => (
                        <div key={`${cls.id}-${cls.subject}`} className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-sm border border-gray-200 dark:border-gray-700 hover:shadow-md transition-shadow">
                            <div className="flex justify-between items-start mb-4">
                                <BadgeNew variant={cls.role === 'Form Tutor' ? 'primary' : 'secondary'}>
                                    {cls.role}
                                </BadgeNew>
                                <MaterialIcon icon="more_vert" className="text-gray-400 cursor-pointer" />
                            </div>
                            
                            <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-1">
                                {cls.grade} {cls.name}
                            </h3>
                            <p className="text-sm font-medium text-design-primary mb-4">{cls.subject}</p>
                            
                            <div className="flex items-center gap-4 text-sm text-gray-600 dark:text-gray-400 mb-6">
                                <div className="flex items-center gap-1">
                                    <MaterialIcon icon="people" size="sm" />
                                    <span>{cls.studentsCount} Students</span>
                                </div>
                                <div className="flex items-center gap-1">
                                    <MaterialIcon icon="meeting_room" size="sm" />
                                    <span>{cls.room || 'TBD'}</span>
                                </div>
                            </div>

                            <div className="flex gap-2">
                                <button className="flex-1 py-2 px-4 bg-gray-100 dark:bg-gray-700 text-gray-900 dark:text-white rounded-lg text-sm font-medium hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors">
                                    Attendance
                                </button>
                                <button className="flex-1 py-2 px-4 bg-design-primary text-white rounded-lg text-sm font-medium hover:bg-design-primary/90 transition-colors">
                                    View Class
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useToast } from '@/components/ui/use-toast';
import Link from 'next/link';

interface GradeRecord {
  studentId: string;
  rollNumber: string;
  name: string;
  profileImage?: string;
  assessment: number;
  midterm: number;
  final: number;
  total: number;
  letterGrade: string;
  status: 'APPROVED' | 'SUBMITTED' | 'DRAFT';
  comments: string;
}

interface ClassStats {
  average: number;
  highest: number;
  lowest: number;
  passRate: number;
}

export default function TeacherGradebook() {
  const { toast } = useToast();


  const [selectedClass, ] = useState('Form 3 Science');
  const [selectedTerm, ] = useState('TERM 2');
  const [academicYear, ] = useState('2023-2024');
  const [subject, ] = useState('Physics & Chemistry Focus');

  const [students, setStudents] = useState<GradeRecord[]>([]);
  const [stats, setStats] = useState<ClassStats>({ average: 0, highest: 0, lowest: 0, passRate: 0 });
  const [loading, setLoading] = useState(false);
  const [lastSaved, setLastSaved] = useState('2 minutes ago');

  useEffect(() => {
    // Fetch grades from API
    const fetchGrades = async () => {
      setLoading(true);
      try {
        const res = await fetch('/api/teacher/grades?class=form3&subject=science&term=2', {
          headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
        });
        const json = await res.json();
        if (json.success) {
          setStudents(json.data || []);
          setStats(json.stats || { average: 0, highest: 0, lowest: 0, passRate: 0 });
        }
      } catch (error) {
        console.error('Failed to fetch grades', error);
        setStudents([]);
        toast({ title: 'Error', description: 'Failed to load grades data', variant: 'destructive' });
      } finally {
        setLoading(false);
      }
    };

    fetchGrades();
  }, [selectedClass, selectedTerm]);

  /* Mock data removed - now uses API */

  const handleGradeChange = (studentId: string, field: 'assessment' | 'midterm' | 'final', value: number) => {
    setStudents(prev => prev.map(s => {
      if (s.studentId === studentId) {
        const updated = { ...s, [field]: value };
        updated.total = updated.assessment + updated.midterm + updated.final;
        updated.letterGrade = calculateLetterGrade(updated.total);
        return updated;
      }
      return s;
    }));
  };

  const handleCommentChange = (studentId: string, value: string) => {
    setStudents(prev => prev.map(s => s.studentId === studentId ? { ...s, comments: value } : s));
  };

  const calculateLetterGrade = (total: number): string => {
    if (total >= 90) return 'A';
    if (total >= 80) return 'B';
    if (total >= 70) return 'B';
    if (total >= 60) return 'C';
    if (total >= 50) return 'D';
    return 'F';
  };

  const getGradeColor = (grade: string) => {
    if (grade === 'A') return 'bg-green-100 text-green-700';
    if (grade === 'B') return 'bg-blue-100 text-blue-700';
    if (grade === 'C') return 'bg-yellow-100 text-yellow-700';
    return 'bg-red-100 text-red-700';
  };

  const getStatusBadge = (status: string) => {
    if (status === 'APPROVED') return { bg: 'bg-green-100 text-green-700', icon: 'check_circle', label: 'Approved' };
    if (status === 'SUBMITTED') return { bg: 'bg-blue-100 text-blue-700', icon: 'send', label: 'Submitted' };
    return { bg: 'bg-amber-100 text-amber-700', icon: 'edit_note', label: 'Draft' };
  };

  const saveDraft = async () => {
    toast({ title: 'Saving...', description: 'Saving grades as draft' });
    // API call to save
    setLastSaved('Just now');
  };

  const submitForApproval = async () => {
    toast({ title: 'Submitting...', description: 'Submitting grades for approval' });
    // API call to submit
  };

  const exportCSV = () => {
    toast({ title: 'Exporting...', description: 'Downloading CSV file' });
  };

  return (
    <div className="bg-gray-50 min-h-screen flex flex-col font-sans">
      {/* Top Navigation */}
      <header className="flex items-center justify-between border-b border-gray-200 bg-white px-10 py-3 sticky top-0 z-50">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-4 text-gray-900">
            <div className="size-8 flex items-center justify-center bg-blue-50 rounded-lg text-blue-600">
              <span className="material-symbols-outlined text-2xl">school</span>
            </div>
            <h2 className="text-gray-900 text-lg font-bold leading-tight tracking-tight">Regisbridge Academy</h2>
          </div>
          <label className="flex flex-col min-w-40 !h-10 max-w-64 hidden md:flex">
            <div className="flex w-full flex-1 items-stretch rounded-lg h-full ring-1 ring-gray-200 focus-within:ring-2 focus-within:ring-blue-600">
              <div className="text-gray-500 flex border-none bg-gray-50 items-center justify-center pl-4 rounded-l-lg border-r-0">
                <span className="material-symbols-outlined text-[20px]">search</span>
              </div>
              <input
                className="form-input flex w-full min-w-0 flex-1 resize-none overflow-hidden rounded-lg rounded-l-none text-gray-900 focus:outline-0 focus:ring-0 border-none bg-gray-50 focus:border-none h-full placeholder:text-gray-500 px-4 pl-2 text-base font-normal leading-normal"
                placeholder="Search student or class"
              />
            </div>
          </label>
        </div>
        <div className="flex flex-1 justify-end gap-8">
          <div className="hidden lg:flex items-center gap-9">
            <Link className="text-gray-900 text-sm font-medium leading-normal hover:text-blue-600 transition-colors" href="/teacher">Dashboard</Link>
            <Link className="text-blue-600 text-sm font-bold leading-normal" href="/teacher/grades">Academics</Link>
            <Link className="text-gray-900 text-sm font-medium leading-normal hover:text-blue-600 transition-colors" href="/teacher/classes">Students</Link>
            <Link className="text-gray-900 text-sm font-medium leading-normal hover:text-blue-600 transition-colors" href="/teacher/reports">Reports</Link>
          </div>
          <div className="flex items-center gap-4">
            <button className="text-gray-500 hover:text-gray-900">
              <span className="material-symbols-outlined">notifications</span>
            </button>
            <div className="bg-blue-100 rounded-full size-10 border-2 border-white shadow-sm cursor-pointer flex items-center justify-center">
              <span className="text-sm font-bold text-blue-600">TR</span>
            </div>
          </div>
        </div>
      </header>

      <div className="flex flex-1 justify-center py-5 px-4 md:px-10 lg:px-20 xl:px-40">
        <div className="flex flex-col max-w-[1280px] flex-1 w-full">
          {/* Breadcrumbs */}
          <div className="flex flex-wrap gap-2 p-4">
            <Link className="text-gray-500 text-sm font-medium leading-normal hover:underline" href="/teacher/academics">Academics</Link>
            <span className="text-gray-500 text-sm font-medium leading-normal">/</span>
            <Link className="text-gray-500 text-sm font-medium leading-normal hover:underline" href="/teacher/classes">My Classes</Link>
            <span className="text-gray-500 text-sm font-medium leading-normal">/</span>
            <span className="text-gray-900 text-sm font-medium leading-normal">Form 3 Science - Results Entry</span>
          </div>

          {/* Page Title & Main Actions */}
          <div className="flex flex-wrap justify-between items-end gap-4 p-4">
            <div className="flex min-w-72 flex-col gap-2">
              <h1 className="text-gray-900 text-3xl md:text-4xl font-black leading-tight tracking-tight">Gradebook: {selectedClass}</h1>
              <div className="flex items-center gap-3">
                <span className="bg-blue-100 text-blue-700 text-xs font-bold px-2 py-1 rounded">{selectedTerm}</span>
                <p className="text-gray-500 text-base font-normal leading-normal">{academicYear} Academic Year • {subject}</p>
              </div>
            </div>
            <div className="flex gap-3">
              <button onClick={exportCSV} className="flex items-center justify-center gap-2 rounded-lg h-10 px-4 bg-white border border-gray-200 text-gray-700 text-sm font-bold shadow-sm hover:bg-gray-50 transition-colors">
                <span className="material-symbols-outlined text-[20px]">file_download</span>
                <span className="truncate hidden sm:inline">Export CSV</span>
              </button>
              <button className="flex items-center justify-center gap-2 rounded-lg h-10 px-4 bg-white border border-gray-200 text-gray-700 text-sm font-bold shadow-sm hover:bg-gray-50 transition-colors">
                <span className="material-symbols-outlined text-[20px]">history</span>
                <span className="truncate hidden sm:inline">View Logs</span>
              </button>
            </div>
          </div>

          {/* Analytics Cards */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 p-4">
            <div className="flex flex-col gap-2 rounded-xl p-6 bg-white border border-gray-200 shadow-sm">
              <div className="flex justify-between items-start">
                <p className="text-gray-500 text-sm font-medium uppercase tracking-wider">Class Average</p>
                <span className="material-symbols-outlined text-gray-400">analytics</span>
              </div>
              <div className="flex items-baseline gap-2">
                <p className="text-gray-900 text-3xl font-bold leading-tight">{stats.average}%</p>
                <span className="flex items-center text-green-600 text-sm font-bold">
                  <span className="material-symbols-outlined text-sm mr-0.5">trending_up</span>
                  2.5%
                </span>
              </div>
            </div>

            <div className="flex flex-col gap-2 rounded-xl p-6 bg-white border border-gray-200 shadow-sm">
              <div className="flex justify-between items-start">
                <p className="text-gray-500 text-sm font-medium uppercase tracking-wider">Highest Score</p>
                <span className="material-symbols-outlined text-gray-400">military_tech</span>
              </div>
              <div className="flex items-baseline gap-2">
                <p className="text-gray-900 text-3xl font-bold leading-tight">{stats.highest}%</p>
                <span className="text-gray-400 text-sm font-medium">No change</span>
              </div>
            </div>

            <div className="flex flex-col gap-2 rounded-xl p-6 bg-white border border-gray-200 shadow-sm">
              <div className="flex justify-between items-start">
                <p className="text-gray-500 text-sm font-medium uppercase tracking-wider">Lowest Score</p>
                <span className="material-symbols-outlined text-gray-400">warning</span>
              </div>
              <div className="flex items-baseline gap-2">
                <p className="text-gray-900 text-3xl font-bold leading-tight">{stats.lowest}%</p>
                <span className="flex items-center text-green-600 text-sm font-bold">
                  <span className="material-symbols-outlined text-sm mr-0.5">trending_up</span>
                  5%
                </span>
              </div>
            </div>

            <div className="flex flex-col gap-2 rounded-xl p-6 bg-white border border-gray-200 shadow-sm">
              <div className="flex justify-between items-start">
                <p className="text-gray-500 text-sm font-medium uppercase tracking-wider">Pass Rate</p>
                <span className="material-symbols-outlined text-gray-400">check_circle</span>
              </div>
              <div className="flex items-baseline gap-2">
                <p className="text-gray-900 text-3xl font-bold leading-tight">{stats.passRate}%</p>
                <span className="flex items-center text-green-600 text-sm font-bold">
                  <span className="material-symbols-outlined text-sm mr-0.5">trending_up</span>
                  1.2%
                </span>
              </div>
            </div>
          </div>

          {/* Filters & Legend */}
          <div className="flex flex-wrap items-center justify-between gap-4 p-4 border-b border-transparent">
            <div className="flex gap-2 overflow-x-auto pb-2 sm:pb-0">
              <button className="flex h-9 shrink-0 items-center justify-center gap-x-2 rounded-lg bg-gray-100 hover:bg-gray-200 px-4 transition-colors">
                <span className="text-gray-900 text-sm font-medium">All Students</span>
                <span className="material-symbols-outlined text-[18px]">keyboard_arrow_down</span>
              </button>
              <button className="flex h-9 shrink-0 items-center justify-center gap-x-2 rounded-lg bg-gray-100 hover:bg-gray-200 px-4 transition-colors">
                <span className="text-gray-900 text-sm font-medium">At Risk</span>
                <span className="material-symbols-outlined text-[18px]">keyboard_arrow_down</span>
              </button>
              <button className="flex h-9 shrink-0 items-center justify-center gap-x-2 rounded-lg bg-gray-100 hover:bg-gray-200 px-4 transition-colors">
                <span className="text-gray-900 text-sm font-medium">High Achievers</span>
                <span className="material-symbols-outlined text-[18px]">keyboard_arrow_down</span>
              </button>
              <button className="flex h-9 shrink-0 items-center justify-center gap-x-2 rounded-lg bg-gray-100 hover:bg-gray-200 px-4 transition-colors">
                <span className="text-gray-900 text-sm font-medium">Sort By Name</span>
                <span className="material-symbols-outlined text-[18px]">sort</span>
              </button>
            </div>
            <div className="flex items-center gap-4 text-xs font-medium text-gray-500">
              <div className="flex items-center gap-1.5"><span className="block size-2.5 rounded-full bg-green-500"></span>Approved</div>
              <div className="flex items-center gap-1.5"><span className="block size-2.5 rounded-full bg-blue-500"></span>Submitted</div>
              <div className="flex items-center gap-1.5"><span className="block size-2.5 rounded-full bg-amber-400"></span>Draft</div>
            </div>
          </div>

          {/* Main Data Table */}
          <div className="p-4">
            <div className="w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm bg-white">
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-gray-50 border-b border-gray-200">
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider min-w-[200px]">Student Details</th>
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider w-[100px] text-center">
                        Assess.<br /><span className="text-[10px] opacity-70">(20%)</span>
                      </th>
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider w-[100px] text-center">
                        Mid-Term<br /><span className="text-[10px] opacity-70">(30%)</span>
                      </th>
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider w-[100px] text-center">
                        Final<br /><span className="text-[10px] opacity-70">(50%)</span>
                      </th>
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider w-[80px] text-center">Total</th>
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider w-[80px] text-center">Grade</th>
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider min-w-[140px]">Status</th>
                      <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider min-w-[200px]">Comments</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {loading ? (
                      <tr><td colSpan={8} className="text-center py-8">Loading...</td></tr>
                    ) : students.map((student) => (
                      <tr key={student.studentId} className="group hover:bg-gray-50 transition-colors">
                        <td className="p-4">
                          <div className="flex items-center gap-3">
                            <div className="size-10 rounded-full bg-blue-100 flex items-center justify-center">
                              <span className="text-sm font-bold text-blue-600">{student.name.substring(0, 2)}</span>
                            </div>
                            <div>
                              <p className="text-sm font-bold text-gray-900">{student.name}</p>
                              <p className="text-xs text-gray-500">ID: #{student.rollNumber}</p>
                            </div>
                          </div>
                        </td>
                        <td className="p-2 text-center">
                          <input
                            className="w-full text-center text-sm font-medium rounded border border-gray-300 bg-white py-1.5 focus:ring-2 focus:ring-blue-600 focus:border-transparent transition-all"
                            type="number"
                            max="20"
                            value={student.assessment}
                            onChange={(e) => handleGradeChange(student.studentId, 'assessment', parseInt(e.target.value) || 0)}
                          />
                        </td>
                        <td className="p-2 text-center">
                          <input
                            className="w-full text-center text-sm font-medium rounded border border-gray-300 bg-white py-1.5 focus:ring-2 focus:ring-blue-600 focus:border-transparent transition-all"
                            type="number"
                            max="30"
                            value={student.midterm}
                            onChange={(e) => handleGradeChange(student.studentId, 'midterm', parseInt(e.target.value) || 0)}
                          />
                        </td>
                        <td className="p-2 text-center">
                          <input
                            className="w-full text-center text-sm font-medium rounded border border-gray-300 bg-white py-1.5 focus:ring-2 focus:ring-blue-600 focus:border-transparent transition-all"
                            type="number"
                            max="50"
                            value={student.final}
                            onChange={(e) => handleGradeChange(student.studentId, 'final', parseInt(e.target.value) || 0)}
                          />
                        </td>
                        <td className="p-4 text-center">
                          <span className="text-sm font-bold text-gray-900">{student.total}</span>
                        </td>
                        <td className="p-4 text-center">
                          <span className={`inline-flex items-center justify-center size-8 rounded-full font-bold text-sm ${getGradeColor(student.letterGrade)}`}>
                            {student.letterGrade}
                          </span>
                        </td>
                        <td className="p-4">
                          {(() => {
                            const badge = getStatusBadge(student.status);
                            return (
                              <span className={`inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium ${badge.bg}`}>
                                <span className="material-symbols-outlined text-[14px]">{badge.icon}</span>
                                {badge.label}
                              </span>
                            );
                          })()}
                        </td>
                        <td className="p-4">
                          <input
                            className="w-full text-sm rounded border-none bg-transparent placeholder:text-gray-400 focus:ring-0"
                            placeholder="Add comment..."
                            type="text"
                            value={student.comments}
                            onChange={(e) => handleCommentChange(student.studentId, e.target.value)}
                          />
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Pagination */}
              <div className="flex flex-col sm:flex-row items-center justify-between gap-4 p-4 border-t border-gray-200 bg-gray-50">
                <p className="text-sm text-gray-500">
                  Showing <span className="font-bold text-gray-900">1-{students.length}</span> of <span className="font-bold text-gray-900">{students.length}</span> students
                </p>
                <div className="flex items-center gap-2">
                  <button className="p-2 rounded-lg hover:bg-gray-200 text-gray-500 disabled:opacity-50 transition-colors" disabled>
                    <span className="material-symbols-outlined">chevron_left</span>
                  </button>
                  <button className="size-8 rounded-lg bg-blue-600 text-white text-sm font-bold">1</button>
                  <button className="p-2 rounded-lg hover:bg-gray-200 text-gray-500 transition-colors" disabled>
                    <span className="material-symbols-outlined">chevron_right</span>
                  </button>
                </div>
              </div>
            </div>
          </div>

