  TableRow,
} from '@/components/ui/table';
import { 
  Calendar as CalendarIcon,
  Download, 
  Upload, 
  Search, 
  CheckCircle, 
  XCircle, 
  Clock,
  Users,
  TrendingUp,
  AlertCircle,
  Save
} from 'lucide-react';
import { format } from 'date-fns';
import { useToast } from '@/components/ui/use-toast';

interface AttendanceRecord {
  studentId: string;
  rollNumber: string;
  studentName: string;
  grade: string;
  status: 'present' | 'absent' | 'late' | 'excused' | null;
  remarks?: string;
}

export function AttendanceManagement() {
  const { toast } = useToast();
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [selectedGrade, setSelectedGrade] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);

  const stats = {
    totalStudents: attendance.length,
    present: attendance.filter(a => a.status === 'present').length,
    absent: attendance.filter(a => a.status === 'absent').length,
    late: attendance.filter(a => a.status === 'late').length,
    excused: attendance.filter(a => a.status === 'excused').length,
    attendanceRate: attendance.length > 0 
      ? Math.round((attendance.filter(a => a.status === 'present' || a.status === 'late').length / attendance.length) * 100)
      : 0
  };

  const fetchAttendance = async () => {
    setLoading(true);
    try {
      const formattedDate = format(selectedDate, 'yyyy-MM-dd');
      const res = await fetch(`/api/admin/attendance?date=${formattedDate}&grade=${selectedGrade}`);
      const data = await res.json();
      if (data.success) {
        setAttendance(data.data);
      } else {
        toast({ title: 'Error', description: 'Failed to fetch data', variant: 'destructive' });
      }
    } catch (error) {
      console.error(error);
      toast({ title: 'Error', description: 'Connection failed', variant: 'destructive' });
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchAttendance();
  }, [selectedDate, selectedGrade]);

  const handleMarkAttendance = (studentId: string, status: 'present' | 'absent' | 'late' | 'excused') => {
    setAttendance(prev =>
      prev.map(record =>
        record.studentId === studentId
          ? { ...record, status }
          : record
      )
    );
  };

  const handleBulkMark = (status: 'present' | 'absent') => {
    setAttendance(prev =>
      prev.map(record => ({ ...record, status }))
    );
  };

  const saveAttendance = async () => {
    try {
      const recordsToSave = attendance.filter(a => a.status !== null).map(a => ({
        studentId: a.studentId,
        status: a.status,
        remarks: a.remarks
      }));

      const res = await fetch('/api/admin/attendance', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          date: format(selectedDate, 'yyyy-MM-dd'),
          records: recordsToSave
        })
      });

      const data = await res.json();
      if (data.success) {
        toast({ title: 'Success', description: 'Attendance saved successfully' });
      } else {
         toast({ title: 'Error', description: data.message, variant: 'destructive' });
      }
    } catch (error) {
       toast({ title: 'Error', description: 'Failed to save', variant: 'destructive' });
    }
  };

  const filteredAttendance = attendance.filter(record => {
    const matchesSearch = record.studentName.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         record.rollNumber.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesSearch;
  });

  const getStatusColor = (status: string | null) => {
    switch (status) {
      case 'present': return 'bg-green-100 text-green-800';
      case 'absent': return 'bg-red-100 text-red-800';
      case 'late': return 'bg-yellow-100 text-yellow-800';
      case 'excused': return 'bg-blue-100 text-blue-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="space-y-6">
      <AdminHeader
        title="Attendance Management"
        description="Track and manage student attendance records"
        action={
             <Button onClick={saveAttendance} disabled={loading}>
              <Save className="h-4 w-4 mr-2" />
              Save Changes
            </Button>
        }
      />

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Users className="h-4 w-4" /> Total
            </CardTitle>
          </CardHeader>
          <CardContent><p className="text-2xl font-bold">{stats.totalStudents}</p></CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium flex items-center gap-2 text-green-600">
              <CheckCircle className="h-4 w-4" /> Present
            </CardTitle>
          </CardHeader>
          <CardContent><p className="text-2xl font-bold text-green-600">{stats.present}</p></CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium flex items-center gap-2 text-red-600">
              <XCircle className="h-4 w-4" /> Absent
            </CardTitle>
          </CardHeader>
          <CardContent><p className="text-2xl font-bold text-red-600">{stats.absent}</p></CardContent>
        </Card>
         <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium flex items-center gap-2 text-yellow-600">
              <Clock className="h-4 w-4" /> Late
            </CardTitle>
          </CardHeader>
          <CardContent><p className="text-2xl font-bold text-yellow-600">{stats.late}</p></CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium flex items-center gap-2 text-blue-600">
              <TrendingUp className="h-4 w-4" /> Rate
            </CardTitle>
          </CardHeader>
          <CardContent><p className="text-2xl font-bold text-blue-600">{stats.attendanceRate}%</p></CardContent>
        </Card>
      </div>

      {/* Filters and Actions */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col md:flex-row gap-4">
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" className="w-full md:w-[240px] justify-start text-left font-normal">
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {format(selectedDate, 'PPP')}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={selectedDate}
                  onSelect={(date) => date && setSelectedDate(date)}
                  initialFocus
                />
              </PopoverContent>
            </Popover>

            <Select value={selectedGrade} onValueChange={setSelectedGrade}>
              <SelectTrigger className="w-full md:w-[180px]">
                <SelectValue placeholder="Select Grade" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Grades</SelectItem>
                {[9, 10, 11, 12].map(g => (
                    <SelectItem key={g} value={g.toString()}>Grade {g}</SelectItem>
                ))}
              </SelectContent>
            </Select>

            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <Input
                placeholder="Search..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
            
             <div className="flex gap-2">
                <Button size="sm" variant="outline" onClick={() => handleBulkMark('present')}>All Present</Button>
                <Button size="sm" variant="outline" onClick={() => handleBulkMark('absent')}>All Absent</Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Attendance Table */}
      <Card>
        <CardContent className="pt-6">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>ID</TableHead>
                <TableHead>Student Name</TableHead>
                <TableHead>Grade</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {loading ? (
                 <TableRow><TableCell colSpan={5} className="text-center py-8">Loading...</TableCell></TableRow>
              ) : filteredAttendance.length === 0 ? (
                <TableRow><TableCell colSpan={5} className="text-center py-8">No students found</TableCell></TableRow>
              ) : (
                filteredAttendance.map((record) => (
                  <TableRow key={record.studentId}>
                    <TableCell className="font-medium">{record.rollNumber}</TableCell>
                    <TableCell>{record.studentName}</TableCell>
                    <TableCell>{record.grade}</TableCell>
                    <TableCell>
                      <Badge className={getStatusColor(record.status)}>
                        {record.status ? record.status.toUpperCase() : 'NOT MARKED'}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        <Button size="sm" variant={record.status === 'present' ? 'default' : 'ghost'} onClick={() => handleMarkAttendance(record.studentId, 'present')} className="h-8 w-8 p-0 text-green-600 bg-green-50 hover:bg-green-100">
                          <CheckCircle className="h-4 w-4" />
                        </Button>
                        <Button size="sm" variant={record.status === 'absent' ? 'default' : 'ghost'} onClick={() => handleMarkAttendance(record.studentId, 'absent')} className="h-8 w-8 p-0 text-red-600 bg-red-50 hover:bg-red-100">
                          <XCircle className="h-4 w-4" />
                        </Button>
                        <Button size="sm" variant={record.status === 'late' ? 'default' : 'ghost'} onClick={() => handleMarkAttendance(record.studentId, 'late')} className="h-8 w-8 p-0 text-yellow-600 bg-yellow-50 hover:bg-yellow-100">
                          <Clock className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { AdminHeader } from './shared/AdminHeader';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Plus, Search, Calendar, MoreVertical, Trash, Edit } from 'lucide-react';
import { getAllNews, getAllEvents, createNews, createEvent, deleteNews, deleteEvent } from '@/services/adminService';
import { NewsArticle, Event } from '@/types/admin';
import { useToast } from '@/components/ui/use-toast';
import { format } from 'date-fns';

export function ContentManagement() {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState('news');
  const [news, setNews] = useState<NewsArticle[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);

  // Dialog States
  const [isNewsOpen, setIsNewsOpen] = useState(false);
  const [isEventOpen, setIsEventOpen] = useState(false);

  // Forms
  const [newsForm, setNewsForm] = useState({
    title: '',
    content: '',
    category: 'news',
    publishDate: '',
    status: 'published'
  });

  const [eventForm, setEventForm] = useState({
    title: '',
    description: '',
    eventDate: '',
    location: '',
    category: 'academic',
  });

  const fetchData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'news') {
        const response: any = await getAllNews(); // Type assertion as response structure varies
        // adminService returns data directly usually? getAllNews returns Promise<NewsArticle[]>
        // Checking adminService: response.data!
        // But API returns { success: true, data: { data: [...] } } for news pagination?
        // Let's assume generic fetch returns data. 
        // Note: My API implementation returns { success: true, data: { data: [] } } for paginated news
        // But adminService.ts might expect just array. 
        // If adminService uses `authenticatedFetch` which returns `response.json()`, then `response.data` is the payload.
        // So safe to assume we get the payload.
        
        // Handling potential structure mismatch gracefully
        const data = response.data || response; 
        setNews(Array.isArray(data) ? data : (data.data || []));
      } else {
        const data = await getAllEvents();
        setEvents(data);
      }
    } catch (error) {
      console.error('Failed to fetch content', error);
      // Don't show toast on initial load if just empty/error due to migration not done
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  const handleCreateNews = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await createNews(newsForm as any);
      toast({ title: 'Success', description: 'News article created' });
      setIsNewsOpen(false);
      fetchData();
      setNewsForm({ title: '', content: '', category: 'news', publishDate: '', status: 'published' });
    } catch (error) {
      toast({ title: 'Error', description: 'Failed to create news', variant: 'destructive' });
    }
  };

  const handleCreateEvent = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await createEvent(eventForm as any);
      toast({ title: 'Success', description: 'Event created' });
      setIsEventOpen(false);
      fetchData();
      setEventForm({ title: '', description: '', eventDate: '', location: '', category: 'academic' });
    } catch (error) {
      toast({ title: 'Error', description: 'Failed to create event', variant: 'destructive' });
    }
  };

  const handleDelete = async (id: string, type: 'news' | 'event') => {
    if(!confirm('Are you sure?')) return;
    try {
      if (type === 'news') await deleteNews(id);
      else await deleteEvent(id);
      toast({ title: 'Success', description: 'Item deleted' });
      fetchData();
    } catch (error) {
      toast({ title: 'Error', description: 'Failed to delete item', variant: 'destructive' });
    }
  }

  return (
    <div className="space-y-6">
      <AdminHeader
        title="Content Management"
        description="Create and manage news, announcements, and school events"
        action={
          <Button onClick={() => activeTab === 'news' ? setIsNewsOpen(true) : setIsEventOpen(true)}>
            <Plus className="h-4 w-4 mr-2" />
            {activeTab === 'news' ? 'Create Article' : 'Create Event'}
          </Button>
        }
      />

      <Tabs defaultValue="news" value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList>
          <TabsTrigger value="news">News & Announcements</TabsTrigger>
          <TabsTrigger value="events">Events</TabsTrigger>
        </TabsList>

        {/* NEWS TAB */}
        <TabsContent value="news" className="space-y-4 mt-4">
          <div className="bg-white rounded-lg border shadow-sm">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Title</TableHead>
                  <TableHead>Category</TableHead>
                  <TableHead>Date</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                   <TableRow><TableCell colSpan={5} className="text-center py-8">Loading...</TableCell></TableRow>
                ) : news.length === 0 ? (
                   <TableRow><TableCell colSpan={5} className="text-center py-8">No news articles found</TableCell></TableRow>
                ) : (
                  news.map((item) => (
                    <TableRow key={item.id}>
                      <TableCell className="font-medium">{item.title}</TableCell>
                      <TableCell className="capitalize">{item.category}</TableCell>
                      <TableCell>
                        {item.publishDate ? format(new Date(item.publishDate), 'MMM d, yyyy') : 'N/A'}
                      </TableCell>
                      <TableCell>
                        <Badge variant={item.status === 'published' ? 'default' : 'secondary'}>
                          {item.status}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-right">
                        <Button variant="ghost" size="icon" onClick={() => handleDelete(item.id, 'news')}>
                          <Trash className="h-4 w-4 text-red-500" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </TabsContent>

        {/* EVENTS TAB */}
        <TabsContent value="events" className="space-y-4 mt-4">
          <div className="bg-white rounded-lg border shadow-sm">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Event</TableHead>
                  <TableHead>Date</TableHead>
                  <TableHead>Location</TableHead>
                  <TableHead>Category</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                   <TableRow><TableCell colSpan={5} className="text-center py-8">Loading...</TableCell></TableRow>
                ) : events.length === 0 ? (
                   <TableRow><TableCell colSpan={5} className="text-center py-8">No events found</TableCell></TableRow>
                ) : (
                  events.map((item) => (
                    <TableRow key={item.id}>
                      <TableCell className="font-medium">{item.title}</TableCell>
                      <TableCell>
                         {item.eventDate ? format(new Date(item.eventDate), 'PPP p') : 'N/A'}
                      </TableCell>
                      <TableCell>{item.location || 'TBD'}</TableCell>
                      <TableCell className="capitalize">{item.category}</TableCell>
                      <TableCell className="text-right">
                        <Button variant="ghost" size="icon" onClick={() => handleDelete(item.id, 'event')}>
                           <Trash className="h-4 w-4 text-red-500" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </TabsContent>
      </Tabs>

      {/* CREATE NEWS DIALOG */}
      <Dialog open={isNewsOpen} onOpenChange={setIsNewsOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create News Article</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleCreateNews} className="space-y-4">
            <div className="space-y-2">
              <Label>Title</Label>
              <Input required value={newsForm.title} onChange={e => setNewsForm({...newsForm, title: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Category</Label>
              <Select value={newsForm.category} onValueChange={val => setNewsForm({...newsForm, category: val})}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="news">News</SelectItem>
                  <SelectItem value="announcement">Announcement</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Content</Label>
              <Textarea required value={newsForm.content} onChange={e => setNewsForm({...newsForm, content: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Publish Date</Label>
              <Input type="date" value={newsForm.publishDate} onChange={e => setNewsForm({...newsForm, publishDate: e.target.value})} />
            </div>
            <DialogFooter>
              <Button type="submit">Create Article</Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      {/* CREATE EVENT DIALOG */}
      <Dialog open={isEventOpen} onOpenChange={setIsEventOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create Event</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleCreateEvent} className="space-y-4">
            <div className="space-y-2">
              <Label>Title</Label>
              <Input required value={eventForm.title} onChange={e => setEventForm({...eventForm, title: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Date & Time</Label>
              <Input required type="datetime-local" value={eventForm.eventDate} onChange={e => setEventForm({...eventForm, eventDate: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Location</Label>
              <Input value={eventForm.location} onChange={e => setEventForm({...eventForm, location: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Category</Label>
              <Select value={eventForm.category} onValueChange={val => setEventForm({...eventForm, category: val})}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="academic">Academic</SelectItem>
                  <SelectItem value="sports">Sports</SelectItem>
                  <SelectItem value="cultural">Cultural</SelectItem>
                </SelectContent>
              </Select>
            </div>
             <div className="space-y-2">
              <Label>Description</Label>
              <Textarea value={eventForm.description} onChange={e => setEventForm({...eventForm, description: e.target.value})} />
            </div>
            <DialogFooter>
              <Button type="submit">Create Event</Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { AdminHeader } from './shared/AdminHeader';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Plus, DollarSign, Wallet, AlertCircle } from 'lucide-react';
import { useToast } from '@/components/ui/use-toast';
import { format } from 'date-fns';
import { getAllStudents } from '@/services/adminService';

export function FinanceManagement() {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState('overview');
  const [stats, setStats] = useState({ totalRevenue: 0, pendingFees: 0, overdueCount: 0 });
  const [payments, setPayments] = useState<any[]>([]);
  const [students, setStudents] = useState<any[]>([]);
  
  const [isPaymentOpen, setIsPaymentOpen] = useState(false);
  const [paymentForm, setPaymentForm] = useState({
    studentId: '',
    amount: '',
    paidAmount: '',
    feeType: 'TUITION',
    dueDate: '',
    paymentMethod: 'CASH',
    notes: ''
  });

  const fetchData = async () => {
    try {
      // Fetch Stats
      const statsRes = await fetch('/api/admin/finance/stats');
      const statsData = await statsRes.json();
      if (statsData.success) {
        setStats(statsData.data);
      }

      // Fetch Payments
      const paymentsRes = await fetch('/api/admin/finance/payments');
      const paymentsData = await paymentsRes.json();
      if (paymentsData.success) {
        setPayments(paymentsData.data.data);
      }
    } catch (error) {
      console.error('Failed to fetch finance data', error);
    }
  };

  const fetchStudents = async () => {
    try {
      const data = await getAllStudents();
      setStudents(data.data || []);
    } catch (e) { console.error('Error fetching students', e); }
  }

  useEffect(() => {
    fetchData();
    fetchStudents();
  }, []);

  const handleRecordPayment = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch('/api/admin/finance/payments', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(paymentForm)
      });
      const data = await res.json();
      
      if (data.success) {
        toast({ title: 'Success', description: 'Payment recorded successfully' });
        setIsPaymentOpen(false);
        fetchData(); // Refresh data
        // Reset form slightly
        setPaymentForm({...paymentForm, amount: '', paidAmount: '', notes: ''});
      } else {
        toast({ title: 'Error', description: data.message || 'Failed to record', variant: 'destructive' });
      }
    } catch (error) {
      toast({ title: 'Error', description: 'Exception occurred', variant: 'destructive' });
    }
  };

  return (
    <div className="space-y-6">
      <AdminHeader
        title="Finance Management"
        description="Track fees, revenue, and pending payments"
        action={
          <Button onClick={() => setIsPaymentOpen(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Record Payment
          </Button>
        }
      />

      <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
        <div className="p-4 bg-white rounded-lg border shadow-sm flex items-center space-x-4">
          <div className="p-2 bg-green-100 rounded-full text-green-600">
            <DollarSign className="h-6 w-6" />
          </div>
          <div>
            <p className="text-sm text-gray-500">Total Revenue</p>
            <h3 className="text-2xl font-bold">${stats.totalRevenue.toLocaleString()}</h3>
          </div>
        </div>
        
        <div className="p-4 bg-white rounded-lg border shadow-sm flex items-center space-x-4">
          <div className="p-2 bg-yellow-100 rounded-full text-yellow-600">
            <Wallet className="h-6 w-6" />
          </div>
          <div>
            <p className="text-sm text-gray-500">Pending Fees</p>
            <h3 className="text-2xl font-bold">${stats.pendingFees.toLocaleString()}</h3>
          </div>
        </div>

        <div className="p-4 bg-white rounded-lg border shadow-sm flex items-center space-x-4">
          <div className="p-2 bg-red-100 rounded-full text-red-600">
            <AlertCircle className="h-6 w-6" />
          </div>
          <div>
            <p className="text-sm text-gray-500">Overdue Payments</p>
            <h3 className="text-2xl font-bold">{stats.overdueCount}</h3>
          </div>
        </div>
      </div>

      <Tabs defaultValue="overview" value={activeTab} onValueChange={setActiveTab}>
        <TabsList>
          <TabsTrigger value="overview">Recent Transactions</TabsTrigger>
          {/* Add Reports Tab later if needed */}
        </TabsList>

        <TabsContent value="overview" className="mt-4">
           <div className="bg-white rounded-lg border shadow-sm">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Student</TableHead>
                  <TableHead>Fee Type</TableHead>
                  <TableHead>Amount</TableHead>
                  <TableHead>Paid</TableHead>
                  <TableHead>Balance</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Due Date</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {payments.length === 0 ? (
                  <TableRow><TableCell colSpan={7} className="text-center py-8">No transactions found</TableCell></TableRow>
                ) : (
                  payments.map((p: any) => (
                    <TableRow key={p.id}>
                      <TableCell>
                        <div className="font-medium">{p.studentName}</div>
                        <div className="text-xs text-muted-foreground">{p.studentId}</div>
                      </TableCell>
                      <TableCell>{p.feeType}</TableCell>
                      <TableCell>${p.amount}</TableCell>
                      <TableCell className="text-green-600">+${p.paidAmount}</TableCell>
                      <TableCell className="text-red-600">${p.balance}</TableCell>
                      <TableCell>
                         <Badge variant={p.status === 'PAID' ? 'default' : p.status === 'PENDING' ? 'destructive' : 'secondary'}>
                           {p.status}
                         </Badge>
                      </TableCell>
                      <TableCell>
                        {p.dueDate ? format(new Date(p.dueDate), 'MMM d, yyyy') : '-'}
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </TabsContent>
      </Tabs>

      {/* RECORD PAYMENT DIALOG */}
      <Dialog open={isPaymentOpen} onOpenChange={setIsPaymentOpen}>
        <DialogContent className="sm:max-w-[425px]">
          <DialogHeader>
            <DialogTitle>Record Fee Payment</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleRecordPayment} className="space-y-4">
            <div className="space-y-2">
              <Label>Student</Label>
              <Select value={paymentForm.studentId} onValueChange={val => setPaymentForm({...paymentForm, studentId: val})}>
                <SelectTrigger><SelectValue placeholder="Select Student" /></SelectTrigger>
                <SelectContent>
                  {students.map((s: any) => (
                    <SelectItem key={s.id} value={s.id}>{s.firstName} {s.lastName} ({s.studentId || s.id.substring(0,8)})</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Total Amount</Label>
                <Input type="number" required value={paymentForm.amount} onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})} placeholder="0.00" />
              </div>
              <div className="space-y-2">
                 <Label>Paid Now</Label>
                 <Input type="number" value={paymentForm.paidAmount} onChange={e => setPaymentForm({...paymentForm, paidAmount: e.target.value})} placeholder="0.00" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-2">
                <Label>Fee Type</Label>
                 <Select value={paymentForm.feeType} onValueChange={val => setPaymentForm({...paymentForm, feeType: val})}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="TUITION">Tuition</SelectItem>
                    <SelectItem value="LIBRARY">Library</SelectItem>
                    <SelectItem value="TRANSPORT">Transport</SelectItem>
                    <SelectItem value="OTHER">Other</SelectItem>
                  </SelectContent>
                </Select>
               </div>
               <div className="space-y-2">
                  <Label>Payment Method</Label>
                   <Select value={paymentForm.paymentMethod} onValueChange={val => setPaymentForm({...paymentForm, paymentMethod: val})}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="CASH">Cash</SelectItem>
                      <SelectItem value="CARD">Card</SelectItem>
                      <SelectItem value="TRANSFER">Transfer</SelectItem>
                    </SelectContent>
                  </Select>
               </div>
            </div>

            <div className="space-y-2">
              <Label>Due Date</Label>
              <Input type="date" required value={paymentForm.dueDate} onChange={e => setPaymentForm({...paymentForm, dueDate: e.target.value})} />
            </div>

            <DialogFooter>
              <Button type="submit">Record Payment</Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

// NotificationCenter Component - Real-time notifications dropdown
import { useState, useEffect } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { 
  Bell, 
  CheckCheck, 
  Trash2, 
  UserPlus, 
  AlertCircle, 
  DollarSign, 
  FileText,
  GraduationCap,
  X
} from 'lucide-react';

interface Notification {
  id: string;
  type: 'info' | 'success' | 'warning' | 'error';
  title: string;
  message: string;
  timestamp: Date;
  read: boolean;
}

interface NotificationCenterProps {
  onClose: () => void;
  onClearUnread: () => void;
}

const mockNotifications: Notification[] = [
  {
    id: '1',
    type: 'success',
    title: 'New Student Registered',
    message: 'John Doe has successfully registered for Grade 10',
    timestamp: new Date(Date.now() - 1000 * 60 * 5),
    read: false,
  },
  {
    id: '2',
    type: 'warning',
    title: 'Payment Overdue',
    message: '5 students have overdue fee payments',
    timestamp: new Date(Date.now() - 1000 * 60 * 30),
    read: false,
  },
  {
    id: '3',
    type: 'info',
    title: 'Report Generated',
    message: 'Monthly attendance report is ready',
    timestamp: new Date(Date.now() - 1000 * 60 * 60),
    read: false,
  },
  {
    id: '4',
    type: 'error',
    title: 'System Alert',
    message: 'Database backup failed - please retry',
    timestamp: new Date(Date.now() - 1000 * 60 * 120),
    read: true,
  },
  {
    id: '5',
    type: 'success',
    title: 'Assignment Submitted',
    message: '25 students submitted their homework',
    timestamp: new Date(Date.now() - 1000 * 60 * 180),
    read: true,
  },
];

export function NotificationCenter({ onClose, onClearUnread }: NotificationCenterProps) {
  const [notifications, setNotifications] = useState<Notification[]>(mockNotifications);
  const [filter, setFilter] = useState<'all' | 'unread'>('all');

  const getIcon = (type: string) => {
    switch (type) {
      case 'success':
        return <GraduationCap className="h-5 w-5 text-green-500" />;
      case 'warning':
        return <DollarSign className="h-5 w-5 text-yellow-500" />;
      case 'error':
        return <AlertCircle className="h-5 w-5 text-red-500" />;
      default:
        return <FileText className="h-5 w-5 text-blue-500" />;
    }
  };

  const formatTimestamp = (date: Date) => {
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (minutes < 1) return 'Just now';
    if (minutes < 60) return `${minutes}m ago`;
    if (hours < 24) return `${hours}h ago`;
    return `${days}d ago`;
  };

  const markAsRead = (id: string) => {
    setNotifications(prev =>
      prev.map(notif =>
        notif.id === id ? { ...notif, read: true } : notif
      )
    );
  };

  const markAllAsRead = () => {
    setNotifications(prev =>
      prev.map(notif => ({ ...notif, read: true }))
    );
    onClearUnread();
  };

  const deleteNotification = (id: string) => {
    setNotifications(prev => prev.filter(notif => notif.id !== id));
  };

  const filteredNotifications = filter === 'unread' 
    ? notifications.filter(n => !n.read)
    : notifications;

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <Card className="absolute right-0 top-12 w-96 shadow-lg border-2 z-50 max-h-[600px] flex flex-col">
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b">
        <div className="flex items-center gap-2">
          <Bell className="h-5 w-5" />
          <h3 className="font-semibold">Notifications</h3>
          {unreadCount > 0 && (
            <Badge variant="destructive" className="ml-1">{unreadCount}</Badge>
          )}
        </div>
        <Button variant="ghost" size="sm" onClick={onClose}>
          <X className="h-4 w-4" />
        </Button>
      </div>

      {/* Filter Tabs */}
      <div className="flex items-center gap-2 px-4 py-2 border-b bg-gray-50">
        <Button
          variant={filter === 'all' ? 'default' : 'ghost'}
          size="sm"
          onClick={() => setFilter('all')}
        >
          All ({notifications.length})
        </Button>
        <Button
          variant={filter === 'unread' ? 'default' : 'ghost'}
          size="sm"
          onClick={() => setFilter('unread')}
        >
          Unread ({unreadCount})
        </Button>
        {unreadCount > 0 && (
          <Button
            variant="ghost"
            size="sm"
            onClick={markAllAsRead}
            className="ml-auto text-xs"
          >
            <CheckCheck className="h-3 w-3 mr-1" />
            Mark all read
          </Button>
        )}
      </div>

      {/* Notifications List */}
      <ScrollArea className="flex-1">
        <div className="divide-y">
          {filteredNotifications.length > 0 ? (
            filteredNotifications.map(notification => (
              <div
                key={notification.id}
                className={`p-4 hover:bg-gray-50 transition-colors cursor-pointer ${
                  !notification.read ? 'bg-blue-50' : ''
                }`}
                onClick={() => markAsRead(notification.id)}
              >
                <div className="flex items-start gap-3">
                  <div className="mt-0.5">{getIcon(notification.type)}</div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-2">
                      <p className="font-medium text-sm text-gray-900 truncate">
                        {notification.title}
                      </p>
                      {!notification.read && (
                        <div className="h-2 w-2 bg-blue-500 rounded-full flex-shrink-0 mt-1" />
                      )}
                    </div>
                    <p className="text-xs text-gray-600 mt-1 line-clamp-2">
                      {notification.message}
                    </p>
                    <div className="flex items-center justify-between mt-2">
                      <span className="text-xs text-gray-500">
                        {formatTimestamp(notification.timestamp)}
                      </span>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={(e) => {
                          e.stopPropagation();
                          deleteNotification(notification.id);
                        }}
                        className="h-6 w-6 p-0"
                      >
                        <Trash2 className="h-3 w-3 text-gray-400" />
                      </Button>
                    </div>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="p-8 text-center text-gray-500">
              <Bell className="h-12 w-12 mx-auto mb-2 opacity-20" />
              <p className="text-sm">No notifications</p>
            </div>
          )}
        </div>
      </ScrollArea>

      {/* Footer */}
      {notifications.length > 0 && (
        <div className="p-3 border-t bg-gray-50">
          <Button variant="ghost" size="sm" className="w-full text-xs">
            View All Notifications
          </Button>
        </div>
      )}
    </Card>
  );
}

// Overview Component - Dashboard with statistics and charts
import { useEffect, useState } from 'react';
import { StatsCard } from './shared/StatsCard';
import { AdminHeader } from './shared/AdminHeader';
import { Users, GraduationCap, DollarSign, FileText, TrendingUp, Clock, PieChart as PieChartIcon, Send, FileDown, Database, Mail, BarChart3 } from 'lucide-react';
import { getDashboardStats, getEnrollmentData, getRevenueData, getActivityLogs } from '@/services/adminService';
import type { DashboardStats, EnrollmentData, RevenueData, ActivityLog } from '@/types/admin';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { LineChart, Line, BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { useToast } from '@/hooks/use-toast';
import { enrollmentMarch2021, enrollmentSummary } from '@/lib/data/seed-data-enrollment';
import { staffStats } from '@/lib/data/seed-data-staff';
import { feeBreakdown2021 } from '@/lib/data/seed-data-financial';

export function Overview() {
  const { toast } = useToast();
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [enrollmentData, setEnrollmentData] = useState<EnrollmentData[]>([]);
  const [revenueData, setRevenueData] = useState<RevenueData[]>([]);
  const [activityLogs, setActivityLogs] = useState<ActivityLog[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadDashboardData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const loadDashboardData = async () => {
    try {
      setLoading(true);
      const [statsData, enrollData, revData, logsData] = await Promise.all([
        getDashboardStats(),
        getEnrollmentData(new Date().getFullYear()),
        getRevenueData(new Date().getFullYear()),
        getActivityLogs(10),
      ]);

      setStats(statsData);
      setEnrollmentData(enrollData);
      setRevenueData(revData);
      setActivityLogs(logsData);
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to load dashboard data',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  // Real enrollment data from March-April 2021
  const gradeDistribution = enrollmentMarch2021
    .filter(record => record.currentTotal > 0)
    .map((record, index) => ({
      name: record.grade,
      value: record.currentTotal,
      fill: ['#1C1A75', '#2D2B8F', '#3D3BAF', '#10B981', '#059669', '#F59E0B', '#EF4444', '#DC2626', '#7C3AED', '#6366F1', '#8B5CF6', '#A78BFA'][index % 12],
    }));

  // Staff distribution by department (real 2021 data)
  const staffDistribution = [
    { department: 'Administration', count: staffStats.departments.administration, fill: '#1C1A75' },
    { department: 'ECD', count: staffStats.departments.ecd, fill: '#10B981' },
    { department: 'Primary', count: staffStats.departments.primary, fill: '#F59E0B' },
    { department: 'ICT', count: staffStats.departments.ict, fill: '#EF4444' },
  ];

  // Fee structure breakdown (real 2021 data)
  const feeBreakdownChart = [
    { category: 'ECD Total', amount: feeBreakdown2021.ecd.total, fill: '#1C1A75' },
    { category: 'Primary Total', amount: feeBreakdown2021.primary.total, fill: '#10B981' },
    { category: 'Boarding', amount: feeBreakdown2021.boarding.newFee, fill: '#F59E0B' },
  ];

  // Enrollment growth data (March-April 2021)
  const enrollmentGrowth = [
    { period: 'March 15', students: enrollmentSummary.opening.total, male: enrollmentSummary.opening.male, female: enrollmentSummary.opening.female },
    { period: 'April 21', students: enrollmentSummary.current.total, male: enrollmentSummary.current.male, female: enrollmentSummary.current.female },
  ];

  const handleQuickAction = (action: string) => {
    toast({
      title: 'Quick Action',
      description: `${action} - Feature coming soon!`,
    });
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-[#1C1A75] mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <AdminHeader
        title="Dashboard Overview"
        description="Welcome back! Here's what's happening with your school."
      />

      {/* Stats Grid - Real 2021 Data */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatsCard
          title="Total Students"
          value={enrollmentSummary.current.total}
          description="April 21, 2021"
          icon={GraduationCap}
          trend={{ value: enrollmentSummary.growth.percentage, isPositive: true }}
        />
        <StatsCard
          title="Total Staff"
          value={staffStats.totalStaff}
          description="14 qualified teachers"
          icon={Users}
        />
        <StatsCard
          title="ECD Students"
          value={enrollmentMarch2021.filter(r => r.grade.includes('ECD')).reduce((sum, r) => sum + r.currentTotal, 0)}
          description={`${((enrollmentMarch2021.filter(r => r.grade.includes('ECD')).reduce((sum, r) => sum + r.currentTotal, 0) / enrollmentSummary.current.total) * 100).toFixed(0)}% of total`}
          icon={GraduationCap}
        />
        <StatsCard
          title="Primary Students"
          value={enrollmentMarch2021.filter(r => r.grade.includes('Grade')).reduce((sum, r) => sum + r.currentTotal, 0)}
          description={`${((enrollmentMarch2021.filter(r => r.grade.includes('Grade')).reduce((sum, r) => sum + r.currentTotal, 0) / enrollmentSummary.current.total) * 100).toFixed(0)}% of total`}
          icon={FileText}
        />
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Enrollment Growth (March-April 2021) */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <TrendingUp className="h-5 w-5" />
              Enrollment Growth (March-April 2021)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={enrollmentGrowth}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="period" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="male" fill="#1C1A75" name="Male" stackId="a" />
                <Bar dataKey="female" fill="#10B981" name="Female" stackId="a" />
              </BarChart>
            </ResponsiveContainer>
            <div className="mt-4 text-center text-sm text-gray-600">
              <p className="font-semibold text-green-600">+{enrollmentSummary.growth.absolute} students (+{enrollmentSummary.growth.percentage.toFixed(1)}%)</p>
              <p className="text-xs mt-1">Total: {enrollmentSummary.current.total} students</p>
            </div>
          </CardContent>
        </Card>

        {/* Revenue Chart */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <DollarSign className="h-5 w-5" />
              Monthly Revenue
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={revenueData}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="amount" fill="#10B981" name="Revenue ($)" />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      </div>

      {/* New Enhanced Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Grade Distribution Pie Chart */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <PieChartIcon className="h-5 w-5" />
              Student Distribution by Grade
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={250}>
              <PieChart>
                <Pie
                  data={gradeDistribution}
                  cx="50%"
                  cy="50%"
                  labelLine={false}
                  label={({ name, percent }) => `${name}: ${(percent * 100).toFixed(0)}%`}
                  outerRadius={80}
                  dataKey="value"
                >
                  {gradeDistribution.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.fill} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Staff Distribution Chart */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <BarChart3 className="h-5 w-5" />
              Staff by Department (2021)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={250}>
              <BarChart data={staffDistribution}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="department" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="count" fill="#1C1A75" name="Staff Count" />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Fee Structure Breakdown Chart */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <DollarSign className="h-5 w-5" />
              Fee Structure 2021 (USD)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={250}>
              <PieChart>
                <Pie
                  data={feeBreakdownChart}
                  cx="50%"
                  cy="50%"
                  labelLine={false}
                  label={({ category, amount }) => `${category}: $${amount}`}
                  outerRadius={80}
                  dataKey="amount"
                >
                  {feeBreakdownChart.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.fill} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      </div>

      {/* Quick Actions Widget */}
      <Card>
        <CardHeader>
          <CardTitle>Quick Actions</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
            <Button 
              variant="outline" 
              className="h-20 flex flex-col gap-2"
              onClick={() => handleQuickAction('Send Announcement')}
            >
              <Send className="h-5 w-5" />
              <span className="text-xs">Send Announcement</span>
