                No recent activity to display
              </p>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

'use client'

import { useState } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group'
import { useToast } from '@/components/ui/use-toast'
import { Loader2, Copy } from 'lucide-react'

interface GeneratedResult {
    registrationNumbers?: string[]
    registrationNumber?: string
}

export function RegistrationGenerator({ onGenerate }: { onGenerate: () => void }) {
  const { toast } = useToast()
  const [loading, setLoading] = useState(false)
  const [role, setRole] = useState<'student' | 'teacher'>('student')
  const [count, setCount] = useState(1)
  const [lastGenerated, setLastGenerated] = useState<string[]>([])

  const handleGenerate = async () => {
    setLoading(true)
    try {
      const res = await fetch('/api/admin/registration-numbers', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          role,
          count: Math.max(1, Math.min(100, count))
        })
      })

      const data = await res.json()
      
      if (data.success) {
        const numbers = data.data.registrationNumber 
            ? [data.data.registrationNumber] 
            : data.data.registrationNumbers || []
            
        setLastGenerated(numbers)
        onGenerate() // Refresh stats
        toast({
          title: 'Success',
          description: `Generated ${numbers.length} registration number(s)`
        })
      } else {
        throw new Error(data.message)
      }
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to generate numbers',
        variant: 'destructive'
      })
    } finally {
      setLoading(false)
    }
  }

  const copyToClipboard = () => {
    if (lastGenerated.length === 0) return
    const text = lastGenerated.join('\n')
    navigator.clipboard.writeText(text)
    toast({ title: 'Copied', description: 'Numbers copied to clipboard' })
  }

  return (
    <div className="grid md:grid-cols-2 gap-6">
      <Card>
        <CardHeader>
          <CardTitle>Generate Numbers</CardTitle>
          <CardDescription>Create new unique registration IDs for students or staff.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="space-y-3">
            <Label>Role Type</Label>
            <RadioGroup defaultValue="student" onValueChange={(v) => setRole(v as any)} className="flex gap-4">
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="student" id="r-student" />
                <Label htmlFor="r-student">Student (RS)</Label>
              </div>
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="teacher" id="r-teacher" />
                <Label htmlFor="r-teacher">Teacher (RT)</Label>
              </div>
            </RadioGroup>
          </div>

          <div className="space-y-3">
            <Label>Quantity</Label>
            <div className="flex gap-4 items-center">
                <Input 
                    type="number" 
                    min={1} 
                    max={100} 
                    value={count} 
                    onChange={(e) => setCount(parseInt(e.target.value) || 1)}
                    className="w-32"
                />
                <span className="text-sm text-muted-foreground">Max 100 at a time</span>
            </div>
          </div>

          <Button onClick={handleGenerate} disabled={loading} className="w-full">
            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            Generate {role === 'student' ? 'Student' : 'Teacher'} ID{count > 1 ? 's' : ''}
          </Button>
        </CardContent>
      </Card>

      <Card className="h-full">
        <CardHeader>
          <CardTitle className="flex justify-between items-center">
            Recent Output
            {lastGenerated.length > 0 && (
                <Button variant="ghost" size="sm" onClick={copyToClipboard}>
                    <Copy className="h-4 w-4 mr-2" />
                    Copy
                </Button>
            )}
          </CardTitle>
          <CardDescription>Recently generated numbers will appear here.</CardDescription>
        </CardHeader>
        <CardContent>
          {lastGenerated.length > 0 ? (
            <div className="bg-muted p-4 rounded-lg max-h-[300px] overflow-y-auto font-mono text-sm">
                {lastGenerated.map((num, i) => (
                    <div key={i} className="py-1 border-b last:border-0 border-gray-200 dark:border-gray-700">
                        {num}
                    </div>
                ))}
            </div>
          ) : (
            <div className="h-40 flex items-center justify-center text-muted-foreground bg-muted/30 rounded-lg border border-dashed">
                Only new numbers show here
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

'use client';

import { useState, useEffect } from 'react';
import { AdminHeader } from './shared/AdminHeader';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Download, Users, TrendingUp, DollarSign, GraduationCap, BarChart as BarChartIcon } from 'lucide-react';
import { useToast } from '@/components/ui/use-toast';

export function ReportsAnalytics() {
  const { toast } = useToast();
  const [stats, setStats] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch('/api/admin/reports/stats');
        const data = await res.json();
        if (data.success) {
          setStats(data.data);
        }
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  if (loading) {
     return <div className="p-8 text-center">Loading analytics...</div>;
  }

  if (!stats) {
     return <div className="p-8 text-center">Failed to load analytics.</div>;
  }

  return (
    <div className="space-y-6">
      <AdminHeader
        title="Reports & Analytics"
        description="Comprehensive view of school performance"
        action={
          <Button variant="outline">
            <Download className="h-4 w-4 mr-2" />
            Export Report
          </Button>
        }
      />

      {/* Top Level Metrics */}
      <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Students</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.students.total}</div>
            <p className="text-xs text-muted-foreground">Across all grades</p>
          </CardContent>
        </Card>
        
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Teaching Staff</CardTitle>
            <GraduationCap className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.staff.teachers}</div>
            <p className="text-xs text-muted-foreground">Active teachers</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Attendance Rate</CardTitle>
            <TrendingUp className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.attendance.rate}%</div>
            <p className="text-xs text-muted-foreground">Today's average</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Revenue</CardTitle>
            <DollarSign className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">${stats.finance.revenue.toLocaleString()}</div>
            <p className="text-xs text-muted-foreground">Pending: ${stats.finance.pending.toLocaleString()}</p>
          </CardContent>
        </Card>
      </div>

      {/* Student Distribution Chart (Simple Bar Visualization) */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Card className="col-span-1">
            <CardHeader>
              <CardTitle>Student Distribution</CardTitle>
              <CardDescription>Number of students per grade</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {stats.students.byGrade.map((g: any) => {
                    const percentage = stats.students.total > 0 ? (g.count / stats.students.total) * 100 : 0;
                    return (
                        <div key={g.grade} className="space-y-1">
                            <div className="flex items-center justify-between text-sm">
                                <span className="font-medium">Grade {g.grade}</span>
                                <span className="text-muted-foreground">{g.count} students</span>
                            </div>
                            <div className="h-2 w-full bg-secondary rounded-full overflow-hidden">
                                <div className="h-full bg-primary" style={{ width: `${percentage}%` }} />
                            </div>
                        </div>
                    );
                })}
                {stats.students.byGrade.length === 0 && <p className="text-sm text-gray-500">No student data available.</p>}
              </div>
            </CardContent>
          </Card>

          <Card className="col-span-1">
              <CardHeader>
                  <CardTitle>Attendance Breakdown</CardTitle>
                  <CardDescription>Today's status distribution</CardDescription>
              </CardHeader>
              <CardContent>
                  <div className="space-y-4">
                      {['present', 'absent', 'late', 'excused'].map((status) => {
                          const count = stats.attendance.breakdown.find((b: any) => b.status === status)?.count || 0;
                          const totalMarked = stats.attendance.breakdown.reduce((acc: any, curr: any) => acc + curr.count, 0);
                          const percentage = totalMarked > 0 ? (count / totalMarked) * 100 : 0;
                          
                          let colorClass = 'bg-gray-500';
                          if (status === 'present') colorClass = 'bg-green-500';
                          if (status === 'absent') colorClass = 'bg-red-500';
                          if (status === 'late') colorClass = 'bg-yellow-500';
                          if (status === 'excused') colorClass = 'bg-blue-500';

                          return (
                              <div key={status} className="space-y-1">
                                  <div className="flex items-center justify-between text-sm capitalize">
                                      <span className="font-medium">{status}</span>
                                      <span className="text-muted-foreground">{count}</span>
                                  </div>
                                  <div className="h-2 w-full bg-secondary rounded-full overflow-hidden">
                                      <div className={`h-full ${colorClass}`} style={{ width: `${percentage}%` }} />
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              </CardContent>
          </Card>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { AdminHeader } from './shared/AdminHeader';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge'; // Check if badge-new or badge
import { Plus, Search, Filter, MoreVertical, Edit, Trash, FileText } from 'lucide-react';
import { getAllStudents, enrollStudent, deleteStudent } from '@/services/adminService';
import { Student, StudentFormData } from '@/types/admin';
import { useToast } from '@/components/ui/use-toast';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';

export function StudentManagement() {
  const { toast } = useToast();
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [isEnrollOpen, setIsEnrollOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [gradeFilter, setGradeFilter] = useState('all');

  // Form State
  const [formData, setFormData] = useState<StudentFormData>({
    firstName: '',
    lastName: '',
    email: '',
    dateOfBirth: '',
    gender: 'male',
    grade: '',
    className: '',
    parentName: '',
    parentEmail: '',
    parentPhone: '',
    parentRelationship: 'Parent',
    address: '',
    phoneNumber: '',
    medicalAllergies: '',
    medicalMedications: '',
  });

  const fetchStudents = async () => {
    setLoading(true);
    try {
      const filters: any = {};
      if (searchTerm) filters.search = searchTerm;
      if (statusFilter !== 'all') filters.status = statusFilter;
      if (gradeFilter !== 'all') filters.grade = gradeFilter;

      const response = await getAllStudents(filters);
      // Backend returns PaginatedResponse<Student>, but for now let's assume it puts data in data.data or just data if we changed it.
      // Checking adminService.ts: return response.data! which is PaginatedResponse<Student>
      // So we need response.data
      setStudents(response.data || []);
    } catch (error) {
      console.error('Failed to fetch students', error);
      toast({
        title: 'Error',
        description: 'Failed to load students. Please try again.',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStudents();
  }, [searchTerm, statusFilter, gradeFilter]);

  const handleEnroll = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await enrollStudent(formData);
      toast({
        title: 'Success',
        description: 'Student enrolled successfully',
      });
      setIsEnrollOpen(false);
      fetchStudents();
      // Reset form
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        dateOfBirth: '',
        gender: 'male',
        grade: '',
        className: '',
        parentName: '',
        parentEmail: '',
        parentPhone: '',
        parentRelationship: 'Parent',
        address: '',
        phoneNumber: '',
        medicalAllergies: '',
        medicalMedications: '',
      });
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error.message || 'Failed to enroll student',
        variant: 'destructive',
      });
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this student? This action cannot be undone.')) return;
    
    try {
      await deleteStudent(id);
      toast({
        title: 'Success',
        description: 'Student deleted successfully',
      });
      fetchStudents();
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to delete student',
        variant: 'destructive',
      });
    }
  };

  return (
    <div className="space-y-6">
      <AdminHeader
        title="Student Management"
        description="Enroll and manage student records, grades, and attendance"
        action={
          <Button onClick={() => setIsEnrollOpen(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Enroll Student
          </Button>
        }
      />
      
      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between items-center bg-white p-4 rounded-lg border shadow-sm">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search students..."
            className="pl-8"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <Select value={gradeFilter} onValueChange={setGradeFilter}>
            <SelectTrigger className="w-[150px]">
              <SelectValue placeholder="Grade" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Grades</SelectItem>
              <SelectItem value="10">Grade 10</SelectItem>
              <SelectItem value="11">Grade 11</SelectItem>
              <SelectItem value="12">Grade 12</SelectItem>
            </SelectContent>
          </Select>
           <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[150px]">
              <SelectValue placeholder="Status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Status</SelectItem>
              <SelectItem value="ACTIVE">Active</SelectItem>
              <SelectItem value="INACTIVE">Inactive</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-lg border shadow-sm overflow-hidden">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Student Info</TableHead>
              <TableHead>Grade/Class</TableHead>
              <TableHead>Roll Number</TableHead>
              <TableHead>Parent Info</TableHead>
              <TableHead>Status</TableHead>
              <TableHead className="text-right">Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {loading ? (
              <TableRow>
                <TableCell colSpan={6} className="text-center py-8">Loading students...</TableCell>
              </TableRow>
            ) : students.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} className="text-center py-8">No students found</TableCell>
              </TableRow>
            ) : (
              students.map((student) => (
                <TableRow key={student.id}>
                  <TableCell>
                    <div>
                      <div className="font-medium">{student.firstName} {student.lastName}</div>
                      <div className="text-sm text-muted-foreground">{student.email}</div>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="font-medium">Grade {student.grade}</div>
                    <div className="text-sm text-muted-foreground">Class {student.className}</div>
                  </TableCell>
                  <TableCell>{student.rollNumber || 'N/A'}</TableCell>
                  <TableCell>
                    <div className="text-sm">
                      <div>{student.parentInfo?.name}</div>
                      <div className="text-muted-foreground">{student.parentInfo?.phone}</div>
                    </div>
                  </TableCell>
                  <TableCell>
                    <Badge variant={student.status === 'ACTIVE' ? 'default' : 'secondary'}>
                      {student.status || 'Active'}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-right">
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="icon">
                          <MoreVertical className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuLabel>Actions</DropdownMenuLabel>
                        <DropdownMenuItem>
                          <FileText className="mr-2 h-4 w-4" /> View Details
                        </DropdownMenuItem>
                        <DropdownMenuItem>
                          <Edit className="mr-2 h-4 w-4" /> Edit Record
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem className="text-red-600" onClick={() => handleDelete(student.id)}>
                          <Trash className="mr-2 h-4 w-4" /> Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Enrollment Dialog */}
      <Dialog open={isEnrollOpen} onOpenChange={setIsEnrollOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Enroll New Student</DialogTitle>
            <DialogDescription>
              Create a new student record and user account.
            </DialogDescription>
          </DialogHeader>
          
          <form onSubmit={handleEnroll} className="space-y-6">
            {/* Student Info */}
            <div className="space-y-4">
              <h3 className="text-sm font-medium border-b pb-2">Student Information</h3>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>First Name</Label>
                  <Input required value={formData.firstName} onChange={(e) => setFormData({...formData, firstName: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <Label>Last Name</Label>
                  <Input required value={formData.lastName} onChange={(e) => setFormData({...formData, lastName: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <Label>Email</Label>
                  <Input required type="email" value={formData.email} onChange={(e) => setFormData({...formData, email: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <Label>Date of Birth</Label>
                  <Input type="date" value={formData.dateOfBirth} onChange={(e) => setFormData({...formData, dateOfBirth: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <Label>Grade</Label>
                  <Select value={formData.grade} onValueChange={(val) => setFormData({...formData, grade: val})}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select Grade" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="10">Grade 10</SelectItem>
                      <SelectItem value="11">Grade 11</SelectItem>
                      <SelectItem value="12">Grade 12</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Class/Section</Label>
                  <Input value={formData.className} onChange={(e) => setFormData({...formData, className: e.target.value})} placeholder="e.g. 10A" />
                </div>
              </div>
            </div>

            {/* Parent Info */}
            <div className="space-y-4">
              <h3 className="text-sm font-medium border-b pb-2">Guardian Information</h3>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Guardian Name</Label>
                  <Input required value={formData.parentName} onChange={(e) => setFormData({...formData, parentName: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <Label>Guardian Email</Label>
                  <Input type="email" value={formData.parentEmail} onChange={(e) => setFormData({...formData, parentEmail: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <Label>Phone Number</Label>
                  <Input required value={formData.parentPhone} onChange={(e) => setFormData({...formData, parentPhone: e.target.value})} />
                </div>
                 <div className="space-y-2">
                  <Label>Relationship</Label>
                  <Select value={formData.parentRelationship} onValueChange={(val) => setFormData({...formData, parentRelationship: val})}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select Relationship" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Parent">Parent</SelectItem>
                      <SelectItem value="Guardian">Guardian</SelectItem>
                      <SelectItem value="Other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </div>

            {/* Medical Info */}
             <div className="space-y-4">
              <h3 className="text-sm font-medium border-b pb-2">Medical Information (Optional)</h3>
              <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-2">
                  <Label>Allergies</Label>
                  <Input value={formData.medicalAllergies} onChange={(e) => setFormData({...formData, medicalAllergies: e.target.value})} />
                </div>
                 <div className="space-y-2">
                  <Label>Medications</Label>
                  <Input value={formData.medicalMedications} onChange={(e) => setFormData({...formData, medicalMedications: e.target.value})} />
                </div>
              </div>
            </div>

            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => setIsEnrollOpen(false)}>Cancel</Button>
              <Button type="submit">Enroll Student</Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

// SystemSettings Component - Configure system-wide settings
'use client';
import { useState, useEffect } from 'react';
import { AdminHeader } from './shared/AdminHeader';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Textarea } from '@/components/ui/textarea';
import { Separator } from '@/components/ui/separator';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { 
  Mail, 
  MessageSquare, 
  Bell, 
  Database, 
  Shield, 
  Globe, 
  Save,
  Download,
  Upload,
  RefreshCw,
  AlertCircle
} from 'lucide-react';
import { useToast } from '@/components/ui/use-toast';

interface Settings {
  emailEnabled: boolean;
  smtpServer: string;
  smtpPort: string;
  smtpUsername: string;
  smtpPassword: string;
  emailFromAddress: string;
  emailFromName: string;

  smsEnabled: boolean;
  smsProvider: string;
  smsApiKey: string;
  smsFromNumber: string;

  enableEmailNotifications: boolean;
  enableSMSNotifications: boolean;
  enablePushNotifications: boolean;
  notifyOnNewRegistration: boolean;
  notifyOnPayment: boolean;
  notifyOnAttendance: boolean;

  schoolName: string;
  schoolEmail: string;
  schoolPhone: string;
  schoolAddress: string;
  academicYear: string;
  currency: string;
  timezone: string;
  dateFormat: string;

  enableTwoFactor: boolean;
  sessionTimeout: number;
  passwordMinLength: number;
  passwordRequireSpecialChar: boolean;
  maxLoginAttempts: number;

  autoBackupEnabled: boolean;
  backupFrequency: string;
  backupTime: string;
  backupRetentionDays: number;
}

const defaultSettings: Settings = {
  emailEnabled: true,
  smtpServer: '',
  smtpPort: '',
  smtpUsername: '',
  smtpPassword: '',
  emailFromAddress: '',
  emailFromName: '',
  smsEnabled: false,
  smsProvider: 'twilio',
  smsApiKey: '',
  smsFromNumber: '',
  enableEmailNotifications: true,
  enableSMSNotifications: false,
  enablePushNotifications: true,
  notifyOnNewRegistration: true,
  notifyOnPayment: true,
  notifyOnAttendance: false,
  schoolName: '',
  schoolEmail: '',
  schoolPhone: '',
  schoolAddress: '',
  academicYear: '',
  currency: 'USD',
  timezone: 'Africa/Harare',
  dateFormat: 'DD/MM/YYYY',
  enableTwoFactor: false,
  sessionTimeout: 60,
  passwordMinLength: 8,
  passwordRequireSpecialChar: true,
  maxLoginAttempts: 5,
  autoBackupEnabled: true,
  backupFrequency: 'daily',
  backupTime: '02:00',
  backupRetentionDays: 30,
};

export function SystemSettings() {
  const { toast } = useToast();
  const [settings, setSettings] = useState<Settings>(defaultSettings);
  const [loading, setLoading] = useState(false);
  const [backupInProgress, setBackupInProgress] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      const res = await fetch('/api/admin/settings');
      const data = await res.json();
      if (data.success) {
        setSettings(data.settings);
      }
    } catch (error) {
      console.error(error);
      toast({ title: 'Error', description: 'Failed to load settings', variant: 'destructive' });
    }
  };

  const updateSetting = (key: keyof Settings, value: any) => {
    setSettings(prev => ({ ...prev, [key]: value }));
  };

  const handleSave = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/admin/settings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(settings)
      });
      const data = await res.json();
      if (data.success) {
        toast({
            title: 'Settings Saved',
            description: 'Your settings have been updated successfully',
        });
      } else {
        toast({ title: 'Error', description: 'Failed to save', variant: 'destructive' });
      }
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to save settings',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const handleBackupNow = async () => {
    setBackupInProgress(true);
    try {
      // Simulation of backup process
      await new Promise(resolve => setTimeout(resolve, 2000));
      toast({
        title: 'Backup Complete',
        description: 'Database backup created successfully',
      });
    } catch (error) {
      toast({
        title: 'Backup Failed',
        description: 'Failed to create database backup',
        variant: 'destructive',
      });
    } finally {
      setBackupInProgress(false);
    }
  };

  const handleRestoreBackup = () => {
    toast({
      title: 'Restore Initiated',
      description: 'Please select a backup file to restore',
    });
  };

  return (
    <div className="space-y-6">
      <AdminHeader
        title="System Settings"
        description="Configure system-wide settings and preferences"
      />

      <Tabs defaultValue="general" className="space-y-6">
        <TabsList className="grid grid-cols-2 md:grid-cols-5 gap-2">
          <TabsTrigger value="general">
            <Globe className="h-4 w-4 mr-2" />
            General
          </TabsTrigger>
          <TabsTrigger value="email">
            <Mail className="h-4 w-4 mr-2" />
            Email
          </TabsTrigger>
          <TabsTrigger value="notifications">
            <Bell className="h-4 w-4 mr-2" />
            Notifications
          </TabsTrigger>
          <TabsTrigger value="security">
            <Shield className="h-4 w-4 mr-2" />
            Security
          </TabsTrigger>
          <TabsTrigger value="backup">
            <Database className="h-4 w-4 mr-2" />
            Backup
          </TabsTrigger>
        </TabsList>

        {/* General Settings */}
        <TabsContent value="general" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>School Information</CardTitle>
              <CardDescription>Basic information about your school</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="schoolName">School Name</Label>
                  <Input
                    id="schoolName"
                    value={settings.schoolName}
                    onChange={(e) => updateSetting('schoolName', e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="academicYear">Academic Year</Label>
                  <Input
                    id="academicYear"
                    value={settings.academicYear}
                    onChange={(e) => updateSetting('academicYear', e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="schoolEmail">School Email</Label>
                  <Input
                    id="schoolEmail"
                    type="email"
                    value={settings.schoolEmail}
                    onChange={(e) => updateSetting('schoolEmail', e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="schoolPhone">School Phone</Label>
                  <Input
                    id="schoolPhone"
                    value={settings.schoolPhone}
                    onChange={(e) => updateSetting('schoolPhone', e.target.value)}
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="schoolAddress">School Address</Label>
                <Textarea
                  id="schoolAddress"
                  value={settings.schoolAddress}
                  onChange={(e) => updateSetting('schoolAddress', e.target.value)}
                  rows={3}
                />
              </div>
              <Separator />
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="currency">Currency</Label>
                  <Select value={settings.currency} onValueChange={(value) => updateSetting('currency', value)}>
                    <SelectTrigger id="currency">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="USD">USD ($)</SelectItem>
                      <SelectItem value="ZWL">ZWL (Z$)</SelectItem>
                      <SelectItem value="ZAR">ZAR (R)</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="timezone">Timezone</Label>
                  <Select value={settings.timezone} onValueChange={(value) => updateSetting('timezone', value)}>
                    <SelectTrigger id="timezone">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Africa/Harare">Africa/Harare (CAT)</SelectItem>
                      <SelectItem value="Africa/Johannesburg">Africa/Johannesburg (SAST)</SelectItem>
                      <SelectItem value="UTC">UTC</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="dateFormat">Date Format</Label>
                  <Select value={settings.dateFormat} onValueChange={(value) => updateSetting('dateFormat', value)}>
                    <SelectTrigger id="dateFormat">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="DD/MM/YYYY">DD/MM/YYYY</SelectItem>
                      <SelectItem value="MM/DD/YYYY">MM/DD/YYYY</SelectItem>
                      <SelectItem value="YYYY-MM-DD">YYYY-MM-DD</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Email Settings */}
        <TabsContent value="email" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Email Configuration</CardTitle>
              <CardDescription>Configure SMTP settings for sending emails</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="emailEnabled">Enable Email Service</Label>
                  <p className="text-sm text-gray-500">Allow system to send emails</p>
                </div>
                <Switch
                  id="emailEnabled"
                  checked={settings.emailEnabled}
                  onCheckedChange={(checked) => updateSetting('emailEnabled', checked)}
                />
              </div>
              <Separator />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="smtpServer">SMTP Server</Label>
                  <Input
                    id="smtpServer"
                    value={settings.smtpServer}
                    onChange={(e) => updateSetting('smtpServer', e.target.value)}
                    disabled={!settings.emailEnabled}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="smtpPort">SMTP Port</Label>
                  <Input
                    id="smtpPort"
                    value={settings.smtpPort}
                    onChange={(e) => updateSetting('smtpPort', e.target.value)}
                    disabled={!settings.emailEnabled}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="smtpUsername">SMTP Username</Label>
                  <Input
                    id="smtpUsername"
                    value={settings.smtpUsername}
                    onChange={(e) => updateSetting('smtpUsername', e.target.value)}
                    disabled={!settings.emailEnabled}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="smtpPassword">SMTP Password</Label>
                  <Input
                    id="smtpPassword"
                    type="password"
                    value={settings.smtpPassword}
                    onChange={(e) => updateSetting('smtpPassword', e.target.value)}
                    disabled={!settings.emailEnabled}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="emailFromAddress">From Email Address</Label>
                  <Input
                    id="emailFromAddress"
                    type="email"
                    value={settings.emailFromAddress}
                    onChange={(e) => updateSetting('emailFromAddress', e.target.value)}
                    disabled={!settings.emailEnabled}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="emailFromName">From Name</Label>
                  <Input
                    id="emailFromName"
                    value={settings.emailFromName}
                    onChange={(e) => updateSetting('emailFromName', e.target.value)}
                    disabled={!settings.emailEnabled}
                  />
                </div>
              </div>
              <Button variant="outline" disabled={!settings.emailEnabled}>
                <Mail className="h-4 w-4 mr-2" />
                Test Email Configuration
              </Button>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>SMS Configuration</CardTitle>
              <CardDescription>Configure SMS gateway for sending text messages</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="smsEnabled">Enable SMS Service</Label>
                  <p className="text-sm text-gray-500">Allow system to send SMS messages</p>
                </div>
                <Switch
                  id="smsEnabled"
                  checked={settings.smsEnabled}
                  onCheckedChange={(checked) => updateSetting('smsEnabled', checked)}
                />
              </div>
              <Separator />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="smsProvider">SMS Provider</Label>
                  <Select 
                    value={settings.smsProvider} 
                    onValueChange={(value) => updateSetting('smsProvider', value)}
                    disabled={!settings.smsEnabled}
                  >
                    <SelectTrigger id="smsProvider">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="twilio">Twilio</SelectItem>
                      <SelectItem value="africastalking">Africa's Talking</SelectItem>
                      <SelectItem value="clickatell">Clickatell</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="smsFromNumber">From Number</Label>
                  <Input
                    id="smsFromNumber"
                    value={settings.smsFromNumber}
                    onChange={(e) => updateSetting('smsFromNumber', e.target.value)}
                    disabled={!settings.smsEnabled}
                    placeholder="+1234567890"
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <Label htmlFor="smsApiKey">API Key</Label>
                  <Input
                    id="smsApiKey"
                    type="password"
                    value={settings.smsApiKey}
                    onChange={(e) => updateSetting('smsApiKey', e.target.value)}
                    disabled={!settings.smsEnabled}
                  />
                </div>
              </div>
              <Button variant="outline" disabled={!settings.smsEnabled}>
                <MessageSquare className="h-4 w-4 mr-2" />
                Test SMS Configuration
              </Button>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Notification Settings */}
        <TabsContent value="notifications" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Notification Channels</CardTitle>
              <CardDescription>Choose how you want to receive notifications</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="enableEmailNotifications">Email Notifications</Label>
                  <p className="text-sm text-gray-500">Receive notifications via email</p>
                </div>
                <Switch
                  id="enableEmailNotifications"
                  checked={settings.enableEmailNotifications}
                  onCheckedChange={(checked) => updateSetting('enableEmailNotifications', checked)}
                />
              </div>
              <Separator />
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="enableSMSNotifications">SMS Notifications</Label>
                  <p className="text-sm text-gray-500">Receive notifications via SMS</p>
                </div>
                <Switch
                  id="enableSMSNotifications"
                  checked={settings.enableSMSNotifications}
                  onCheckedChange={(checked) => updateSetting('enableSMSNotifications', checked)}
                />
              </div>
              <Separator />
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="enablePushNotifications">Push Notifications</Label>
                  <p className="text-sm text-gray-500">Receive push notifications in browser</p>
                </div>
                <Switch
                  id="enablePushNotifications"
                  checked={settings.enablePushNotifications}
                  onCheckedChange={(checked) => updateSetting('enablePushNotifications', checked)}
                />
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Notification Events</CardTitle>
              <CardDescription>Choose which events trigger notifications</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="notifyOnNewRegistration">New Student Registration</Label>
                  <p className="text-sm text-gray-500">Notify when a new student registers</p>
                </div>
                <Switch
                  id="notifyOnNewRegistration"
                  checked={settings.notifyOnNewRegistration}
                  onCheckedChange={(checked) => updateSetting('notifyOnNewRegistration', checked)}
                />
              </div>
              <Separator />
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="notifyOnPayment">Fee Payments</Label>
                  <p className="text-sm text-gray-500">Notify when fees are paid</p>
                </div>
                <Switch
                  id="notifyOnPayment"
                  checked={settings.notifyOnPayment}
                  onCheckedChange={(checked) => updateSetting('notifyOnPayment', checked)}
                />
              </div>
              <Separator />
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="notifyOnAttendance">Attendance Alerts</Label>
                  <p className="text-sm text-gray-500">Notify on attendance issues</p>
                </div>
                <Switch
                  id="notifyOnAttendance"
                  checked={settings.notifyOnAttendance}
                  onCheckedChange={(checked) => updateSetting('notifyOnAttendance', checked)}
                />
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Security Settings */}
        <TabsContent value="security" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Authentication Security</CardTitle>
              <CardDescription>Configure authentication and access control</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="enableTwoFactor">Two-Factor Authentication</Label>
                  <p className="text-sm text-gray-500">Require 2FA for admin accounts</p>
                </div>
                <Switch
                  id="enableTwoFactor"
                  checked={settings.enableTwoFactor}
                  onCheckedChange={(checked) => updateSetting('enableTwoFactor', checked)}
                />
              </div>
              <Separator />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="sessionTimeout">Session Timeout (minutes)</Label>
                  <Input
                    id="sessionTimeout"
                    type="number"
                    value={settings.sessionTimeout}
                    onChange={(e) => updateSetting('sessionTimeout', parseInt(e.target.value))}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="maxLoginAttempts">Max Login Attempts</Label>
                  <Input
                    id="maxLoginAttempts"
                    type="number"
                    value={settings.maxLoginAttempts}
                    onChange={(e) => updateSetting('maxLoginAttempts', parseInt(e.target.value))}
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Password Policy</CardTitle>
              <CardDescription>Set password requirements for all users</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="passwordMinLength">Minimum Password Length</Label>
                <Input
                  id="passwordMinLength"
                  type="number"
                  value={settings.passwordMinLength}
                  onChange={(e) => updateSetting('passwordMinLength', parseInt(e.target.value))}
                />
              </div>
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="passwordRequireSpecialChar">Require Special Characters</Label>
                  <p className="text-sm text-gray-500">Password must contain special characters</p>
                </div>
                <Switch
                  id="passwordRequireSpecialChar"
                  checked={settings.passwordRequireSpecialChar}
                  onCheckedChange={(checked) => updateSetting('passwordRequireSpecialChar', checked)}
                />
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Backup Settings */}
        <TabsContent value="backup" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Automated Backups</CardTitle>
              <CardDescription>Configure automatic database backups</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <Label htmlFor="autoBackupEnabled">Enable Automatic Backups</Label>
                  <p className="text-sm text-gray-500">Automatically backup database</p>
                </div>
                <Switch
                  id="autoBackupEnabled"
                  checked={settings.autoBackupEnabled}
                  onCheckedChange={(checked) => updateSetting('autoBackupEnabled', checked)}
                />
              </div>
              <Separator />
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="backupFrequency">Backup Frequency</Label>
                  <Select 
                    value={settings.backupFrequency} 
                    onValueChange={(value) => updateSetting('backupFrequency', value)}
                    disabled={!settings.autoBackupEnabled}
                  >
                    <SelectTrigger id="backupFrequency">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="hourly">Hourly</SelectItem>
                      <SelectItem value="daily">Daily</SelectItem>
                      <SelectItem value="weekly">Weekly</SelectItem>
                      <SelectItem value="monthly">Monthly</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="backupTime">Backup Time</Label>
                  <Input
                    id="backupTime"
                    type="time"
                    value={settings.backupTime}
                    onChange={(e) => updateSetting('backupTime', e.target.value)}
                    disabled={!settings.autoBackupEnabled}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="backupRetentionDays">Retention (days)</Label>
                  <Input
                    id="backupRetentionDays"
                    type="number"
                    value={settings.backupRetentionDays}
                    onChange={(e) => updateSetting('backupRetentionDays', parseInt(e.target.value))}
                    disabled={!settings.autoBackupEnabled}
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Manual Backup & Restore</CardTitle>
              <CardDescription>Create or restore backups manually</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-start gap-4 p-4 border rounded-lg bg-amber-50 border-amber-200">
                <AlertCircle className="h-5 w-5 text-amber-600 mt-0.5" />
                <div className="flex-1">
                  <p className="text-sm font-medium text-amber-900">Important</p>
                  <p className="text-sm text-amber-700">
                    Creating a backup will temporarily lock the database. 
                    It's recommended to do this during off-peak hours.
                  </p>
                </div>
              </div>
              <div className="flex gap-3">
                <Button onClick={handleBackupNow} disabled={backupInProgress}>
                  {backupInProgress ? (
                    <>
                      <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                      Creating Backup...
                    </>
                  ) : (
                    <>
                      <Download className="h-4 w-4 mr-2" />
                      Create Backup Now
                    </>
                  )}
                </Button>
                <Button variant="outline" onClick={handleRestoreBackup}>
                  <Upload className="h-4 w-4 mr-2" />
                  Restore from Backup
                </Button>
              </div>
              <Separator />
              <div>
                <Label className="mb-2 block">Recent Backups</Label>
                <div className="space-y-2">
                  {['backup_2025-11-10_02-00.sql', 'backup_2025-11-09_02-00.sql', 'backup_2025-11-08_02-00.sql'].map((backup, index) => (
                    <div key={index} className="flex items-center justify-between p-3 border rounded-lg">
                      <div className="flex items-center gap-3">
                        <Database className="h-4 w-4 text-gray-500" />
                        <span className="text-sm font-medium">{backup}</span>
                      </div>
                      <div className="flex gap-2">
                        <Button size="sm" variant="ghost">
                          <Download className="h-3 w-3" />
                        </Button>
                        <Button size="sm" variant="ghost">
                          <Upload className="h-3 w-3" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Save Button */}
      <div className="flex justify-end sticky bottom-6 z-10">
        <Button onClick={handleSave} size="lg" disabled={loading} className="shadow-lg">
          {loading ? (
            <>
              <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
              Saving...
            </>
          ) : (
            <>
              <Save className="h-4 w-4 mr-2" />
              Save All Settings
            </>
          )}
        </Button>
      </div>
    </div>
  );
}

'use client'

import { useState, useEffect } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Plus, Search, Trash2, Edit, Filter } from 'lucide-react'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { useToast } from "@/components/ui/use-toast"

interface User {
  id: string
  email: string
  firstName: string
  lastName: string
  role: string
  grade?: string | null
  studentId?: string | null
  status: string
  createdAt: string
}

export default function UserManagement() {
  const { toast } = useToast()
  const [users, setUsers] = useState<User[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [roleFilter, setRoleFilter] = useState<string>('')
  const [page, setPage] = useState(1)
  const [totalPages, setTotalPages] = useState(1)
  
  // Create User Form State
  const [isCreateOpen, setIsCreateOpen] = useState(false)
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    role: 'student',
    grade: ''
  })

  useEffect(() => {
    fetchUsers()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page, roleFilter])

  const fetchUsers = async () => {
    setLoading(true)
    try {
      const params = new URLSearchParams({
        page: page.toString(),
        limit: '10',
        ...(roleFilter && { role: roleFilter }),
        ...(search && { search }),
      })

      const response = await fetch(`/api/admin/users?${params}`)

      if (response.ok) {
        const data = await response.json()
        setUsers(data.users)
        setTotalPages(data.pagination ? data.pagination.totalPages : 1)
      }
    } catch (error) {
      console.error('Failed to fetch users:', error)
      toast({ title: 'Error', description: 'Failed to fetch users', variant: 'destructive' })
    } finally {
      setLoading(false)
    }
  }

  const handleSearch = () => {
    setPage(1)
    fetchUsers()
  }

  const handleDelete = async (userId: string) => {
    if (!confirm('Are you sure you want to delete this user?')) return

    try {
      const response = await fetch(`/api/admin/users/${userId}`, {
        method: 'DELETE',
      })

      if (response.ok) {
        toast({ title: 'Success', description: 'User deleted' })
        fetchUsers()
      } else {
        const data = await response.json()
        toast({ title: 'Error', description: data.message || 'Failed to delete user', variant: 'destructive' })
      }
    } catch (error) {
      console.error('Delete error:', error)
      toast({ title: 'Error', description: 'Failed to delete user', variant: 'destructive' })
    }
  }

  const handleCreateUser = async (e: React.FormEvent) => {
    e.preventDefault()
    try {
      const response = await fetch('/api/admin/users', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      })

      const data = await response.json()
      if (response.ok) {
        toast({ title: 'Success', description: 'User created successfully' })
        setIsCreateOpen(false)
        setFormData({
            firstName: '',
            lastName: '',
            email: '',
            password: '',
            role: 'student',
            grade: ''
        })
        fetchUsers()
      } else {
        toast({ title: 'Error', description: data.message || 'Failed to create user', variant: 'destructive' })
      }
    } catch (error) {
       toast({ title: 'Error', description: 'Failed to create user', variant: 'destructive' })
    }
  }

  const getRoleBadgeColor = (role: string) => {
    const colors: Record<string, string> = {
      admin: 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400',
      teacher: 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400',
      student: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400',
      parent: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400',
    }
    return colors[role] || 'bg-gray-100 text-gray-800'
  }

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <div className="flex justify-between items-center">
            <div>
              <CardTitle>User Management</CardTitle>
              <CardDescription>Manage all users in the system</CardDescription>
            </div>
            
            <Dialog open={isCreateOpen} onOpenChange={setIsCreateOpen}>
              <DialogTrigger asChild>
                <Button className="gap-2">
                  <Plus className="h-4 w-4" />
                  Add User
                </Button>
              </DialogTrigger>
              <DialogContent>
                <DialogHeader>
                  <DialogTitle>Add New User</DialogTitle>
                </DialogHeader>
                <form onSubmit={handleCreateUser} className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="firstName">First Name</Label>
                      <Input id="firstName" required value={formData.firstName} onChange={(e) => setFormData({...formData, firstName: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="lastName">Last Name</Label>
                      <Input id="lastName" required value={formData.lastName} onChange={(e) => setFormData({...formData, lastName: e.target.value})} />
                    </div>
                  </div>
                  
                  <div className="space-y-2">
                    <Label htmlFor="email">Email</Label>
                    <Input id="email" type="email" required value={formData.email} onChange={(e) => setFormData({...formData, email: e.target.value})} />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="password">Password</Label>
                    <Input id="password" type="password" required value={formData.password} onChange={(e) => setFormData({...formData, password: e.target.value})} />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Role</Label>
                      <Select value={formData.role} onValueChange={(val) => setFormData({...formData, role: val})}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="student">Student</SelectItem>
                          <SelectItem value="teacher">Teacher</SelectItem>
                          <SelectItem value="admin">Admin</SelectItem>
                          <SelectItem value="parent">Parent</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    {formData.role === 'student' && (
                        <div className="space-y-2">
                        <Label>Grade</Label>
                        <Input value={formData.grade} onChange={(e) => setFormData({...formData, grade: e.target.value})} placeholder="e.g. 10" />
                        </div>
                    )}
                  </div>
                  
                  <DialogFooter>
                    <Button type="submit">Create User</Button>
                  </DialogFooter>
                </form>
              </DialogContent>
            </Dialog>
          </div>
        </CardHeader>
        <CardContent>
          {/* Search and Filters */}
          <div className="flex gap-4 mb-6">
            <div className="flex-1 flex gap-2">
              <Input
                placeholder="Search by name or email..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
              />
              <Button onClick={handleSearch} variant="outline">
                <Search className="h-4 w-4" />
              </Button>
            </div>
            <select
              value={roleFilter}
              onChange={(e) => {
                setRoleFilter(e.target.value)
                setPage(1)
              }}
              className="px-3 py-2 border rounded-md bg-background"
            >
              <option value="">All Roles</option>
              <option value="admin">Admin</option>
              <option value="teacher">Teacher</option>
              <option value="student">Student</option>
              <option value="parent">Parent</option>
            </select>
          </div>

          {/* Users Table */}
          {loading ? (
            <div className="text-center py-8">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
            </div>
          ) : users.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <p>No users found</p>
              <p className="text-sm mt-2">Try adjusting your filters or create a new user</p>
            </div>
          ) : (
            <>
              <div className="border rounded-lg overflow-hidden">
                <table className="w-full">
                  <thead className="bg-muted">
                    <tr>
                      <th className="text-left p-3 font-medium">Name</th>
                      <th className="text-left p-3 font-medium">Email</th>
                      <th className="text-left p-3 font-medium">Role</th>
                      <th className="text-left p-3 font-medium">Status</th>
                      <th className="text-left p-3 font-medium">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {users.map((user) => (
                      <tr key={user.id} className="border-t hover:bg-muted/50">
                        <td className="p-3">
                          <div>
                            <p className="font-medium">{user.firstName} {user.lastName}</p>
                            {user.studentId && (
                              <p className="text-sm text-muted-foreground">{user.studentId}</p>
                            )}
                          </div>
                        </td>
                        <td className="p-3 text-sm">{user.email}</td>
                        <td className="p-3">
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getRoleBadgeColor(user.role)}`}>
                            {user.role}
                          </span>
                        </td>
                        <td className="p-3">
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${user.status === 'active'
                              ? 'bg-green-100 text-green-800 dark:bg-green-900/30'
                              : 'bg-gray-100 text-gray-800 dark:bg-gray-900/30'
                            }`}>
                            {user.status || 'Active'}
                          </span>
                        </td>
                        <td className="p-3">
                          <div className="flex gap-2">
                           
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => handleDelete(user.id)}
                            >
                              <Trash2 className="h-4 w-4 text-destructive" />
                            </Button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Pagination */}
              {totalPages > 1 && (
                <div className="flex justify-center gap-2 mt-4">
                  <Button
                    variant="outline"
                    onClick={() => setPage(p => Math.max(1, p - 1))}
                    disabled={page === 1}
                  >
                    Previous
                  </Button>
                  <div className="flex items-center gap-2 px-4">
                    Page {page} of {totalPages}
                  </div>
                  <Button
                    variant="outline"
                    onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                    disabled={page === totalPages}
                  >
                    Next
                  </Button>
                </div>
              )}
            </>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

'use client';

// AdminHeader Component - Header for admin pages with breadcrumbs
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { ChevronLeft, Home } from 'lucide-react';

interface BreadcrumbItem {
  label: string;
  path?: string;
}

interface AdminHeaderProps {
  title: string;
  description?: string;
  breadcrumbs?: BreadcrumbItem[];
  action?: React.ReactNode;
}

export function AdminHeader({
  title,
  description,
  breadcrumbs,
  action,
}: AdminHeaderProps) {
  const router = useRouter();

  return (
    <div className="mb-6">
      {/* Breadcrumbs */}
      {breadcrumbs && breadcrumbs.length > 0 && (
        <div className="flex items-center gap-2 text-sm text-gray-500 mb-2">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => router.push('/admin')}
            className="h-auto p-0 hover:bg-transparent"
          >
            <Home className="h-4 w-4" />
          </Button>
          {breadcrumbs.map((item, index) => (
            <div key={index} className="flex items-center gap-2">
              <span>/</span>
              {item.path ? (
                <Button
                  variant="ghost"
