                  <SelectItem value="Lower 6">Lower 6</SelectItem>
                  <SelectItem value="Upper 6">Upper 6</SelectItem>
                </SelectContent>
              </Select>
              <p className="text-sm text-muted-foreground">
                You will receive an application ID upon registration. Your official registration number will be assigned after admission approval.
              </p>
            </div>

            {/* Password */}
            <div className="space-y-2">
              <Label htmlFor="password">Password *</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  id="password"
                  name="password"
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Create a strong password"
                  value={formData.password}
                  onChange={handleChange}
                  disabled={isLoading}
                  className="pl-10 pr-10"
                  autoComplete="new-password"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-3 text-muted-foreground hover:text-foreground"
                  tabIndex={-1}
                  aria-label={showPassword ? "Hide password" : "Show password"}
                >
                  {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>

              {/* Password Requirements */}
              {formData.password && (
                <div className="text-xs space-y-1 mt-2">
                  <div className={`flex items-center gap-2 ${passwordRequirements.minLength ? 'text-green-600' : 'text-muted-foreground'}`}>
                    {passwordRequirements.minLength ? <Check className="h-3 w-3" /> : <X className="h-3 w-3" />}
                    At least 8 characters
                  </div>
                  <div className={`flex items-center gap-2 ${passwordRequirements.hasUpperCase ? 'text-green-600' : 'text-muted-foreground'}`}>
                    {passwordRequirements.hasUpperCase ? <Check className="h-3 w-3" /> : <X className="h-3 w-3" />}
                    One uppercase letter
                  </div>
                  <div className={`flex items-center gap-2 ${passwordRequirements.hasLowerCase ? 'text-green-600' : 'text-muted-foreground'}`}>
                    {passwordRequirements.hasLowerCase ? <Check className="h-3 w-3" /> : <X className="h-3 w-3" />}
                    One lowercase letter
                  </div>
                  <div className={`flex items-center gap-2 ${passwordRequirements.hasNumber ? 'text-green-600' : 'text-muted-foreground'}`}>
                    {passwordRequirements.hasNumber ? <Check className="h-3 w-3" /> : <X className="h-3 w-3" />}
                    One number
                  </div>
                </div>
              )}
            </div>

            {/* Confirm Password */}
            <div className="space-y-2">
              <Label htmlFor="confirmPassword">Confirm Password *</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  id="confirmPassword"
                  name="confirmPassword"
                  type={showConfirmPassword ? 'text' : 'password'}
                  placeholder="Confirm your password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  disabled={isLoading}
                  className="pl-10 pr-10"
                  autoComplete="new-password"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                  className="absolute right-3 top-3 text-muted-foreground hover:text-foreground"
                  tabIndex={-1}
                  aria-label={showConfirmPassword ? "Hide confirm password" : "Show confirm password"}
                >
                  {showConfirmPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>
              {confirmPassword && formData.password !== confirmPassword && (
                <p className="text-xs text-destructive">Passwords do not match</p>
              )}
            </div>

            <Button 
              type="submit" 
              className="w-full" 
              disabled={isLoading || !isPasswordStrong}
            >
              {isLoading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Creating account...
                </>
              ) : (
                'Create Account'
              )}
            </Button>
          </CardContent>
        </form>

        <CardFooter className="flex flex-col space-y-4">
          <div className="text-sm text-center text-muted-foreground">
            Already have an account?{' '}
            <Link href="/login" className="text-primary hover:underline font-medium">
              Sign in here
            </Link>
          </div>
        </CardFooter>
      </Card>
    </div>
  );
}

'use client'

import * as React from 'react'

//Dark mode disabled - light mode only
// Stub to prevent import errors
export function ThemeProvider({ children }: { children: React.ReactNode }) {
  return <>{children}</>
}

// Proper hook implementation to prevent errors in components that reference it
export function useTheme() {
  const [theme] = React.useState('light' as const);
  
  return {
    theme,
    setTheme: (_theme: string) => {},
    themes: ['light'] as const
  };
}

import React, { useState, useEffect } from 'react';
import { Brain, TrendingUp, TrendingDown, AlertTriangle, CheckCircle, Target, Zap, Activity, Users } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { useToast } from '@/hooks/use-toast';
import {
  LineChart,
  Line,
  AreaChart,
  Area,
  PieChart as RechartsPieChart,
  Pie,
  Cell,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  ScatterChart,
  Scatter
} from 'recharts';

interface StudentInsight {
  studentId: string;
  studentName: string;
  riskLevel: 'low' | 'medium' | 'high';
  predictedGrade: string;
  confidence: number;
  strengths: string[];
  weaknesses: string[];
  recommendations: string[];
  engagementScore: number;
  lastAssessment: Date;
}

interface ClassAnalytics {
  classId: string;
  className: string;
  averagePerformance: number;
  attendanceRate: number;
  engagementTrend: 'up' | 'down' | 'stable';
  atRiskStudents: number;
  topPerformers: number;
  improvementAreas: string[];
}

interface AIPrediction {
  type: 'grade' | 'engagement' | 'risk' | 'recommendation';
  prediction: string;
  confidence: number;
  timeframe: string;
  actionable: boolean;
}

interface AIInsightsDashboardProps {
  userRole?: 'student' | 'parent' | 'teacher' | 'admin';
  studentId?: string;
  classId?: string;
}

export function AIInsightsDashboard({
  userRole = 'teacher',
  studentId,
  classId
}: AIInsightsDashboardProps) {
  const [insights, setInsights] = useState<StudentInsight[]>([]);
  const [classAnalytics, setClassAnalytics] = useState<ClassAnalytics[]>([]);
  const [predictions, setPredictions] = useState<AIPrediction[]>([]);
  const [selectedTimeframe, setSelectedTimeframe] = useState('30days');
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');
  const { toast } = useToast();

  useEffect(() => {
    loadAIData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [userRole, studentId, classId, selectedTimeframe]);

  const loadAIData = async () => {
    setIsLoading(true);
    try {
      // Simulate AI processing delay
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Mock AI-generated insights
      const mockInsights: StudentInsight[] = [
        {
          studentId: '1',
          studentName: 'John Smith',
          riskLevel: 'low',
          predictedGrade: 'A-',
          confidence: 87,
          strengths: ['Mathematics', 'Problem Solving', 'Critical Thinking'],
          weaknesses: ['Reading Comprehension', 'Time Management'],
          recommendations: [
            'Focus on reading comprehension exercises',
            'Practice time management techniques',
            'Continue strong performance in mathematics'
          ],
          engagementScore: 85,
          lastAssessment: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
        },
        {
          studentId: '2',
          studentName: 'Mary Johnson',
          riskLevel: 'medium',
          predictedGrade: 'B',
          confidence: 72,
          strengths: ['Creative Writing', 'Art', 'Social Studies'],
          weaknesses: ['Mathematics', 'Science', 'Test Anxiety'],
          recommendations: [
            'Additional support in mathematics',
            'Stress management techniques',
            'Peer tutoring for science concepts'
          ],
          engagementScore: 68,
          lastAssessment: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000),
        },
        {
          studentId: '3',
          studentName: 'David Brown',
          riskLevel: 'high',
          predictedGrade: 'C+',
          confidence: 91,
          strengths: ['Physical Education', 'Team Sports'],
          weaknesses: ['Academic Subjects', 'Study Skills', 'Attendance'],
          recommendations: [
            'Immediate intervention required',
            'Study skills training program',
            'Attendance monitoring and support',
            'Parental involvement increase'
          ],
          engagementScore: 45,
          lastAssessment: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000),
        }
      ];

      const mockClassAnalytics: ClassAnalytics[] = [
        {
          classId: 'grade-7',
          className: 'Grade 7',
          averagePerformance: 78,
          attendanceRate: 94,
          engagementTrend: 'up',
          atRiskStudents: 3,
          topPerformers: 8,
          improvementAreas: ['Mathematics', 'Reading Comprehension'],
        },
        {
          classId: 'grade-6',
          className: 'Grade 6',
          averagePerformance: 82,
          attendanceRate: 96,
          engagementTrend: 'stable',
          atRiskStudents: 1,
          topPerformers: 12,
          improvementAreas: ['Science Projects'],
        }
      ];

      const mockPredictions: AIPrediction[] = [
        {
          type: 'grade',
          prediction: 'Overall class performance expected to improve by 8% next term',
          confidence: 85,
          timeframe: '3 months',
          actionable: true,
        },
        {
          type: 'engagement',
          prediction: 'Student engagement will increase with new interactive learning methods',
          confidence: 78,
          timeframe: '6 weeks',
          actionable: true,
        },
        {
          type: 'risk',
          prediction: '3 students identified as at-risk for academic challenges',
          confidence: 92,
          timeframe: 'immediate',
          actionable: true,
        },
        {
          type: 'recommendation',
          prediction: 'Implement peer tutoring program for better outcomes',
          confidence: 88,
          timeframe: 'next month',
          actionable: true,
        }
      ];

      setInsights(mockInsights);
      setClassAnalytics(mockClassAnalytics);
      setPredictions(mockPredictions);

    } catch (error) {
      console.error('Error loading AI data:', error);
      toast({
        title: "Error",
        description: "Failed to load AI insights.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const getRiskColor = (risk: string) => {
    switch (risk) {
      case 'low': return 'bg-green-100 text-green-800';
      case 'medium': return 'bg-yellow-100 text-yellow-800';
      case 'high': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getTrendIcon = (trend: string) => {
    switch (trend) {
      case 'up': return <TrendingUp className="h-4 w-4 text-green-500" />;
      case 'down': return <TrendingDown className="h-4 w-4 text-red-500" />;
      default: return <Activity className="h-4 w-4 text-gray-500" />;
    }
  };

  // Prepare chart data
  const performanceData = insights.map(insight => ({
    name: insight.studentName.split(' ')[0],
    performance: insight.engagementScore,
    predicted: parseFloat(insight.predictedGrade.charAt(0)) * 20 + 60, // Convert grade to percentage
    risk: insight.riskLevel === 'high' ? 3 : insight.riskLevel === 'medium' ? 2 : 1,
  }));

  const riskDistribution = [
    { name: 'Low Risk', value: insights.filter(i => i.riskLevel === 'low').length, color: '#10B981' },
    { name: 'Medium Risk', value: insights.filter(i => i.riskLevel === 'medium').length, color: '#F59E0B' },
    { name: 'High Risk', value: insights.filter(i => i.riskLevel === 'high').length, color: '#EF4444' },
  ];

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#1C1A75]"></div>
        <span className="ml-2">Analyzing data with AI...</span>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-[#1C1A75] flex items-center gap-2">
            <Brain className="h-6 w-6" />
            AI Insights Dashboard
          </h2>
          <p className="text-gray-600">Machine learning-powered analytics and predictions</p>
        </div>
        <div className="flex items-center gap-4">
          <Select value={selectedTimeframe} onValueChange={setSelectedTimeframe}>
            <SelectTrigger className="w-32">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="7days">7 Days</SelectItem>
              <SelectItem value="30days">30 Days</SelectItem>
              <SelectItem value="90days">90 Days</SelectItem>
              <SelectItem value="1year">1 Year</SelectItem>
            </SelectContent>
          </Select>
          <Button className="bg-[#1C1A75] hover:bg-[#1C1A75]/90">
            <Zap className="mr-2 h-4 w-4" />
            Run Analysis
          </Button>
        </div>
      </div>

      {/* AI Predictions Alert */}
      <div className="grid gap-4 md:grid-cols-2">
        {predictions.slice(0, 2).map((prediction, index) => (
          <Alert key={index} className={`${
            prediction.type === 'risk' ? 'border-red-200 bg-red-50' :
            prediction.type === 'recommendation' ? 'border-blue-200 bg-blue-50' :
            'border-green-200 bg-green-50'
          }`}>
            <Target className="h-4 w-4" />
            <AlertTitle>AI Prediction</AlertTitle>
            <AlertDescription>
              <p className="font-medium">{prediction.prediction}</p>
              <div className="flex items-center gap-2 mt-2">
                <Badge variant="outline">{prediction.confidence}% confidence</Badge>
                <span className="text-sm text-gray-600">• {prediction.timeframe}</span>
              </div>
            </AlertDescription>
          </Alert>
        ))}
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="overview">Overview</TabsTrigger>
          <TabsTrigger value="students">Student Insights</TabsTrigger>
          <TabsTrigger value="analytics">Analytics</TabsTrigger>
          <TabsTrigger value="predictions">Predictions</TabsTrigger>
        </TabsList>

        <TabsContent value="overview" className="space-y-4">
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Students Analyzed</CardTitle>
                <Users className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{insights.length}</div>
                <p className="text-xs text-muted-foreground">
                  AI-powered insights generated
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">At-Risk Students</CardTitle>
                <AlertTriangle className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-red-600">
                  {insights.filter(i => i.riskLevel === 'high').length}
                </div>
                <p className="text-xs text-muted-foreground">
                  Require immediate attention
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Avg Engagement</CardTitle>
                <Activity className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  {Math.round(insights.reduce((acc, i) => acc + i.engagementScore, 0) / insights.length)}%
                </div>
                <p className="text-xs text-muted-foreground">
                  Student engagement score
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">AI Accuracy</CardTitle>
                <CheckCircle className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-green-600">94%</div>
                <p className="text-xs text-muted-foreground">
                  Prediction accuracy rate
                </p>
              </CardContent>
            </Card>
          </div>

          <div className="grid gap-6 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Performance vs Engagement</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300}>
                  <ScatterChart data={performanceData}>
                    <CartesianGrid />
                    <XAxis dataKey="performance" name="Engagement" />
                    <YAxis dataKey="predicted" name="Predicted Grade %" />
                    <Tooltip cursor={{ strokeDasharray: '3 3' }} />
                    <Scatter name="Students" dataKey="predicted" fill="#1C1A75" />
                  </ScatterChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Risk Level Distribution</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300}>
                  <RechartsPieChart>
                    <Pie
                      data={riskDistribution}
                      cx="50%"
                      cy="50%"
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="value"
                      label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                    >
                      {riskDistribution.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </RechartsPieChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="students" className="space-y-4">
          <div className="grid gap-4">
            {insights.map((insight) => (
              <Card key={insight.studentId}>
                <CardHeader>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-[#1C1A75] rounded-full flex items-center justify-center text-white font-bold">
                        {insight.studentName.charAt(0)}
                      </div>
                      <div>
                        <CardTitle className="text-lg">{insight.studentName}</CardTitle>
                        <CardDescription>
                          Last assessment: {insight.lastAssessment.toLocaleDateString()}
                        </CardDescription>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge className={getRiskColor(insight.riskLevel)}>
                        {insight.riskLevel.toUpperCase()} RISK
                      </Badge>
                      <Badge variant="outline">
                        Predicted: {insight.predictedGrade}
                      </Badge>
                    </div>
                  </div>
                </CardHeader>
                <CardContent>
                  <div className="grid gap-4 md:grid-cols-2">
                    <div>
                      <h4 className="font-medium mb-2 flex items-center gap-2">
                        <CheckCircle className="h-4 w-4 text-green-500" />
                        Strengths
                      </h4>
                      <div className="flex flex-wrap gap-1">
                        {insight.strengths.map((strength, index) => (
                          <Badge key={index} variant="secondary" className="text-xs">
                            {strength}
                          </Badge>
                        ))}
                      </div>
                    </div>

                    <div>
                      <h4 className="font-medium mb-2 flex items-center gap-2">
                        <AlertTriangle className="h-4 w-4 text-yellow-500" />
                        Areas for Improvement
                      </h4>
                      <div className="flex flex-wrap gap-1">
                        {insight.weaknesses.map((weakness, index) => (
                          <Badge key={index} variant="outline" className="text-xs">
                            {weakness}
                          </Badge>
                        ))}
                      </div>
                    </div>
                  </div>

                  <div className="mt-4">
                    <h4 className="font-medium mb-2">AI Recommendations</h4>
                    <div className="space-y-2">
                      {insight.recommendations.map((rec, index) => (
                        <div key={index} className="flex items-start gap-2">
                          <Target className="h-4 w-4 text-blue-500 mt-0.5 flex-shrink-0" />
                          <p className="text-sm">{rec}</p>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="mt-4 pt-4 border-t">
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="text-sm font-medium">Engagement Score</p>
                        <p className="text-xs text-gray-600">Based on participation and activity</p>
                      </div>
                      <div className="text-right">
                        <p className="text-lg font-bold">{insight.engagementScore}%</p>
                        <Progress value={insight.engagementScore} className="w-20 h-2" />
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </TabsContent>

        <TabsContent value="analytics" className="space-y-4">
          <div className="grid gap-6 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Student Performance Trends</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300}>
                  <LineChart data={performanceData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="name" />
                    <YAxis domain={[0, 100]} />
                    <Tooltip />
                    <Line type="monotone" dataKey="performance" stroke="#1C1A75" strokeWidth={2} />
                    <Line type="monotone" dataKey="predicted" stroke="#D4AF37" strokeWidth={2} strokeDasharray="5 5" />
                  </LineChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Engagement vs Performance</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300}>
                  <AreaChart data={performanceData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="name" />
                    <YAxis domain={[0, 100]} />
                    <Tooltip />
                    <Area type="monotone" dataKey="performance" stackId="1" stroke="#1C1A75" fill="#1C1A75" />
                    <Area type="monotone" dataKey="predicted" stackId="2" stroke="#D4AF37" fill="#D4AF37" />
                  </AreaChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Class Performance Analytics</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid gap-4 md:grid-cols-3">
                {classAnalytics.map((analytics) => (
                  <div key={analytics.classId} className="p-4 border rounded-lg">
                    <h3 className="font-medium mb-2">{analytics.className}</h3>
                    <div className="space-y-2">
                      <div className="flex justify-between">
                        <span className="text-sm">Avg Performance</span>
                        <span className="font-medium">{analytics.averagePerformance}%</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Attendance</span>
                        <span className="font-medium">{analytics.attendanceRate}%</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">At-Risk Students</span>
                        <span className="font-medium text-red-600">{analytics.atRiskStudents}</span>
                      </div>
                      <div className="flex items-center gap-2 mt-2">
                        {getTrendIcon(analytics.engagementTrend)}
                        <span className="text-sm capitalize">{analytics.engagementTrend} trend</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="predictions" className="space-y-4">
          <div className="grid gap-4">
            {predictions.map((prediction, index) => (
              <Card key={index}>
                <CardHeader>
                  <div className="flex items-center justify-between">
                    <CardTitle className="flex items-center gap-2">
                      {prediction.type === 'risk' && <AlertTriangle className="h-5 w-5 text-red-500" />}
                      {prediction.type === 'grade' && <TrendingUp className="h-5 w-5 text-green-500" />}
                      {prediction.type === 'engagement' && <Activity className="h-5 w-5 text-blue-500" />}
                      {prediction.type === 'recommendation' && <Target className="h-5 w-5 text-purple-500" />}
                      {prediction.type.charAt(0).toUpperCase() + prediction.type.slice(1)} Prediction
                    </CardTitle>
                    <Badge variant={prediction.confidence > 80 ? "default" : "secondary"}>
                      {prediction.confidence}% confidence
                    </Badge>
                  </div>
                </CardHeader>
                <CardContent>
                  <p className="text-sm mb-3">{prediction.prediction}</p>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <Badge variant="outline">{prediction.timeframe}</Badge>
                      {prediction.actionable && (
                        <Badge className="bg-green-100 text-green-800">Actionable</Badge>
                      )}
                    </div>
                    <Button size="sm" variant="outline">
                      View Details
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { Upload, X, CheckCircle, AlertCircle, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';

import { useToast } from '@/hooks/use-toast';
import lmsService from '@/services/lmsService';

interface AssignmentSubmissionProps {
  assignmentId: string;
  assignmentTitle: string;
  studentId: string;
  studentName: string;
  onSubmissionComplete?: () => void;
  onClose?: () => void;
}

interface UploadedFile {
  id: string;
  name: string;
  size: number;
  type: string;
  uploadProgress: number;
  status: 'uploading' | 'completed' | 'error';
  file: File;
}

export function AssignmentSubmission({
  assignmentId,
  assignmentTitle,
  studentId,
  studentName: _studentName,
  onSubmissionComplete,
  onClose
}: AssignmentSubmissionProps) {
  const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);
  const [isDragOver, setIsDragOver] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submissionNotes, setSubmissionNotes] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();

  const allowedFileTypes = [
    'application/pdf',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'text/plain',
    'image/jpeg',
    'image/png',
    'image/gif',
    'application/zip',
    'application/x-rar-compressed'
  ];

  const maxFileSize = 10 * 1024 * 1024; // 10MB

  const formatFileSize = (bytes: number): string => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const validateFile = (file: File): string | null => {
    if (!allowedFileTypes.includes(file.type)) {
      return `File type ${file.type} is not allowed. Please upload PDF, Word documents, text files, or images.`;
    }

    if (file.size > maxFileSize) {
      return `File size ${formatFileSize(file.size)} exceeds the maximum limit of ${formatFileSize(maxFileSize)}.`;
    }

    return null;
  };

  const handleFileSelect = (files: FileList | null) => {
    if (!files) return;

    const newFiles: UploadedFile[] = [];

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const validationError = validateFile(file);

      if (validationError) {
        toast({
          title: "Invalid File",
          description: validationError,
          variant: "destructive",
        });
        continue;
      }

      const uploadedFile: UploadedFile = {
        id: Date.now().toString() + Math.random(),
        name: file.name,
        size: file.size,
        type: file.type,
        uploadProgress: 0,
        status: 'uploading',
        file,
      };

      newFiles.push(uploadedFile);

      // Simulate upload progress
      simulateUpload(uploadedFile.id);
    }

    setUploadedFiles(prev => [...prev, ...newFiles]);
  };

  const simulateUpload = (fileId: string) => {
    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 30;
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);

        setUploadedFiles(prev =>
          prev.map(f =>
            f.id === fileId
              ? { ...f, uploadProgress: 100, status: 'completed' as const }
              : f
          )
        );
      } else {
        setUploadedFiles(prev =>
          prev.map(f =>
            f.id === fileId
              ? { ...f, uploadProgress: progress }
              : f
          )
        );
      }
    }, 200);
  };

  const removeFile = (fileId: string) => {
    setUploadedFiles(prev => prev.filter(f => f.id !== fileId));
  };

  const handleSubmit = async () => {
    const completedFiles = uploadedFiles.filter(f => f.status === 'completed');

    if (completedFiles.length === 0) {
      toast({
        title: "No Files to Submit",
        description: "Please upload and wait for files to finish uploading before submitting.",
        variant: "destructive",
      });
      return;
    }

    setIsSubmitting(true);

    try {
      // Submit each file
      for (const file of completedFiles) {
        await lmsService.submitAssignment(assignmentId, file.file, studentId);
      }

      toast({
        title: "Assignment Submitted",
        description: `Successfully submitted ${completedFiles.length} file(s) for "${assignmentTitle}".`,
      });

      onSubmissionComplete?.();
      onClose?.();
    } catch (_error) {
      toast({
        title: "Submission Failed",
        description: "Failed to submit assignment. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    handleFileSelect(e.dataTransfer.files);
  };

  const getFileIcon = (fileType: string) => {
    if (fileType.startsWith('image/')) return '🖼️';
    if (fileType === 'application/pdf') return '📄';
    if (fileType.includes('word')) return '📝';
    if (fileType === 'text/plain') return '📃';
    if (fileType.includes('zip') || fileType.includes('rar')) return '📦';
    return '📄';
  };

  return (
    <div className="space-y-6">
      <div className="text-center">
        <h2 className="text-2xl font-bold text-[#1C1A75] mb-2">Submit Assignment</h2>
        <p className="text-gray-600">
          Upload your completed assignment for <strong>{assignmentTitle}</strong>
        </p>
      </div>

      {/* File Upload Area */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Upload className="h-5 w-5" />
            Upload Files
          </CardTitle>
          <CardDescription>
            Drag and drop files here or click to browse. Maximum file size: 10MB per file.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div
            className={`border-2 border-dashed rounded-lg p-8 text-center transition-colors ${
              isDragOver
                ? 'border-[#1C1A75] bg-blue-50'
                : 'border-gray-300 hover:border-gray-400'
            }`}
            onDragOver={handleDragOver}
            onDragLeave={handleDragLeave}
            onDrop={handleDrop}
          >
            <Upload className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <p className="text-lg font-medium text-gray-900 mb-2">
              Drop files here or click to browse
            </p>
            <p className="text-sm text-gray-600 mb-4">
              Supported formats: PDF, Word, Text, Images, ZIP
            </p>
            <Button
              onClick={() => fileInputRef.current?.click()}
              className="bg-[#1C1A75] hover:bg-[#1C1A75]/90"
            >
              Choose Files
            </Button>
            <input
              ref={fileInputRef}
              type="file"
              multiple
              accept=".pdf,.doc,.docx,.txt,.jpg,.jpeg,.png,.gif,.zip,.rar"
              onChange={(e) => handleFileSelect(e.target.files)}
              className="hidden"
            />
          </div>
        </CardContent>
      </Card>

      {/* Uploaded Files */}
      {uploadedFiles.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>Uploaded Files</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {uploadedFiles.map((file) => (
                <div key={file.id} className="flex items-center gap-3 p-3 border rounded-lg">
                  <div className="text-2xl">{getFileIcon(file.type)}</div>
                  <div className="flex-1">
                    <p className="font-medium text-sm">{file.name}</p>
                    <p className="text-xs text-gray-600">{formatFileSize(file.size)}</p>
                    {file.status === 'uploading' && (
                      <div className="mt-2">
                        <Progress value={file.uploadProgress} className="h-1" />
                        <p className="text-xs text-gray-500 mt-1">
                          Uploading... {Math.round(file.uploadProgress)}%
                        </p>
                      </div>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    {file.status === 'completed' && (
                      <CheckCircle className="h-5 w-5 text-green-500" />
                    )}
                    {file.status === 'error' && (
                      <AlertCircle className="h-5 w-5 text-red-500" />
                    )}
                    <Button
                      size="sm"
                      variant="ghost"
                      onClick={() => removeFile(file.id)}
                      className="text-red-600 hover:text-red-700"
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Submission Notes */}
      <Card>
        <CardHeader>
          <CardTitle>Additional Notes (Optional)</CardTitle>
        </CardHeader>
        <CardContent>
          <textarea
            value={submissionNotes}
            onChange={(e) => setSubmissionNotes(e.target.value)}
            placeholder="Add any notes or comments about your submission..."
            className="w-full p-3 border rounded-lg resize-none"
            rows={4}
          />
        </CardContent>
      </Card>

      {/* Action Buttons */}
      <div className="flex gap-3 justify-end">
        <Button variant="outline" onClick={onClose}>
          Cancel
        </Button>
        <Button
          onClick={handleSubmit}
          disabled={uploadedFiles.filter(f => f.status === 'completed').length === 0 || isSubmitting}
          className="bg-[#1C1A75] hover:bg-[#1C1A75]/90"
        >
          {isSubmitting ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              Submitting...
            </>
          ) : (
            <>
              <CheckCircle className="mr-2 h-4 w-4" />
              Submit Assignment
            </>
          )}
        </Button>
      </div>

      {/* Submission Guidelines */}
      <Card className="bg-blue-50 border-blue-200">
        <CardHeader>
          <CardTitle className="text-blue-900">Submission Guidelines</CardTitle>
        </CardHeader>
        <CardContent className="text-blue-800">
          <ul className="space-y-2 text-sm">
            <li>• Ensure all files are properly named and organized</li>
            <li>• Check that your work is complete before submitting</li>
            <li>• You can submit multiple files if needed</li>
            <li>• Supported formats: PDF, Word documents, text files, images</li>
            <li>• Maximum file size: 10MB per file</li>
            <li>• You cannot modify your submission after it's submitted</li>
          </ul>
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import { MessageCircle, Send, X, Minimize2, Maximize2, Paperclip } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import socketService from '@/services/socket';
import { useToast } from '@/hooks/use-toast';

interface Message {
  id: string;
  userId: string;
  userName: string;
  userAvatar?: string;
  message: string;
  timestamp: Date;
  messageType: 'text' | 'image' | 'file';
}

interface ChatWidgetProps {
  userId?: string;
  userName?: string;
  userAvatar?: string;
  roomId?: string;
}

export function ChatWidget({
  userId = 'anonymous',
  userName = 'Anonymous User',
  userAvatar,
  roomId = 'general'
}: ChatWidgetProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState<string[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<NodeJS.Timeout>();
  const { toast } = useToast();

  useEffect(() => {
    if (isOpen && !isMinimized) {
      // Connect to socket when chat is opened
      socketService.connect(userId);

      // Join the general room
      socketService.joinRoom(roomId);

      // Set up event listeners
      socketService.onMessage((data) => {
        const message: Message = {
          id: data.id || Date.now().toString(),
          userId: data.userId,
          userName: data.userName,
          userAvatar: data.userAvatar,
          message: data.message,
          timestamp: new Date(data.timestamp),
          messageType: data.messageType || 'text',
        };
        setMessages(prev => [...prev, message]);
      });

      socketService.onUserJoined((data) => {
        setOnlineUsers(prev => [...prev, data.userId]);
        toast({
          title: "User joined",
          description: `${data.userName} joined the chat`,
        });
      });

      socketService.onUserLeft((data) => {
        setOnlineUsers(prev => prev.filter(id => id !== data.userId));
      });

      socketService.onTyping((data) => {
        if (data.userId !== userId) {
          setIsTyping(true);
        }
      });

      socketService.onStopTyping(() => {
        setIsTyping(false);
      });
    }

    return () => {
      if (!isOpen) {
        socketService.disconnect();
      }
    };
  }, [isOpen, isMinimized, userId, roomId, toast]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = () => {
    if (newMessage.trim()) {
      socketService.sendMessage(roomId, newMessage.trim());
      setNewMessage('');

      // Stop typing indicator
      socketService.stopTyping(roomId);
      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setNewMessage(e.target.value);

    // Handle typing indicator
    socketService.startTyping(roomId);

    // Clear previous timeout
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }

    // Set new timeout to stop typing
    typingTimeoutRef.current = setTimeout(() => {
      socketService.stopTyping(roomId);
    }, 1000);
  };

  const formatTime = (date: Date) => {
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  if (!isOpen) {
    return (
      <div className="fixed bottom-4 right-4 z-50">
        <Button
          onClick={() => setIsOpen(true)}
          className="rounded-full w-14 h-14 bg-[#1C1A75] hover:bg-[#1C1A75]/90 shadow-lg"
          size="lg"
        >
          <MessageCircle className="h-6 w-6" />
        </Button>
        {onlineUsers.length > 0 && (
          <Badge className="absolute -top-2 -right-2 bg-green-500 text-white">
            {onlineUsers.length}
          </Badge>
        )}
      </div>
    );
  }

  return (
    <div className="fixed bottom-4 right-4 z-50">
      <Card className={`w-80 ${isMinimized ? 'h-14' : 'h-96'} shadow-xl border-2 border-[#D4AF37]`}>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium flex items-center gap-2">
            <MessageCircle className="h-4 w-4" />
            School Chat
            {onlineUsers.length > 0 && (
              <Badge variant="secondary" className="text-xs">
                {onlineUsers.length} online
              </Badge>
            )}
          </CardTitle>
          <div className="flex items-center gap-1">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setIsMinimized(!isMinimized)}
              className="h-6 w-6 p-0"
            >
              {isMinimized ? <Maximize2 className="h-3 w-3" /> : <Minimize2 className="h-3 w-3" />}
            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setIsOpen(false)}
              className="h-6 w-6 p-0"
            >
              <X className="h-3 w-3" />
            </Button>
          </div>
        </CardHeader>

        {!isMinimized && (
          <CardContent className="flex flex-col h-full p-0">
            <ScrollArea className="flex-1 p-4">
              <div className="space-y-3">
                {messages.length === 0 ? (
                  <div className="text-center text-gray-500 text-sm py-4">
                    No messages yet. Start the conversation!
                  </div>
                ) : (
                  messages.map((message) => (
                    <div
                      key={message.id}
                      className={`flex gap-2 ${message.userId === userId ? 'justify-end' : 'justify-start'}`}
                    >
                      {message.userId !== userId && (
                        <Avatar className="w-6 h-6">
                          <AvatarImage src={message.userAvatar} />
                          <AvatarFallback className="text-xs">
                            {message.userName.charAt(0).toUpperCase()}
                          </AvatarFallback>
                        </Avatar>
                      )}
                      <div
                        className={`max-w-[70%] rounded-lg px-3 py-2 text-sm ${
                          message.userId === userId
                            ? 'bg-[#1C1A75] text-white'
                            : 'bg-gray-100 text-gray-900'
                        }`}
                      >
                        {message.userId !== userId && (
                          <div className="font-medium text-xs mb-1">
                            {message.userName}
                          </div>
                        )}
                        <div>{message.message}</div>
                        <div className={`text-xs mt-1 ${
                          message.userId === userId ? 'text-blue-100' : 'text-gray-500'
                        }`}>
                          {formatTime(message.timestamp)}
                        </div>
                      </div>
                    </div>
                  ))
                )}
                {isTyping && (
                  <div className="flex gap-2 justify-start">
                    <Avatar className="w-6 h-6">
                      <AvatarFallback className="text-xs">?</AvatarFallback>
                    </Avatar>
                    <div className="bg-gray-100 rounded-lg px-3 py-2">
                      <div className="flex space-x-1">
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                      </div>
                    </div>
                  </div>
                )}
                <div ref={messagesEndRef} />
              </div>
            </ScrollArea>

            <div className="border-t p-3">
              <div className="flex gap-2">
                <Input
                  value={newMessage}
                  onChange={handleInputChange}
                  onKeyPress={handleKeyPress}
                  placeholder="Type a message..."
                  className="flex-1 text-sm"
                />
                <Button
                  onClick={handleSendMessage}
                  disabled={!newMessage.trim()}
                  size="sm"
                  className="bg-[#1C1A75] hover:bg-[#1C1A75]/90"
                >
                  <Send className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        )}
      </Card>
    </div>
  );
}

