    { value: 'grade-4', label: 'Grade 4 Parents' },
    { value: 'grade-5', label: 'Grade 5 Parents' },
    { value: 'grade-6', label: 'Grade 6 Parents' },
    { value: 'grade-7', label: 'Grade 7 Parents' },
    { value: 'boarding-parents', label: 'Boarding Students\' Parents' },
  ];

  const handleCreateCampaign = () => {
    if (!formData.name || !formData.subject || !formData.content || formData.recipientGroups.length === 0) {
      toast({
        title: "Missing Information",
        description: "Please fill in all required fields.",
        variant: "destructive",
      });
      return;
    }

    const newCampaign: EmailCampaign = {
      id: Date.now().toString(),
      name: formData.name,
      subject: formData.subject,
      content: formData.content,
      recipientGroups: formData.recipientGroups,
      status: formData.scheduledDate ? 'scheduled' : 'draft',
      scheduledDate: formData.scheduledDate ? new Date(formData.scheduledDate) : undefined,
      recipientCount: calculateRecipientCount(formData.recipientGroups),
    };

    setCampaigns(prev => [...prev, newCampaign]);
    setIsCreateDialogOpen(false);

    // Reset form
    setFormData({
      name: '',
      subject: '',
      content: '',
      recipientGroups: [],
      scheduledDate: '',
    });

    toast({
      title: "Campaign Created",
      description: `Email campaign "${newCampaign.name}" has been created.`,
    });
  };

  const calculateRecipientCount = (groups: string[]): number => {
    // Mock calculation - in real implementation, this would query the database
    const groupSizes: { [key: string]: number } = {
      'all-parents': 80,
      'all-students': 120,
      'new-parents': 15,
      'grade-1': 12,
      'grade-2': 15,
      'grade-3': 18,
      'grade-4': 20,
      'grade-5': 22,
      'grade-6': 18,
      'grade-7': 15,
      'boarding-parents': 25,
    };

    return groups.reduce((total, group) => total + (groupSizes[group] || 0), 0);
  };

  const handleSendCampaign = async (campaignId: string) => {
    const campaign = campaigns.find(c => c.id === campaignId);
    if (!campaign) return;

    // Update status to sending
    setCampaigns(prev =>
      prev.map(c =>
        c.id === campaignId
          ? { ...c, status: 'sending' as const }
          : c
      )
    );

    try {
      // Mock sending - in real implementation, this would send to all recipients
      await new Promise(resolve => setTimeout(resolve, 2000)); // Simulate API call

      // Update status to sent
      setCampaigns(prev =>
        prev.map(c =>
          c.id === campaignId
            ? { ...c, status: 'sent' as const, sentDate: new Date() }
            : c
        )
      );

      toast({
        title: "Campaign Sent",
        description: `Email campaign "${campaign.name}" has been sent to ${campaign.recipientCount} recipients.`,
      });
    } catch (error) {
      setCampaigns(prev =>
        prev.map(c =>
          c.id === campaignId
            ? { ...c, status: 'failed' as const }
            : c
        )
      );

      toast({
        title: "Campaign Failed",
        description: "Failed to send email campaign. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleDeleteCampaign = (campaignId: string) => {
    setCampaigns(prev => prev.filter(c => c.id !== campaignId));
    toast({
      title: "Campaign Deleted",
      description: "Email campaign has been deleted.",
    });
  };

  const getStatusColor = (status: EmailCampaign['status']) => {
    switch (status) {
      case 'draft': return 'bg-gray-100 text-gray-800';
      case 'scheduled': return 'bg-blue-100 text-blue-800';
      case 'sending': return 'bg-yellow-100 text-yellow-800';
      case 'sent': return 'bg-green-100 text-green-800';
      case 'failed': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status: EmailCampaign['status']) => {
    switch (status) {
      case 'sent': return <Send className="h-3 w-3" />;
      case 'scheduled': return <Calendar className="h-3 w-3" />;
      default: return <Mail className="h-3 w-3" />;
    }
  };

  if (userRole !== 'admin') {
    return (
      <Card>
        <CardContent className="text-center py-8">
          <Mail className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">Access Restricted</h3>
          <p className="text-gray-600">Only administrators can manage email campaigns.</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-[#1C1A75]">Email Campaigns</h2>
          <p className="text-gray-600">Create and manage automated email campaigns</p>
        </div>
        <Dialog open={isCreateDialogOpen} onOpenChange={setIsCreateDialogOpen}>
          <DialogTrigger asChild>
            <Button className="bg-[#1C1A75] hover:bg-[#1C1A75]/90">
              <Plus className="mr-2 h-4 w-4" />
              Create Campaign
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Create Email Campaign</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div>
                <Label htmlFor="campaignName">Campaign Name</Label>
                <Input
                  id="campaignName"
                  value={formData.name}
                  onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
                  placeholder="Enter campaign name"
                />
              </div>
              <div>
                <Label htmlFor="subject">Email Subject</Label>
                <Input
                  id="subject"
                  value={formData.subject}
                  onChange={(e) => setFormData(prev => ({ ...prev, subject: e.target.value }))}
                  placeholder="Enter email subject"
                />
              </div>
              <div>
                <Label htmlFor="content">Email Content</Label>
                <Textarea
                  id="content"
                  value={formData.content}
                  onChange={(e) => setFormData(prev => ({ ...prev, content: e.target.value }))}
                  placeholder="Enter email content (HTML supported)"
                  rows={8}
                />
              </div>
              <div>
                <Label>Recipient Groups</Label>
                <Select
                  value=""
                  onValueChange={(value) => {
                    if (!formData.recipientGroups.includes(value)) {
                      setFormData(prev => ({
                        ...prev,
                        recipientGroups: [...prev.recipientGroups, value]
                      }));
                    }
                  }}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select recipient groups" />
                  </SelectTrigger>
                  <SelectContent>
                    {recipientGroupOptions.map((group) => (
                      <SelectItem key={group.value} value={group.value}>
                        {group.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <div className="flex flex-wrap gap-2 mt-2">
                  {formData.recipientGroups.map((group) => {
                    const groupLabel = recipientGroupOptions.find(g => g.value === group)?.label;
                    return (
                      <Badge key={group} variant="secondary">
                        {groupLabel}
                        <button
                          onClick={() => setFormData(prev => ({
                            ...prev,
                            recipientGroups: prev.recipientGroups.filter(g => g !== group)
                          }))}
                          className="ml-1 text-xs hover:text-red-600"
                        >
                          ×
                        </button>
                      </Badge>
                    );
                  })}
                </div>
              </div>
              <div>
                <Label htmlFor="scheduledDate">Schedule Date (Optional)</Label>
                <Input
                  id="scheduledDate"
                  type="datetime-local"
                  value={formData.scheduledDate}
                  onChange={(e) => setFormData(prev => ({ ...prev, scheduledDate: e.target.value }))}
                />
              </div>
              <Button onClick={handleCreateCampaign} className="w-full bg-[#1C1A75] hover:bg-[#1C1A75]/90">
                Create Campaign
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <div className="grid gap-4">
        {campaigns.map((campaign) => (
          <Card key={campaign.id}>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="flex items-center gap-2">
                    <Mail className="h-5 w-5 text-[#1C1A75]" />
                    <div>
                      <CardTitle className="text-lg">{campaign.name}</CardTitle>
                      <CardDescription>{campaign.subject}</CardDescription>
                    </div>
                  </div>
                  <Badge className={getStatusColor(campaign.status)}>
                    {getStatusIcon(campaign.status)}
                    <span className="ml-1 capitalize">{campaign.status}</span>
                  </Badge>
                </div>
                <div className="flex items-center gap-2">
                  {campaign.status === 'draft' && (
                    <Button
                      size="sm"
                      onClick={() => handleSendCampaign(campaign.id)}
                      className="bg-[#1C1A75] hover:bg-[#1C1A75]/90"
                    >
                      <Send className="mr-1 h-3 w-3" />
                      Send Now
                    </Button>
                  )}
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => setSelectedCampaign(campaign)}
                  >
                    <Eye className="mr-1 h-3 w-3" />
                    View
                  </Button>
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => handleDeleteCampaign(campaign.id)}
                    className="text-red-600 border-red-600 hover:bg-red-50"
                  >
                    <Trash2 className="mr-1 h-3 w-3" />
                    Delete
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
                <div>
                  <p><strong>Recipients:</strong> {campaign.recipientCount}</p>
                  <p><strong>Groups:</strong> {campaign.recipientGroups.join(', ')}</p>
                </div>
                <div>
                  {campaign.sentDate && (
                    <p><strong>Sent:</strong> {format(campaign.sentDate, 'MMM d, yyyy HH:mm')}</p>
                  )}
                  {campaign.scheduledDate && (
                    <p><strong>Scheduled:</strong> {format(campaign.scheduledDate, 'MMM d, yyyy HH:mm')}</p>
                  )}
                </div>
                <div>
                  {campaign.openRate !== undefined && (
                    <p><strong>Open Rate:</strong> {campaign.openRate}%</p>
                  )}
                  {campaign.clickRate !== undefined && (
                    <p><strong>Click Rate:</strong> {campaign.clickRate}%</p>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        ))}

        {campaigns.length === 0 && (
          <Card>
            <CardContent className="text-center py-8">
              <Mail className="h-12 w-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No campaigns yet</h3>
              <p className="text-gray-600">Create your first email campaign to get started.</p>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Campaign Preview Dialog */}
      {selectedCampaign && (
        <Dialog open={!!selectedCampaign} onOpenChange={() => setSelectedCampaign(null)}>
          <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{selectedCampaign.name}</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div>
                <Label>Subject</Label>
                <p className="text-sm text-gray-600">{selectedCampaign.subject}</p>
              </div>
              <div>
                <Label>Content Preview</Label>
                <div className="border rounded-lg p-4 max-h-96 overflow-y-auto bg-gray-50">
                  <div dangerouslySetInnerHTML={{ __html: selectedCampaign.content }} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div>
                  <p><strong>Recipients:</strong> {selectedCampaign.recipientCount}</p>
                  <p><strong>Status:</strong> <span className="capitalize">{selectedCampaign.status}</span></p>
                </div>
                <div>
                  <p><strong>Groups:</strong> {selectedCampaign.recipientGroups.join(', ')}</p>
                  {selectedCampaign.sentDate && (
                    <p><strong>Sent:</strong> {format(selectedCampaign.sentDate, 'MMM d, yyyy HH:mm')}</p>
                  )}
                </div>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { logger } from '@/lib/logger';
import { TrendingUp, TrendingDown, Award, BookOpen, Users, Calendar, Filter, Download, Eye } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import lmsService from '@/services/lmsService';
import { format } from 'date-fns';
import {
  LineChart,
  Line,
  AreaChart,
  Area,
  BarChart,
  Bar,
  PieChart,
  Pie,
  Cell,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer
} from 'recharts';

interface GradeData {
  studentId: string;
  studentName: string;
  term: string;
  overallGrade: string;
  overallPercentage: number;
  gpa: number;
  classRank: number;
  totalStudents: number;
  subjects: SubjectGrade[];
  attendance: {
    present: number;
    absent: number;
    late: number;
    percentage: number;
  };
}

interface SubjectGrade {
  name: string;
  grade: string;
  percentage: number;
  rank: number;
  totalStudents: number;
  assignments: AssignmentGrade[];
  tests: TestGrade[];
  trend: 'up' | 'down' | 'stable';
}

interface AssignmentGrade {
  id: string;
  title: string;
  score: number;
  maxScore: number;
  percentage: number;
  date: Date;
  category: 'homework' | 'quiz' | 'project' | 'exam';
}

interface TestGrade {
  id: string;
  title: string;
  score: number;
  maxScore: number;
  percentage: number;
  date: Date;
  weight: number;
}

interface GradeBookProps {
  userRole?: 'student' | 'parent' | 'teacher' | 'admin';
  studentId?: string;
  studentName?: string;
}

export function GradeBook({
  userRole = 'student',
  studentId = 'student-123',
  studentName = 'John Smith'
}: GradeBookProps) {
  const [gradeData, setGradeData] = useState<GradeData | null>(null);
  const [selectedSubject, setSelectedSubject] = useState<string>('');
  const [selectedTerm, setSelectedTerm] = useState<string>('Term 2 2024');
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');
  const { toast } = useToast();

  useEffect(() => {
    loadGradeData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [studentId, selectedTerm]);

  const loadGradeData = async () => {
    setIsLoading(true);
    try {
      const result = await lmsService.getGrades(studentId);
      if (result.success) {
        setGradeData(result.data);
      }

      // Also load progress data for analytics
      const progressResult = await lmsService.getStudentProgress(studentId);
      if (progressResult.success) {
        // Combine grade and progress data for comprehensive analytics
        logger.debug('Progress data loaded');
      }
    } catch (error) {
      console.error('Error loading grade data:', error);
      toast({
        title: "Error",
        description: "Failed to load grade book data.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  // Mock comprehensive grade data for demonstration
  useEffect(() => {
    if (!gradeData) {
      const mockData: GradeData = {
        studentId,
        studentName,
        term: selectedTerm,
        overallGrade: 'A-',
        overallPercentage: 87.5,
        gpa: 3.7,
        classRank: 3,
        totalStudents: 25,
        subjects: [
          {
            name: 'Mathematics',
            grade: 'A',
            percentage: 92,
            rank: 3,
            totalStudents: 25,
            trend: 'up',
            assignments: [
              { id: '1', title: 'Chapter 5 Homework', score: 18, maxScore: 20, percentage: 90, date: new Date(Date.now() - 14 * 24 * 60 * 60 * 1000), category: 'homework' },
              { id: '2', title: 'Algebra Quiz', score: 45, maxScore: 50, percentage: 90, date: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000), category: 'quiz' },
              { id: '3', title: 'Mid-term Exam', score: 88, maxScore: 100, percentage: 88, date: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000), category: 'exam' },
            ],
            tests: [
              { id: '1', title: 'Unit Test 1', score: 85, maxScore: 100, percentage: 85, date: new Date(Date.now() - 21 * 24 * 60 * 60 * 1000), weight: 0.3 },
              { id: '2', title: 'Unit Test 2', score: 92, maxScore: 100, percentage: 92, date: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000), weight: 0.3 },
            ]
          },
          {
            name: 'English',
            grade: 'B+',
            percentage: 87,
            rank: 5,
            totalStudents: 25,
            trend: 'stable',
            assignments: [
              { id: '4', title: 'Essay Writing', score: 16, maxScore: 20, percentage: 80, date: new Date(Date.now() - 10 * 24 * 60 * 60 * 1000), category: 'project' },
              { id: '5', title: 'Reading Comprehension', score: 22, maxScore: 25, percentage: 88, date: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000), category: 'quiz' },
            ],
            tests: [
              { id: '3', title: 'Literature Exam', score: 78, maxScore: 100, percentage: 78, date: new Date(Date.now() - 14 * 24 * 60 * 60 * 1000), weight: 0.4 },
            ]
          },
          {
            name: 'Science',
            grade: 'A-',
            percentage: 89,
            rank: 4,
            totalStudents: 25,
            trend: 'up',
            assignments: [
              { id: '6', title: 'Lab Report', score: 19, maxScore: 20, percentage: 95, date: new Date(Date.now() - 12 * 24 * 60 * 60 * 1000), category: 'project' },
              { id: '7', title: 'Science Quiz', score: 23, maxScore: 25, percentage: 92, date: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000), category: 'quiz' },
            ],
            tests: [
              { id: '4', title: 'Science Mid-term', score: 82, maxScore: 100, percentage: 82, date: new Date(Date.now() - 10 * 24 * 60 * 60 * 1000), weight: 0.35 },
            ]
          }
        ],
        attendance: {
          present: 45,
          absent: 2,
          late: 1,
          percentage: 94
        }
      };
      setGradeData(mockData);
    }
  }, [studentId, studentName, selectedTerm, gradeData]);

  const getGradeColor = (grade: string) => {
    if (grade.startsWith('A')) return 'text-green-600 bg-green-100';
    if (grade.startsWith('B')) return 'text-blue-600 bg-blue-100';
    if (grade.startsWith('C')) return 'text-yellow-600 bg-yellow-100';
    if (grade.startsWith('D')) return 'text-orange-600 bg-orange-100';
    return 'text-red-600 bg-red-100';
  };

  const getTrendIcon = (trend: string) => {
    switch (trend) {
      case 'up': return <TrendingUp className="h-4 w-4 text-green-500" />;
      case 'down': return <TrendingDown className="h-4 w-4 text-red-500" />;
      default: return <div className="h-4 w-4" />;
    }
  };

  // Prepare chart data
  const performanceData = gradeData?.subjects.map(subject => ({
    subject: subject.name,
    percentage: subject.percentage,
    grade: subject.grade,
  })) || [];

  const attendanceData = [
    { name: 'Present', value: gradeData?.attendance.present || 0, color: '#10B981' },
    { name: 'Absent', value: gradeData?.attendance.absent || 0, color: '#EF4444' },
    { name: 'Late', value: gradeData?.attendance.late || 0, color: '#F59E0B' },
  ];

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#1C1A75]"></div>
        <span className="ml-2">Loading grade book...</span>
      </div>
    );
  }

  if (!gradeData) {
    return (
      <Card>
        <CardContent className="text-center py-8">
          <BookOpen className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No grade data available</h3>
          <p className="text-gray-600">Grade information will appear here once available.</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-[#1C1A75]">Grade Book & Analytics</h2>
          <p className="text-gray-600">Comprehensive academic performance tracking</p>
        </div>
        <div className="flex items-center gap-4">
          <Select value={selectedTerm} onValueChange={setSelectedTerm}>
            <SelectTrigger className="w-48">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Term 1 2024">Term 1 2024</SelectItem>
              <SelectItem value="Term 2 2024">Term 2 2024</SelectItem>
              <SelectItem value="Term 3 2024">Term 3 2024</SelectItem>
            </SelectContent>
          </Select>
          <Button variant="outline">
            <Download className="mr-2 h-4 w-4" />
            Export Report
          </Button>
        </div>
      </div>

      {/* Overview Cards */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Overall Grade</CardTitle>
            <Award className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{gradeData.overallGrade}</div>
            <p className="text-xs text-muted-foreground">
              {gradeData.overallPercentage}% average
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">GPA</CardTitle>
            <TrendingUp className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{gradeData.gpa}</div>
            <p className="text-xs text-muted-foreground">
              Out of 4.0 scale
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Class Rank</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">#{gradeData.classRank}</div>
            <p className="text-xs text-muted-foreground">
              Out of {gradeData.totalStudents} students
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Attendance</CardTitle>
            <Calendar className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{gradeData.attendance.percentage}%</div>
            <p className="text-xs text-muted-foreground">
              {gradeData.attendance.present} days present
            </p>
          </CardContent>
        </Card>
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="overview">Overview</TabsTrigger>
          <TabsTrigger value="subjects">Subject Details</TabsTrigger>
          <TabsTrigger value="analytics">Analytics</TabsTrigger>
          <TabsTrigger value="attendance">Attendance</TabsTrigger>
        </TabsList>

        <TabsContent value="overview" className="space-y-4">
          <div className="grid gap-4 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Subject Performance</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {gradeData.subjects.map((subject) => (
                    <div key={subject.name} className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <span className="font-medium">{subject.name}</span>
                        {getTrendIcon(subject.trend)}
                      </div>
                      <div className="flex items-center gap-2">
                        <Badge className={getGradeColor(subject.grade)}>
                          {subject.grade}
                        </Badge>
                        <span className="text-sm text-gray-600">{subject.percentage}%</span>
                      </div>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Recent Assignments</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {gradeData.subjects
                    .flatMap(subject => subject.assignments)
                    .sort((a, b) => b.date.getTime() - a.date.getTime())
                    .slice(0, 5)
                    .map((assignment) => (
                      <div key={assignment.id} className="flex items-center justify-between">
                        <div>
                          <p className="font-medium text-sm">{assignment.title}</p>
                          <p className="text-xs text-gray-600">
                            {format(assignment.date, 'MMM d')} • {assignment.category}
                          </p>
                        </div>
                        <Badge variant="outline">
                          {assignment.percentage}%
                        </Badge>
                      </div>
                    ))}
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="subjects" className="space-y-4">
          <div className="flex items-center gap-4 mb-4">
            <Select value={selectedSubject} onValueChange={setSelectedSubject}>
              <SelectTrigger className="w-64">
                <SelectValue placeholder="Select subject for details" />
              </SelectTrigger>
              <SelectContent>
                {gradeData.subjects.map((subject) => (
                  <SelectItem key={subject.name} value={subject.name}>
                    {subject.name} ({subject.grade})
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {selectedSubject && (() => {
            const subject = gradeData.subjects.find(s => s.name === selectedSubject);
            if (!subject) return null;

            return (
              <div className="grid gap-4 md:grid-cols-2">
                <Card>
                  <CardHeader>
                    <CardTitle>{subject.name} Performance</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <span>Overall Grade</span>
                        <Badge className={getGradeColor(subject.grade)}>
                          {subject.grade} ({subject.percentage}%)
                        </Badge>
                      </div>
                      <div className="flex items-center justify-between">
                        <span>Class Rank</span>
                        <span>#{subject.rank} of {subject.totalStudents}</span>
                      </div>
                      <Progress value={subject.percentage} className="h-2" />
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader>
                    <CardTitle>Assignment Breakdown</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-3">
                      {subject.assignments.map((assignment) => (
                        <div key={assignment.id} className="flex items-center justify-between">
                          <div>
                            <p className="font-medium text-sm">{assignment.title}</p>
                            <p className="text-xs text-gray-600">
                              {format(assignment.date, 'MMM d')} • {assignment.category}
                            </p>
                          </div>
                          <Badge variant="outline">
                            {assignment.score}/{assignment.maxScore} ({assignment.percentage}%)
                          </Badge>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              </div>
            );
          })()}
        </TabsContent>

        <TabsContent value="analytics" className="space-y-4">
          <div className="grid gap-6 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Subject Performance</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={performanceData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="subject" />
                    <YAxis domain={[0, 100]} />
                    <Tooltip />
                    <Bar dataKey="percentage" fill="#1C1A75" />
                  </BarChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Attendance Breakdown</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300}>
                  <PieChart>
                    <Pie
                      data={attendanceData}
                      cx="50%"
                      cy="50%"
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="value"
                      label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                    >
                      {attendanceData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Performance Trend</CardTitle>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={300}>
                <LineChart data={performanceData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="subject" />
                  <YAxis domain={[0, 100]} />
                  <Tooltip />
                  <Line type="monotone" dataKey="percentage" stroke="#1C1A75" strokeWidth={2} />
                </LineChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="attendance" className="space-y-4">
          <div className="grid gap-4 md:grid-cols-3">
            <Card>
              <CardHeader>
                <CardTitle className="text-green-600">Present</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-3xl font-bold text-green-600">{gradeData.attendance.present}</div>
                <p className="text-sm text-gray-600">Days attended</p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="text-red-600">Absent</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-3xl font-bold text-red-600">{gradeData.attendance.absent}</div>
                <p className="text-sm text-gray-600">Days missed</p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="text-yellow-600">Late</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-3xl font-bold text-yellow-600">{gradeData.attendance.late}</div>
                <p className="text-sm text-gray-600">Late arrivals</p>
              </CardContent>
            </Card>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Attendance Rate</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <span>Overall Attendance</span>
                  <span className="font-bold">{gradeData.attendance.percentage}%</span>
                </div>
                <Progress value={gradeData.attendance.percentage} className="h-3" />
                <p className="text-sm text-gray-600">
                  Based on {gradeData.attendance.present + gradeData.attendance.absent} school days
                </p>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import React from 'react';
import { Languages } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';

const languages = [
  { code: 'en', name: 'English', flag: '🇺🇸' },
  { code: 'sh', name: 'Shona', flag: '🇿🇼' },
  { code: 'nd', name: 'Ndebele', flag: '🇿🇼' },
];

export function LanguageToggle() {
  const { i18n } = useTranslation();

  const currentLanguage = languages.find(lang => lang.code === i18n.language) || languages[0];

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="sm"
          className="h-9 w-9 px-0 text-white hover:bg-white/10 hover:text-[#D4AF37] transition-colors"
          aria-label="Toggle language"
        >
          <Languages className="h-4 w-4" />
          <span className="sr-only">Toggle language</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700">
        {languages.map((language) => (
          <DropdownMenuItem
            key={language.code}
            onClick={() => i18n.changeLanguage(language.code)}
            className={`cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700 ${
              i18n.language === language.code ? 'bg-gray-50 dark:bg-gray-700' : ''
            }`}
          >
            <span className="mr-2">{language.flag}</span>
            <span>{language.name}</span>
            {i18n.language === language.code && (
              <span className="ml-auto text-[#D4AF37]">✓</span>
            )}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import React, { useState, useEffect } from 'react';
import { BookOpen, Play, FileText, Download, CheckCircle, Clock, Users, Award, MessageSquare, Calendar } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import lmsService from '@/services/lmsService';
import { format } from 'date-fns';

interface Course {
  id: string;
  title: string;
  description: string;
  teacher: string;
  enrolledStudents: number;
  lessons: number;
  progress: number;
}

interface Assignment {
  id: string;
  title: string;
  course: string;
  dueDate: Date;
  status: 'pending' | 'in-progress' | 'submitted' | 'graded';
  description: string;
  points: number;
}

interface LearningPlatformProps {
  studentId?: string;
  studentName?: string;
}

export function LearningPlatform({
  studentId = 'student-123',
  studentName = 'John Smith'
}: LearningPlatformProps) {
  const [courses, setCourses] = useState<Course[]>([]);
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [selectedCourse, setSelectedCourse] = useState<Course | null>(null);
  const [courseContent, setCourseContent] = useState<any>(null);
  const [activeTab, setActiveTab] = useState('courses');
  const [isLoading, setIsLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [studentId]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      // Load courses
      const coursesResult = await lmsService.getCourses(studentId);
      if (coursesResult.success) {
        setCourses(coursesResult.data);
      }

      // Load assignments
      const assignmentsResult = await lmsService.getAssignments(studentId);
      if (assignmentsResult.success) {
        setAssignments(assignmentsResult.data);
      }
    } catch (error) {
      console.error('Error loading LMS data:', error);
      toast({
        title: "Error",
        description: "Failed to load learning platform data.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const loadCourseContent = async (courseId: string) => {
    try {
      const result = await lmsService.getCourseContent(courseId);
      if (result.success) {
        setCourseContent(result.data);
      }
    } catch (error) {
      console.error('Error loading course content:', error);
    }
  };

  const handleAssignmentSubmit = async (assignmentId: string, file: File) => {
    try {
      const result = await lmsService.submitAssignment(assignmentId, file, studentId);
      if (result.success) {
        toast({
          title: "Assignment Submitted",
          description: "Your assignment has been submitted successfully.",
        });

        // Update assignment status
        setAssignments(prev =>
          prev.map(assignment =>
            assignment.id === assignmentId
              ? { ...assignment, status: 'submitted' as const }
              : assignment
          )
        );
      }
    } catch (error) {
      toast({
        title: "Submission Failed",
        description: "Failed to submit assignment. Please try again.",
        variant: "destructive",
      });
    }
  };

  const getStatusColor = (status: Assignment['status']) => {
    switch (status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'in-progress': return 'bg-blue-100 text-blue-800';
      case 'submitted': return 'bg-green-100 text-green-800';
      case 'graded': return 'bg-purple-100 text-purple-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status: Assignment['status']) => {
    switch (status) {
      case 'submitted': return <CheckCircle className="h-3 w-3" />;
      case 'graded': return <Award className="h-3 w-3" />;
      case 'in-progress': return <Clock className="h-3 w-3" />;
      default: return <FileText className="h-3 w-3" />;
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#1C1A75]"></div>
        <span className="ml-2">Loading learning platform...</span>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-[#1C1A75]">Online Learning Platform</h2>
          <p className="text-gray-600">Access your courses, assignments, and learning resources</p>
        </div>
        <Badge variant="secondary" className="text-sm">
          Welcome back, {studentName}
        </Badge>
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="courses">My Courses</TabsTrigger>
          <TabsTrigger value="assignments">Assignments</TabsTrigger>
          <TabsTrigger value="progress">Progress</TabsTrigger>
          <TabsTrigger value="resources">Resources</TabsTrigger>
        </TabsList>

        <TabsContent value="courses" className="space-y-4">
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {courses.map((course) => (
              <Card key={course.id} className="cursor-pointer hover:shadow-lg transition-shadow">
                <CardHeader>
                  <div className="flex items-center justify-between">
                    <CardTitle className="text-lg">{course.title}</CardTitle>
                    <Badge variant="outline">{course.progress}%</Badge>
                  </div>
                  <CardDescription>{course.description}</CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="space-y-3">
                    <div className="flex items-center justify-between text-sm text-gray-600">
                      <span>Teacher: {course.teacher}</span>
                      <span>{course.lessons} lessons</span>
                    </div>
                    <div>
                      <div className="flex justify-between text-sm mb-1">
                        <span>Progress</span>
                        <span>{course.progress}%</span>
                      </div>
                      <Progress value={course.progress} className="h-2" />
                    </div>
                    <Button
                      className="w-full"
                      onClick={() => {
                        setSelectedCourse(course);
                        loadCourseContent(course.id);
                      }}
                    >
                      <BookOpen className="mr-2 h-4 w-4" />
                      Continue Learning
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </TabsContent>

        <TabsContent value="assignments" className="space-y-4">
          <div className="grid gap-4">
            {assignments.map((assignment) => (
              <Card key={assignment.id}>
                <CardHeader>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <FileText className="h-5 w-5 text-[#1C1A75]" />
                      <div>
                        <CardTitle className="text-lg">{assignment.title}</CardTitle>
                        <CardDescription>{assignment.course}</CardDescription>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge className={getStatusColor(assignment.status)}>
                        {getStatusIcon(assignment.status)}
                        <span className="ml-1 capitalize">{assignment.status}</span>
                      </Badge>
                      <span className="text-sm text-gray-500">
                        {assignment.points} points
                      </span>
                    </div>
                  </div>
                </CardHeader>
                <CardContent>
                  <p className="text-sm text-gray-700 mb-3">{assignment.description}</p>
                  <div className="flex items-center justify-between">
                    <span className="text-sm text-gray-600">
                      Due: {format(assignment.dueDate, 'MMM d, yyyy')}
                    </span>
                    {assignment.status !== 'submitted' && assignment.status !== 'graded' && (
                      <Dialog>
                        <DialogTrigger asChild>
                          <Button size="sm">
                            Submit Assignment
                          </Button>
                        </DialogTrigger>
                        <DialogContent>
                          <DialogHeader>
                            <DialogTitle>Submit Assignment</DialogTitle>
                          </DialogHeader>
                          <div className="space-y-4">
                            <p className="text-sm text-gray-600">
                              Upload your completed assignment file below.
                            </p>
                            <input
                              type="file"
                              accept=".pdf,.doc,.docx,.txt"
                              onChange={(e) => {
                                const file = e.target.files?.[0];
                                if (file) {
                                  handleAssignmentSubmit(assignment.id, file);
                                }
                              }}
                              className="w-full p-2 border rounded-lg"
                            />
                          </div>
                        </DialogContent>
                      </Dialog>
                    )}
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </TabsContent>

        <TabsContent value="progress" className="space-y-4">
          <div className="grid gap-6 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Overall Progress</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-center">
                  <div className="text-3xl font-bold text-[#1C1A75] mb-2">76%</div>
                  <Progress value={76} className="mb-4" />
                  <p className="text-sm text-gray-600">Keep up the great work!</p>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Achievements</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  <div className="flex items-center gap-3">
                    <Award className="h-8 w-8 text-yellow-500" />
                    <div>
                      <p className="font-medium">Math Whiz</p>
                      <p className="text-sm text-gray-600">Completed 80% of mathematics course</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <Award className="h-8 w-8 text-blue-500" />
                    <div>
                      <p className="font-medium">Speed Reader</p>
                      <p className="text-sm text-gray-600">Completed 10 reading assignments</p>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="resources" className="space-y-4">
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Download className="h-5 w-5" />
                  Mathematics Resources
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  <Button variant="outline" className="w-full justify-start">
                    <FileText className="mr-2 h-4 w-4" />
                    Formula Sheet (PDF)
                  </Button>
                  <Button variant="outline" className="w-full justify-start">
                    <Play className="mr-2 h-4 w-4" />
                    Video Tutorial
                  </Button>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Download className="h-5 w-5" />
                  Science Resources
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  <Button variant="outline" className="w-full justify-start">
                    <FileText className="mr-2 h-4 w-4" />
                    Lab Safety Guide (PDF)
                  </Button>
                  <Button variant="outline" className="w-full justify-start">
                    <Play className="mr-2 h-4 w-4" />
                    Experiment Videos
                  </Button>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Download className="h-5 w-5" />
                  English Resources
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  <Button variant="outline" className="w-full justify-start">
                    <FileText className="mr-2 h-4 w-4" />
                    Literature Guide (PDF)
                  </Button>
                  <Button variant="outline" className="w-full justify-start">
                    <MessageSquare className="mr-2 h-4 w-4" />
                    Discussion Forum
                  </Button>
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>

      {/* Course Content Modal */}
      {selectedCourse && courseContent && (
        <Dialog open={!!selectedCourse} onOpenChange={() => setSelectedCourse(null)}>
          <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{selectedCourse.title}</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="grid gap-4">
                {courseContent.modules?.map((module: any) => (
                  <Card key={module.id}>
                    <CardHeader>
                      <CardTitle className="text-lg">{module.title}</CardTitle>
                    </CardHeader>
                    <CardContent>
                      <div className="space-y-2">
                        {module.lessons?.map((lesson: any) => (
                          <div key={lesson.id} className="flex items-center justify-between p-3 border rounded-lg">
                            <div className="flex items-center gap-3">
                              {lesson.type === 'video' ? (
                                <Play className="h-5 w-5 text-blue-500" />
                              ) : (
                                <FileText className="h-5 w-5 text-gray-500" />
                              )}
                              <div>
                                <p className="font-medium">{lesson.title}</p>
                                <p className="text-sm text-gray-600">
                                  {Math.floor(lesson.duration / 60)} minutes
                                </p>
                              </div>
                            </div>
                            <div className="flex items-center gap-2">
                              {lesson.completed && (
                                <CheckCircle className="h-5 w-5 text-green-500" />
                              )}
                              <Button size="sm" variant={lesson.completed ? "outline" : "default"}>
                                {lesson.completed ? 'Review' : 'Start'}
                              </Button>
                            </div>
                          </div>
                        ))}
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </div>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Calendar, Clock, User, MessageSquare, Video, CheckCircle, XCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { format, addDays, startOfDay } from 'date-fns';

interface Meeting {
  id: string;
  parentName: string;
  parentEmail: string;
  teacherName: string;
  studentName: string;
  date: Date;
  time: string;
  duration: number;
  topic: string;
  status: 'pending' | 'confirmed' | 'completed' | 'cancelled';
  meetingType: 'in-person' | 'virtual';
  notes?: string;
}

interface MeetingSchedulerProps {
  userRole?: 'parent' | 'teacher' | 'admin';
  userName?: string;
  userEmail?: string;
}

export function MeetingScheduler({
  userRole = 'parent',
  userName = 'Anonymous User',
  userEmail = 'user@example.com'
}: MeetingSchedulerProps) {
  const [meetings, setMeetings] = useState<Meeting[]>([]);
  const [isBookingDialogOpen, setIsBookingDialogOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [selectedTime, setSelectedTime] = useState('');
  const [duration, setDuration] = useState(30);
  const [topic, setTopic] = useState('');
  const [teacher, setTeacher] = useState('');
  const [studentName, setStudentName] = useState('');
  const [meetingType, setMeetingType] = useState<'in-person' | 'virtual'>('virtual');
  const [notes, setNotes] = useState('');
  const { toast } = useToast();

  // Mock data for demonstration
  useEffect(() => {
    const mockMeetings: Meeting[] = [
      {
        id: '1',
        parentName: 'John Smith',
        parentEmail: 'john@example.com',
        teacherName: 'Mrs. Johnson',
        studentName: 'Sarah Smith',
        date: addDays(new Date(), 2),
        time: '14:00',
        duration: 30,
        topic: 'Progress Review',
        status: 'confirmed',
        meetingType: 'virtual',
        notes: 'Discussing Sarah\'s recent test results'
      },
      {
        id: '2',
        parentName: 'Mary Davis',
        parentEmail: 'mary@example.com',
        teacherName: 'Mr. Brown',
        studentName: 'Michael Davis',
        date: addDays(new Date(), 5),
        time: '10:00',
        duration: 45,
        topic: 'Behavioral Concerns',
        status: 'pending',
        meetingType: 'in-person',
        notes: 'Recent behavioral issues in class'
      }
    ];
    setMeetings(mockMeetings);
  }, []);

  const availableTimes = [
    '08:00', '08:30', '09:00', '09:30', '10:00', '10:30',
    '11:00', '11:30', '12:00', '13:00', '13:30', '14:00',
    '14:30', '15:00', '15:30', '16:00'
  ];

  const teachers = [
    'Mrs. Johnson (Grade 1)',
    'Mr. Brown (Grade 2)',
    'Ms. Davis (Grade 3)',
    'Mr. Wilson (Grade 4)',
    'Mrs. Garcia (Grade 5)',
    'Mr. Lee (Grade 6)',
    'Ms. Taylor (Grade 7)'
  ];

  const handleBookMeeting = () => {
    if (!selectedDate || !selectedTime || !topic || !teacher || !studentName) {
      toast({
        title: "Missing Information",
        description: "Please fill in all required fields.",
        variant: "destructive",
      });
      return;
    }

    const newMeeting: Meeting = {
      id: Date.now().toString(),
      parentName: userName,
      parentEmail: userEmail,
      teacherName: teacher,
      studentName,
      date: selectedDate,
      time: selectedTime,
      duration,
      topic,
      status: 'pending',
      meetingType,
      notes,
    };

    setMeetings(prev => [...prev, newMeeting]);
    setIsBookingDialogOpen(false);

    // Reset form
    setSelectedDate(new Date());
    setSelectedTime('');
    setDuration(30);
    setTopic('');
    setTeacher('');
    setStudentName('');
    setMeetingType('virtual');
    setNotes('');

    toast({
      title: "Meeting Requested",
      description: "Your meeting request has been submitted and is pending approval.",
    });
  };

  const updateMeetingStatus = (meetingId: string, status: Meeting['status']) => {
    setMeetings(prev =>
      prev.map(meeting =>
        meeting.id === meetingId
          ? { ...meeting, status }
          : meeting
      )
    );

    toast({
      title: "Meeting Updated",
      description: `Meeting status changed to ${status}.`,
    });
  };

  const getStatusColor = (status: Meeting['status']) => {
    switch (status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'confirmed': return 'bg-green-100 text-green-800';
      case 'completed': return 'bg-blue-100 text-blue-800';
      case 'cancelled': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status: Meeting['status']) => {
    switch (status) {
      case 'confirmed': return <CheckCircle className="h-4 w-4" />;
      case 'cancelled': return <XCircle className="h-4 w-4" />;
      default: return <Clock className="h-4 w-4" />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-[#1C1A75]">Parent-Teacher Meetings</h2>
          <p className="text-gray-600">Schedule and manage your parent-teacher conferences</p>
        </div>
        <Dialog open={isBookingDialogOpen} onOpenChange={setIsBookingDialogOpen}>
          <DialogTrigger asChild>
            <Button className="bg-[#1C1A75] hover:bg-[#1C1A75]/90">
              <Calendar className="mr-2 h-4 w-4" />
              Schedule Meeting
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>Schedule Parent-Teacher Meeting</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div>
                <Label htmlFor="studentName">Student Name</Label>
                <Input
                  id="studentName"
                  value={studentName}
                  onChange={(e) => setStudentName(e.target.value)}
                  placeholder="Enter student's full name"
                />
              </div>
              <div>
                <Label htmlFor="teacher">Teacher</Label>
                <Select value={teacher} onValueChange={setTeacher}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select teacher" />
                  </SelectTrigger>
                  <SelectContent>
                    {teachers.map((t) => (
                      <SelectItem key={t} value={t}>{t}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label htmlFor="date">Preferred Date</Label>
                <Input
                  id="date"
                  type="date"
                  value={format(selectedDate, 'yyyy-MM-dd')}
                  onChange={(e) => setSelectedDate(new Date(e.target.value))}
                  min={format(new Date(), 'yyyy-MM-dd')}
                />
              </div>
              <div>
                <Label htmlFor="time">Preferred Time</Label>
                <Select value={selectedTime} onValueChange={setSelectedTime}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select time" />
                  </SelectTrigger>
                  <SelectContent>
                    {availableTimes.map((time) => (
                      <SelectItem key={time} value={time}>{time}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label htmlFor="duration">Duration (minutes)</Label>
                <Select value={duration.toString()} onValueChange={(value) => setDuration(parseInt(value))}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="15">15 minutes</SelectItem>
                    <SelectItem value="30">30 minutes</SelectItem>
                    <SelectItem value="45">45 minutes</SelectItem>
                    <SelectItem value="60">60 minutes</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label htmlFor="meetingType">Meeting Type</Label>
                <Select value={meetingType} onValueChange={(value: 'in-person' | 'virtual') => setMeetingType(value)}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="virtual">Virtual (Video Call)</SelectItem>
                    <SelectItem value="in-person">In-Person</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label htmlFor="topic">Topic</Label>
                <Input
                  id="topic"
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  placeholder="Brief description of the meeting topic"
                />
              </div>
              <div>
                <Label htmlFor="notes">Additional Notes (Optional)</Label>
                <Textarea
                  id="notes"
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Any additional information or concerns"
                  rows={3}
                />
              </div>
              <Button onClick={handleBookMeeting} className="w-full bg-[#1C1A75] hover:bg-[#1C1A75]/90">
                Request Meeting
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <div className="grid gap-4">
        {meetings.map((meeting) => (
          <Card key={meeting.id}>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="flex items-center gap-2">
                    {meeting.meetingType === 'virtual' ? (
                      <Video className="h-5 w-5 text-blue-500" />
                    ) : (
                      <User className="h-5 w-5 text-green-500" />
                    )}
                    <CardTitle className="text-lg">{meeting.topic}</CardTitle>
                  </div>
                  <Badge className={getStatusColor(meeting.status)}>
                    {getStatusIcon(meeting.status)}
                    <span className="ml-1 capitalize">{meeting.status}</span>
                  </Badge>
                </div>
                {userRole === 'teacher' && meeting.status === 'pending' && (
                  <div className="flex gap-2">
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => updateMeetingStatus(meeting.id, 'confirmed')}
                      className="text-green-600 border-green-600 hover:bg-green-50"
                    >
                      Confirm
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => updateMeetingStatus(meeting.id, 'cancelled')}
                      className="text-red-600 border-red-600 hover:bg-red-50"
                    >
                      Decline
                    </Button>
                  </div>
                )}
              </div>
              <CardDescription>
                {format(meeting.date, 'EEEE, MMMM d, yyyy')} at {meeting.time} ({meeting.duration} minutes)
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                <div>
                  <p><strong>Student:</strong> {meeting.studentName}</p>
                  <p><strong>Parent:</strong> {meeting.parentName}</p>
                  <p><strong>Teacher:</strong> {meeting.teacherName}</p>
                </div>
                <div>
                  <p><strong>Type:</strong> {meeting.meetingType === 'virtual' ? 'Virtual Meeting' : 'In-Person Meeting'}</p>
                  {meeting.notes && (
                    <div className="mt-2">
                      <p><strong>Notes:</strong></p>
                      <p className="text-gray-600">{meeting.notes}</p>
                    </div>
                  )}
                </div>
              </div>
              {meeting.status === 'confirmed' && meeting.meetingType === 'virtual' && (
                <div className="mt-4">
                  <Button className="bg-[#1C1A75] hover:bg-[#1C1A75]/90">
                    <Video className="mr-2 h-4 w-4" />
                    Join Meeting
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>
        ))}

        {meetings.length === 0 && (
          <Card>
            <CardContent className="text-center py-8">
              <Calendar className="h-12 w-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No meetings scheduled</h3>
              <p className="text-gray-600">Schedule your first parent-teacher meeting to get started.</p>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { logger } from '@/lib/logger';
import { Bell, BellOff, Settings } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';

export function NotificationManager() {
  const [isSupported, setIsSupported] = useState(false);
  const [isSubscribed, setIsSubscribed] = useState(false);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const { toast } = useToast();

  useEffect(() => {
    // Check if notifications are supported
    if ('Notification' in window && 'serviceWorker' in navigator) {
      setIsSupported(true);
      setPermission(Notification.permission);

      // Check if already subscribed
      checkSubscriptionStatus();
    }
  }, []);

  const checkSubscriptionStatus = async () => {
    try {
      const registration = await navigator.serviceWorker.ready;
      const subscription = await registration.pushManager.getSubscription();
      setIsSubscribed(!!subscription);
    } catch (error) {
      logger.error('Error checking subscription status', error);
    }
  };

  const requestPermission = async () => {
    try {
      const result = await Notification.requestPermission();
      setPermission(result);

      if (result === 'granted') {
        toast({
          title: "Notifications enabled",
          description: "You'll now receive updates from Regisbridge School.",
        });
        await subscribeToNotifications();
      } else {
        toast({
          title: "Notifications blocked",
          description: "Please enable notifications in your browser settings.",
          variant: "destructive",
        });
      }
    } catch (error) {
      logger.error('Error requesting permission', error);
      toast({
        title: "Error",
        description: "Failed to enable notifications.",
        variant: "destructive",
      });
    }
  };

  const subscribeToNotifications = async () => {
    try {
      const registration = await navigator.serviceWorker.ready;

      // You'll need to replace this with your actual VAPID public key
      const vapidPublicKey = 'BKxQzBJh8ZQG6VdJfR8pQ8nZJGwQy8zJGwQy8zJGwQy8zJGwQy8zJGwQy8zJGwQy8zJGwQy8zJGwQy8zJGwQy8z';

      const subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(vapidPublicKey)
      });

      // Here you would send the subscription to your server
  logger.debug('Push subscription object received');

      setIsSubscribed(true);
      toast({
        title: "Subscribed to notifications",
        description: "You'll receive important updates and announcements.",
      });
    } catch (error) {
      logger.error('Error subscribing to notifications', error);
      toast({
        title: "Subscription failed",
        description: "Unable to subscribe to push notifications.",
        variant: "destructive",
      });
    }
  };

  const unsubscribeFromNotifications = async () => {
    try {
      const registration = await navigator.serviceWorker.ready;
      const subscription = await registration.pushManager.getSubscription();

      if (subscription) {
        await subscription.unsubscribe();
        setIsSubscribed(false);
        toast({
          title: "Unsubscribed",
          description: "You will no longer receive push notifications.",
        });
      }
    } catch (error) {
      logger.error('Error unsubscribing from notifications', error);
      toast({
        title: "Error",
        description: "Failed to unsubscribe from notifications.",
        variant: "destructive",
      });
    }
  };

  const handleToggle = async (checked: boolean) => {
    if (checked) {
      if (permission === 'default') {
        await requestPermission();
      } else if (permission === 'granted') {
        await subscribeToNotifications();
      }
    } else {
      await unsubscribeFromNotifications();
    }
  };

  // Helper function to convert VAPID key
  function urlBase64ToUint8Array(base64String: string) {
    const padding = '='.repeat((4 - base64String.length % 4) % 4);
    const base64 = (base64String + padding)
      .replace(/-/g, '+')
      .replace(/_/g, '/');

    const rawData = window.atob(base64);
    const outputArray = new Uint8Array(rawData.length);

    for (let i = 0; i < rawData.length; ++i) {
      outputArray[i] = rawData.charCodeAt(i);
    }
    return outputArray;
  }

  if (!isSupported) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <BellOff className="h-5 w-5" />
            Notifications Not Supported
          </CardTitle>
          <CardDescription>
            Push notifications are not supported in this browser.
          </CardDescription>
        </CardHeader>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Bell className="h-5 w-5" />
          Push Notifications
        </CardTitle>
        <CardDescription>
          Stay updated with school announcements, events, and important notices.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex items-center justify-between">
          <Label htmlFor="notifications" className="text-sm font-medium">
            Enable push notifications
          </Label>
          <Switch
            id="notifications"
            checked={isSubscribed}
            onCheckedChange={handleToggle}
            disabled={permission === 'denied'}
          />
        </div>

        {permission === 'denied' && (
          <p className="text-sm text-red-600">
            Notifications are blocked. Please enable them in your browser settings.
          </p>
        )}

        {permission === 'default' && (
          <p className="text-sm text-gray-600">
            Click the toggle to enable notifications and stay connected with school updates.
          </p>
        )}

        {isSubscribed && (
          <div className="flex items-center gap-2 text-sm text-green-600">
            <Bell className="h-4 w-4" />
            You're subscribed to notifications
          </div>
        )}
      </CardContent>
    </Card>
  );
}

'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { logger } from '@/lib/logger';
import { Download, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';

interface BeforeInstallPromptEvent extends Event {
  readonly platforms: string[];
  readonly userChoice: Promise<{
    outcome: 'accepted' | 'dismissed';
    platform: string;
  }>;
  prompt(): Promise<void>;
}

// Configuration constants
const COOLDOWN_MS = 7 * 24 * 60 * 60 * 1000; // 7 days
const SHOW_DELAY_MS = 3000; // 3 seconds

export function PWAInstallPrompt() {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [showPrompt, setShowPrompt] = useState(false);
  const [isInstalled, setIsInstalled] = useState(false);
  const [cooldownActive, setCooldownActive] = useState(false);
  const previouslyFocused = useRef<HTMLElement | null>(null);
  const installButtonRef = useRef<HTMLButtonElement | null>(null);

  useEffect(() => {
    // Check if already installed
    const isStandalone = window.matchMedia('(display-mode: standalone)').matches;
    const isInWebAppiOS = (window.navigator as any).standalone === true;

    if (isStandalone || isInWebAppiOS) {
      setIsInstalled(true);
      return;
    }

    // Respect dismissal cooldown (7 days)
    try {
      const dismissedAt = localStorage.getItem('pwa-prompt-dismissed');
      if (dismissedAt) {
        const elapsed = Date.now() - Number(dismissedAt);
        if (elapsed < COOLDOWN_MS) {
          setCooldownActive(true);
          return; // Skip wiring listeners if on cooldown
        }
      }
    } catch {
      // Intentionally empty: localStorage may not be available (private mode, SSR)
    }

    let timeoutId: number | undefined;

    // Listen for the beforeinstallprompt event
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);

      // Show prompt after a delay to not be too intrusive
      timeoutId = window.setTimeout(() => {
        setShowPrompt(true);
      }, SHOW_DELAY_MS);
    };

    // Listen for successful installation
    const handleAppInstalled = () => {
      setIsInstalled(true);
      setShowPrompt(false);
      setDeferredPrompt(null);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt, { once: true } as any);
    window.addEventListener('appinstalled', handleAppInstalled);

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt as any);
      window.removeEventListener('appinstalled', handleAppInstalled);
      if (timeoutId) window.clearTimeout(timeoutId);
    };
  }, []);

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;

    try {
      await deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;

      if (outcome === 'accepted') {
        logger.info('PWA install prompt accepted');
      } else {
        logger.info('PWA install prompt dismissed');
      }

      setDeferredPrompt(null);
      setShowPrompt(false);
    } catch (error) {
      logger.error('Install prompt failed', error);
    }
  };

  const handleDismiss = () => {
    setShowPrompt(false);
    // Store dismissal to avoid showing again for some time
    try {
      localStorage.setItem('pwa-prompt-dismissed', Date.now().toString());
    } catch {
      // Intentionally empty: localStorage may not be available (private mode, SSR)
    }
    // Restore focus to prior element for accessibility
    previouslyFocused.current?.focus?.();
  };

  // When prompt becomes visible, capture previous focus and move focus into dialog
  useEffect(() => {
    if (showPrompt && !isInstalled && !cooldownActive) {
      previouslyFocused.current = (document.activeElement as HTMLElement) || null;
      // Focus the install button for quick keyboard access
      installButtonRef.current?.focus();
    }
  }, [showPrompt, isInstalled, cooldownActive]);

  // Escape key handling
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      handleDismiss();
    }
  }, []);

  // Don't show if already installed or dismissed recently
  if (isInstalled || !showPrompt || cooldownActive) {
    return null;
  }

  return (
    <div
      className="fixed bottom-4 right-4 z-50 max-w-sm"
      role="dialog"
      aria-modal="true"
      aria-labelledby="pwa-install-title"
      aria-describedby="pwa-install-description"
      onKeyDown={handleKeyDown}
    >
      <Card className="shadow-lg border-2 border-[#D4AF37]" tabIndex={-1}>
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between">
            <CardTitle id="pwa-install-title" className="text-lg flex items-center gap-2">
              <Download className="h-5 w-5 text-[#1C1A75]" />
              Install App
            </CardTitle>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleDismiss}
              className="h-6 w-6 p-0"
              aria-label="Dismiss install prompt"
            >
              <X className="h-4 w-4" />
            </Button>
          </div>
          <CardDescription id="pwa-install-description">
            Install Regisbridge School app for a better experience with offline access and quick access from your home screen.
          </CardDescription>
        </CardHeader>
        <CardContent className="pt-0">
          <Button
            onClick={handleInstallClick}
            className="w-full bg-[#1C1A75] hover:bg-[#1C1A75]/90 text-white"
            ref={installButtonRef}
            aria-label="Install the Regisbridge School application"
          >
            <Download className="mr-2 h-4 w-4" />
            Install Now
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

