interface SMSMessage {
  id: string;
  recipient: string;
  message: string;
  status: 'pending' | 'sent' | 'delivered' | 'failed';
  sentDate?: Date;
  messageId?: string;
  cost?: number;
}

interface SMSManagerProps {
  userRole?: 'admin' | 'teacher';
}

export function SMSManager({ userRole = 'admin' }: SMSManagerProps) {
  const [messages, setMessages] = useState<SMSMessage[]>([]);
  const [isComposeDialogOpen, setIsComposeDialogOpen] = useState(false);
  const [selectedMessage, setSelectedMessage] = useState<SMSMessage | null>(null);
  const [formData, setFormData] = useState({
    recipient: '',
    message: '',
    recipientGroup: '',
  });
  const [isBulkMode, setIsBulkMode] = useState(false);
  const [bulkRecipients, setBulkRecipients] = useState('');
  const { toast } = useToast();

  // Mock data for demonstration
  useEffect(() => {
    const mockMessages: SMSMessage[] = [
      {
        id: '1',
        recipient: '+263771234567',
        message: 'Your meeting "Progress Review" with Mrs. Johnson is scheduled for tomorrow at 14:00.',
        status: 'delivered',
        sentDate: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000),
        messageId: 'SM123456789',
        cost: 0.05,
      },
      {
        id: '2',
        recipient: '+263781234567',
        message: 'Sports Day is this Friday! Please arrive by 8:30 AM.',
        status: 'sent',
        sentDate: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000),
        messageId: 'SM987654321',
        cost: 0.05,
      },
      {
        id: '3',
        recipient: '+263791234567',
        message: 'Payment reminder: School fees due by end of month.',
        status: 'failed',
        sentDate: new Date(),
        cost: 0,
      }
    ];
    setMessages(mockMessages);
  }, []);

  const recipientGroups = [
    { value: 'all-parents', label: 'All Parents', count: 80 },
    { value: 'all-students', label: 'All Students', count: 120 },
    { value: 'grade-1', label: 'Grade 1 Parents', count: 12 },
    { value: 'grade-2', label: 'Grade 2 Parents', count: 15 },
    { value: 'grade-3', label: 'Grade 3 Parents', count: 18 },
    { value: 'grade-4', label: 'Grade 4 Parents', count: 20 },
    { value: 'grade-5', label: 'Grade 5 Parents', count: 22 },
    { value: 'grade-6', label: 'Grade 6 Parents', count: 18 },
    { value: 'grade-7', label: 'Grade 7 Parents', count: 15 },
    { value: 'boarding-parents', label: 'Boarding Students\' Parents', count: 25 },
  ];

  const handleSendSMS = async () => {
    if (!formData.recipient && !formData.recipientGroup && !isBulkMode) {
      toast({
        title: "Missing Recipient",
        description: "Please enter a recipient or select a group.",
        variant: "destructive",
      });
      return;
    }

    if (!formData.message.trim()) {
      toast({
        title: "Missing Message",
        description: "Please enter a message.",
        variant: "destructive",
      });
      return;
    }

    try {
      let recipients: string[] = [];

      if (isBulkMode && bulkRecipients) {
        recipients = bulkRecipients.split('\n').filter(r => r.trim());
      } else if (formData.recipientGroup) {
        // Mock recipient list for selected group
        const groupSize = recipientGroups.find(g => g.value === formData.recipientGroup)?.count || 0;
        recipients = Array.from({ length: groupSize }, (_, i) => `+26377${1000000 + i}`);
      } else {
        recipients = [formData.recipient];
      }

      // Send SMS to each recipient
      const results: SMSMessage[] = [];
      for (const recipient of recipients) {
        const formattedRecipient = smsService.formatPhoneNumber(recipient);
        const result = await smsService.sendSMS(formattedRecipient, formData.message);

        const newMessage: SMSMessage = {
          id: Date.now().toString() + Math.random(),
          recipient: formattedRecipient,
          message: formData.message,
          status: result.success ? 'sent' : 'failed',
          sentDate: new Date(),
          messageId: result.messageId,
        };

        results.push(newMessage);
      }

      setMessages(prev => [...prev, ...results]);
      setIsComposeDialogOpen(false);

      // Reset form
      setFormData({
        recipient: '',
        message: '',
        recipientGroup: '',
      });
      setBulkRecipients('');

      toast({
        title: "SMS Sent",
        description: `Message sent to ${recipients.length} recipient(s).`,
      });
    } catch (error) {
      toast({
        title: "SMS Failed",
        description: "Failed to send SMS. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleDeleteMessage = (messageId: string) => {
    setMessages(prev => prev.filter(m => m.id !== messageId));
    toast({
      title: "Message Deleted",
      description: "SMS message has been deleted.",
    });
  };

  const getStatusColor = (status: SMSMessage['status']) => {
    switch (status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'sent': return 'bg-blue-100 text-blue-800';
      case 'delivered': return 'bg-green-100 text-green-800';
      case 'failed': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status: SMSMessage['status']) => {
    switch (status) {
      case 'delivered': return <MessageSquare className="h-3 w-3" />;
      case 'sent': return <Send className="h-3 w-3" />;
      case 'failed': return <Phone className="h-3 w-3" />;
      default: return <MessageSquare className="h-3 w-3" />;
    }
  };

  if (userRole !== 'admin') {
    return (
      <Card>
        <CardContent className="text-center py-8">
          <MessageSquare className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">Access Restricted</h3>
          <p className="text-gray-600">Only administrators can manage SMS communications.</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-[#1C1A75]">SMS Notifications</h2>
          <p className="text-gray-600">Send SMS notifications to parents and students</p>
        </div>
        <Dialog open={isComposeDialogOpen} onOpenChange={setIsComposeDialogOpen}>
          <DialogTrigger asChild>
            <Button className="bg-[#1C1A75] hover:bg-[#1C1A75]/90">
              <Plus className="mr-2 h-4 w-4" />
              Compose SMS
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Compose SMS Message</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="flex items-center space-x-2">
                <input
                  type="checkbox"
                  id="bulkMode"
                  checked={isBulkMode}
                  onChange={(e) => setIsBulkMode(e.target.checked)}
                  className="rounded"
                />
                <Label htmlFor="bulkMode">Bulk SMS Mode</Label>
              </div>

              {!isBulkMode ? (
                <>
                  <div>
                    <Label htmlFor="recipient">Recipient Phone Number</Label>
                    <Input
                      id="recipient"
                      value={formData.recipient}
                      onChange={(e) => setFormData(prev => ({ ...prev, recipient: e.target.value }))}
                      placeholder="+263771234567"
                    />
                  </div>
                  <div>
                    <Label htmlFor="recipientGroup">Or Select Group</Label>
                    <Select value={formData.recipientGroup} onValueChange={(value) => setFormData(prev => ({ ...prev, recipientGroup: value }))}>
                      <SelectTrigger>
                        <SelectValue placeholder="Select recipient group" />
                      </SelectTrigger>
                      <SelectContent>
                        {recipientGroups.map((group) => (
                          <SelectItem key={group.value} value={group.value}>
                            {group.label} ({group.count} recipients)
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </>
              ) : (
                <div>
                  <Label htmlFor="bulkRecipients">Recipient Phone Numbers (one per line)</Label>
                  <Textarea
                    id="bulkRecipients"
                    value={bulkRecipients}
                    onChange={(e) => setBulkRecipients(e.target.value)}
                    placeholder="+263771234567&#10;+263781234567&#10;+263791234567"
                    rows={6}
                  />
                </div>
              )}

              <div>
                <Label htmlFor="message">Message</Label>
                <Textarea
                  id="message"
                  value={formData.message}
                  onChange={(e) => setFormData(prev => ({ ...prev, message: e.target.value }))}
                  placeholder="Enter your SMS message (160 characters max for single SMS)"
                  rows={4}
                  maxLength={160}
                />
                <p className="text-sm text-gray-500 mt-1">
                  {formData.message.length}/160 characters
                </p>
              </div>

              <Button onClick={handleSendSMS} className="w-full bg-[#1C1A75] hover:bg-[#1C1A75]/90">
                <Send className="mr-2 h-4 w-4" />
                Send SMS
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <div className="grid gap-4">
        {messages.map((message) => (
          <Card key={message.id}>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="flex items-center gap-2">
                    <MessageSquare className="h-5 w-5 text-[#1C1A75]" />
                    <div>
                      <CardTitle className="text-lg">{message.recipient}</CardTitle>
                      <CardDescription>
                        {message.sentDate ? format(message.sentDate, 'MMM d, yyyy HH:mm') : 'Not sent'}
                      </CardDescription>
                    </div>
                  </div>
                  <Badge className={getStatusColor(message.status)}>
                    {getStatusIcon(message.status)}
                    <span className="ml-1 capitalize">{message.status}</span>
                  </Badge>
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => setSelectedMessage(message)}
                  >
                    <Eye className="mr-1 h-3 w-3" />
                    View
                  </Button>
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => handleDeleteMessage(message.id)}
                    className="text-red-600 border-red-600 hover:bg-red-50"
                  >
                    <Trash2 className="mr-1 h-3 w-3" />
                    Delete
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-gray-700 mb-2">{message.message}</p>
              <div className="flex justify-between text-xs text-gray-500">
                <span>Message ID: {message.messageId}</span>
                {message.cost && <span>Cost: ${message.cost}</span>}
              </div>
            </CardContent>
          </Card>
        ))}

        {messages.length === 0 && (
          <Card>
            <CardContent className="text-center py-8">
              <MessageSquare className="h-12 w-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No SMS messages yet</h3>
              <p className="text-gray-600">Send your first SMS notification to get started.</p>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Message Preview Dialog */}
      {selectedMessage && (
        <Dialog open={!!selectedMessage} onOpenChange={() => setSelectedMessage(null)}>
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>SMS Message Details</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div>
                <Label>Recipient</Label>
                <p className="text-sm text-gray-600">{selectedMessage.recipient}</p>
              </div>
              <div>
                <Label>Message</Label>
                <div className="bg-gray-50 p-3 rounded-lg">
                  <p className="text-sm">{selectedMessage.message}</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div>
                  <p><strong>Status:</strong> <span className="capitalize">{selectedMessage.status}</span></p>
                  <p><strong>Sent:</strong> {selectedMessage.sentDate ? format(selectedMessage.sentDate, 'MMM d, yyyy HH:mm') : 'Not sent'}</p>
                </div>
                <div>
                  <p><strong>Message ID:</strong> {selectedMessage.messageId}</p>
                  {selectedMessage.cost && <p><strong>Cost:</strong> ${selectedMessage.cost}</p>}
                </div>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Calendar, Clock, BookOpen, CheckCircle, Circle, Plus, Edit, Trash2, Target, TrendingUp, AlertTriangle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { useToast } from '@/hooks/use-toast';
import { format, addDays, startOfWeek, endOfWeek, eachDayOfInterval, isSameDay } from 'date-fns';

interface StudyTask {
  id: string;
  title: string;
  description: string;
  subject: string;
  priority: 'low' | 'medium' | 'high';
  status: 'pending' | 'in-progress' | 'completed';
  dueDate: Date;
  estimatedTime: number; // in minutes
  actualTime?: number;
  createdDate: Date;
  completedDate?: Date;
  tags: string[];
}

interface StudySession {
  id: string;
  date: Date;
  startTime: string;
  endTime: string;
  tasks: string[]; // task IDs
  completed: boolean;
  notes?: string;
}

interface StudyPlannerProps {
  studentId?: string;
  studentName?: string;
}

export function StudyPlanner({
  studentId = 'student-123',
  studentName = 'John Smith'
}: StudyPlannerProps) {
  const [tasks, setTasks] = useState<StudyTask[]>([]);
  const [sessions, setSessions] = useState<StudySession[]>([]);
  const [isTaskDialogOpen, setIsTaskDialogOpen] = useState(false);
  const [isSessionDialogOpen, setIsSessionDialogOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [selectedTask, setSelectedTask] = useState<StudyTask | null>(null);
  const [formData, setFormData] = useState<{
    title: string;
    description: string;
    subject: string;
    priority: 'low' | 'medium' | 'high';
    dueDate: string;
    estimatedTime: number;
    tags: string;
  }>({
    title: '',
    description: '',
    subject: '',
    priority: 'medium',
    dueDate: '',
    estimatedTime: 60,
    tags: '',
  });
  const [sessionFormData, setSessionFormData] = useState({
    date: format(new Date(), 'yyyy-MM-dd'),
    startTime: '19:00',
    endTime: '20:00',
    notes: '',
  });
  const { toast } = useToast();

  // Mock data for demonstration
  useEffect(() => {
    const mockTasks: StudyTask[] = [
      {
        id: '1',
        title: 'Complete Mathematics Chapter 5',
        description: 'Review quadratic equations and practice problems',
        subject: 'Mathematics',
        priority: 'high',
        status: 'in-progress',
        dueDate: addDays(new Date(), 2),
        estimatedTime: 90,
        actualTime: 45,
        createdDate: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000),
        tags: ['math', 'chapter5', 'quadratic'],
      },
      {
        id: '2',
        title: 'Write English Essay',
        description: 'Essay on Shakespeare\'s influence on modern literature',
        subject: 'English',
        priority: 'medium',
        status: 'pending',
        dueDate: addDays(new Date(), 5),
        estimatedTime: 120,
        createdDate: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000),
        tags: ['english', 'essay', 'shakespeare'],
      },
      {
        id: '3',
        title: 'Science Lab Report',
        description: 'Document findings from photosynthesis experiment',
        subject: 'Science',
        priority: 'high',
        status: 'completed',
        dueDate: addDays(new Date(), 1),
        estimatedTime: 60,
        actualTime: 75,
        createdDate: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000),
        completedDate: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000),
        tags: ['science', 'lab', 'photosynthesis'],
      }
    ];

    const mockSessions: StudySession[] = [
      {
        id: '1',
        date: new Date(),
        startTime: '19:00',
        endTime: '20:30',
        tasks: ['1'],
        completed: true,
        notes: 'Good progress on math problems',
      },
      {
        id: '2',
        date: addDays(new Date(), 1),
        startTime: '18:30',
        endTime: '20:00',
        tasks: ['2'],
        completed: false,
      }
    ];

    setTasks(mockTasks);
    setSessions(mockSessions);
  }, []);

  const subjects = [
    'Mathematics',
    'English',
    'Science',
    'Social Studies',
    'History',
    'Geography',
    'Art',
    'Music',
    'Physical Education',
  ];

  const handleCreateTask = () => {
    if (!formData.title || !formData.subject || !formData.dueDate) {
      toast({
        title: "Missing Information",
        description: "Please fill in all required fields.",
        variant: "destructive",
      });
      return;
    }

    const newTask: StudyTask = {
      id: Date.now().toString(),
      title: formData.title,
      description: formData.description,
      subject: formData.subject,
      priority: formData.priority,
      status: 'pending',
      dueDate: new Date(formData.dueDate),
      estimatedTime: formData.estimatedTime,
      createdDate: new Date(),
      tags: formData.tags.split(',').map(tag => tag.trim()).filter(tag => tag),
    };

    setTasks(prev => [...prev, newTask]);
    setIsTaskDialogOpen(false);

    // Reset form
    setFormData({
      title: '',
      description: '',
      subject: '',
      priority: 'medium',
      dueDate: '',
      estimatedTime: 60,
      tags: '',
    });

    toast({
      title: "Task Created",
      description: `Study task "${newTask.title}" has been added to your planner.`,
    });
  };

  const handleCreateSession = () => {
    if (!sessionFormData.startTime || !sessionFormData.endTime) {
      toast({
        title: "Missing Information",
        description: "Please set start and end times for the study session.",
        variant: "destructive",
      });
      return;
    }

    const newSession: StudySession = {
      id: Date.now().toString(),
      date: new Date(sessionFormData.date),
      startTime: sessionFormData.startTime,
      endTime: sessionFormData.endTime,
      tasks: [],
      completed: false,
      notes: sessionFormData.notes,
    };

    setSessions(prev => [...prev, newSession]);
    setIsSessionDialogOpen(false);

    // Reset form
    setSessionFormData({
      date: format(new Date(), 'yyyy-MM-dd'),
      startTime: '19:00',
      endTime: '20:00',
      notes: '',
    });

    toast({
      title: "Study Session Created",
      description: "Study session has been scheduled.",
    });
  };

  const updateTaskStatus = (taskId: string, status: StudyTask['status']) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId
          ? {
              ...task,
              status,
              completedDate: status === 'completed' ? new Date() : task.completedDate
            }
          : task
      )
    );

    if (status === 'completed') {
      toast({
        title: "Task Completed",
        description: "Great job! Task marked as completed.",
      });
    }
  };

  const deleteTask = (taskId: string) => {
    setTasks(prev => prev.filter(task => task.id !== taskId));
    toast({
      title: "Task Deleted",
      description: "Study task has been removed.",
    });
  };

  const getPriorityColor = (priority: StudyTask['priority']) => {
    switch (priority) {
      case 'high': return 'bg-red-100 text-red-800';
      case 'medium': return 'bg-yellow-100 text-yellow-800';
      case 'low': return 'bg-green-100 text-green-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusIcon = (status: StudyTask['status']) => {
    switch (status) {
      case 'completed': return <CheckCircle className="h-4 w-4 text-green-500" />;
      case 'in-progress': return <Clock className="h-4 w-4 text-blue-500" />;
      default: return <Circle className="h-4 w-4 text-gray-400" />;
    }
  };

  const getTasksForDate = (date: Date) => {
    return tasks.filter(task =>
      isSameDay(task.dueDate, date) || isSameDay(task.createdDate, date)
    );
  };

  const getSessionsForDate = (date: Date) => {
    return sessions.filter(session => isSameDay(session.date, date));
  };

  const weekStart = startOfWeek(selectedDate);
  const weekEnd = endOfWeek(selectedDate);
  const weekDays = eachDayOfInterval({ start: weekStart, end: weekEnd });

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(task => task.status === 'completed').length;
  const inProgressTasks = tasks.filter(task => task.status === 'in-progress').length;
  const overdueTasks = tasks.filter(task =>
    task.status !== 'completed' && task.dueDate < new Date()
  ).length;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-[#1C1A75]">Study Planner</h2>
          <p className="text-gray-600">Organize your study schedule and track progress</p>
        </div>
        <div className="flex gap-2">
          <Dialog open={isTaskDialogOpen} onOpenChange={setIsTaskDialogOpen}>
            <DialogTrigger asChild>
              <Button className="bg-[#1C1A75] hover:bg-[#1C1A75]/90">
                <Plus className="mr-2 h-4 w-4" />
                Add Task
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-md">
              <DialogHeader>
                <DialogTitle>Create Study Task</DialogTitle>
              </DialogHeader>
              <div className="space-y-4">
                <div>
                  <Label htmlFor="taskTitle">Task Title</Label>
                  <Input
                    id="taskTitle"
                    value={formData.title}
                    onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
                    placeholder="Enter task title"
                  />
                </div>
                <div>
                  <Label htmlFor="taskSubject">Subject</Label>
                  <Select value={formData.subject} onValueChange={(value) => setFormData(prev => ({ ...prev, subject: value }))}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select subject" />
                    </SelectTrigger>
                    <SelectContent>
                      {subjects.map((subject) => (
                        <SelectItem key={subject} value={subject}>{subject}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label htmlFor="taskDescription">Description</Label>
                  <Textarea
                    id="taskDescription"
                    value={formData.description}
                    onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                    placeholder="Task description"
                    rows={3}
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <Label htmlFor="taskPriority">Priority</Label>
                    <Select value={formData.priority} onValueChange={(value: 'low' | 'medium' | 'high') => setFormData(prev => ({ ...prev, priority: value }))}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="low">Low</SelectItem>
                        <SelectItem value="medium">Medium</SelectItem>
                        <SelectItem value="high">High</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div>
                    <Label htmlFor="estimatedTime">Estimated Time (minutes)</Label>
                    <Input
                      id="estimatedTime"
                      type="number"
                      value={formData.estimatedTime}
                      onChange={(e) => setFormData(prev => ({ ...prev, estimatedTime: parseInt(e.target.value) || 60 }))}
                    />
                  </div>
                </div>
                <div>
                  <Label htmlFor="taskDueDate">Due Date</Label>
                  <Input
                    id="taskDueDate"
                    type="date"
                    value={formData.dueDate}
                    onChange={(e) => setFormData(prev => ({ ...prev, dueDate: e.target.value }))}
                  />
                </div>
                <div>
                  <Label htmlFor="taskTags">Tags (comma-separated)</Label>
                  <Input
                    id="taskTags"
                    value={formData.tags}
                    onChange={(e) => setFormData(prev => ({ ...prev, tags: e.target.value }))}
                    placeholder="math, chapter5, important"
                  />
                </div>
                <Button onClick={handleCreateTask} className="w-full bg-[#1C1A75] hover:bg-[#1C1A75]/90">
                  Create Task
                </Button>
              </div>
            </DialogContent>
          </Dialog>

          <Dialog open={isSessionDialogOpen} onOpenChange={setIsSessionDialogOpen}>
            <DialogTrigger asChild>
              <Button variant="outline">
                <Calendar className="mr-2 h-4 w-4" />
                Schedule Session
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-md">
              <DialogHeader>
                <DialogTitle>Schedule Study Session</DialogTitle>
              </DialogHeader>
              <div className="space-y-4">
                <div>
                  <Label htmlFor="sessionDate">Date</Label>
                  <Input
                    id="sessionDate"
                    type="date"
                    value={sessionFormData.date}
                    onChange={(e) => setSessionFormData(prev => ({ ...prev, date: e.target.value }))}
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <Label htmlFor="startTime">Start Time</Label>
                    <Input
                      id="startTime"
                      type="time"
                      value={sessionFormData.startTime}
                      onChange={(e) => setSessionFormData(prev => ({ ...prev, startTime: e.target.value }))}
                    />
                  </div>
                  <div>
                    <Label htmlFor="endTime">End Time</Label>
                    <Input
                      id="endTime"
                      type="time"
                      value={sessionFormData.endTime}
                      onChange={(e) => setSessionFormData(prev => ({ ...prev, endTime: e.target.value }))}
                    />
                  </div>
                </div>
                <div>
                  <Label htmlFor="sessionNotes">Notes (Optional)</Label>
                  <Textarea
                    id="sessionNotes"
                    value={sessionFormData.notes}
                    onChange={(e) => setSessionFormData(prev => ({ ...prev, notes: e.target.value }))}
                    placeholder="Session notes or goals"
                    rows={3}
                  />
                </div>
                <Button onClick={handleCreateSession} className="w-full bg-[#1C1A75] hover:bg-[#1C1A75]/90">
                  Schedule Session
                </Button>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {/* Overview Cards */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Tasks</CardTitle>
            <BookOpen className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{totalTasks}</div>
            <p className="text-xs text-muted-foreground">
              Active study tasks
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Completed</CardTitle>
            <CheckCircle className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{completedTasks}</div>
            <p className="text-xs text-muted-foreground">
              {Math.round((completedTasks / totalTasks) * 100)}% completion rate
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">In Progress</CardTitle>
            <Clock className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-blue-600">{inProgressTasks}</div>
            <p className="text-xs text-muted-foreground">
              Currently working on
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Overdue</CardTitle>
            <AlertTriangle className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-red-600">{overdueTasks}</div>
            <p className="text-xs text-muted-foreground">
              Need attention
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Weekly Calendar View */}
      <Card>
        <CardHeader>
          <CardTitle>Weekly Study Schedule</CardTitle>
          <CardDescription>
            Week of {format(weekStart, 'MMMM d')} - {format(weekEnd, 'MMMM d, yyyy')}
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-7 gap-2">
            {weekDays.map((day) => {
              const dayTasks = getTasksForDate(day);
              const daySessions = getSessionsForDate(day);
              const isToday = isSameDay(day, new Date());

              return (
                <div
                  key={day.toISOString()}
                  className={`min-h-32 p-2 border rounded-lg ${
                    isToday ? 'border-[#1C1A75] bg-blue-50' : 'border-gray-200'
                  }`}
                >
                  <div className="font-medium text-sm mb-2">
                    {format(day, 'EEE d')}
                  </div>

                  {/* Sessions for this day */}
                  {daySessions.map((session) => (
                    <div key={session.id} className="mb-2 p-2 bg-purple-100 rounded text-xs">
                      <div className="font-medium">{session.startTime} - {session.endTime}</div>
                      {session.notes && (
                        <div className="text-gray-600 truncate">{session.notes}</div>
                      )}
                    </div>
                  ))}

                  {/* Tasks for this day */}
                  {dayTasks.slice(0, 3).map((task) => (
                    <div key={task.id} className="mb-1 p-1 bg-gray-100 rounded text-xs">
                      <div className="flex items-center gap-1">
                        {getStatusIcon(task.status)}
                        <span className="truncate">{task.title}</span>
                      </div>
                    </div>
                  ))}

                  {dayTasks.length > 3 && (
                    <div className="text-xs text-gray-500">
                      +{dayTasks.length - 3} more
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      {/* Tasks List */}
      <Card>
        <CardHeader>
          <CardTitle>Study Tasks</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {tasks.map((task) => (
              <div key={task.id} className="flex items-center justify-between p-4 border rounded-lg">
                <div className="flex items-center gap-3">
                  <button
                    onClick={() => updateTaskStatus(task.id, task.status === 'completed' ? 'pending' : 'completed')}
                    className="text-gray-400 hover:text-green-500"
                  >
                    {getStatusIcon(task.status)}
                  </button>
                  <div className="flex-1">
                    <h3 className="font-medium">{task.title}</h3>
                    <p className="text-sm text-gray-600">{task.description}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <Badge variant="outline">{task.subject}</Badge>
                      <Badge className={getPriorityColor(task.priority)}>
                        {task.priority} priority
                      </Badge>
                      <span className="text-xs text-gray-500">
                        Due: {format(task.dueDate, 'MMM d')}
                      </span>
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => updateTaskStatus(task.id, 'in-progress')}
                    disabled={task.status === 'completed'}
                  >
                    {task.status === 'in-progress' ? 'In Progress' : 'Start'}
                  </Button>
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => deleteTask(task.id)}
                    className="text-red-600 border-red-600 hover:bg-red-50"
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            ))}

            {tasks.length === 0 && (
              <div className="text-center py-8">
                <BookOpen className="h-12 w-12 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900 mb-2">No study tasks yet</h3>
                <p className="text-gray-600">Create your first study task to get organized.</p>
              </div>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Video, VideoOff, Mic, MicOff, Phone, PhoneOff, Users, Settings, Share } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { isBrowser } from '@/lib/platform';

interface Participant {
  id: string;
  name: string;
  avatar?: string;
  isMuted: boolean;
  isVideoOn: boolean;
  isHost: boolean;
}

interface VideoConferenceProps {
  roomId?: string;
  userName?: string;
  userId?: string;
  onClose?: () => void;
}

export function VideoConference({
  roomId = 'default-room',
  userName = 'Anonymous User',
  userId = 'anonymous',
  onClose
}: VideoConferenceProps) {
  const [isConnected, setIsConnected] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOn, setIsVideoOn] = useState(true);
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const [participants, setParticipants] = useState<Participant[]>([]);
  const [meetingId, setMeetingId] = useState('');
  const [meetingPassword, setMeetingPassword] = useState('');
  const [isJoinDialogOpen, setIsJoinDialogOpen] = useState(true);
  const [selectedCamera, setSelectedCamera] = useState('');
  const [selectedMicrophone, setSelectedMicrophone] = useState('');
  const [cameras, setCameras] = useState<MediaDeviceInfo[]>([]);
  const [microphones, setMicrophones] = useState<MediaDeviceInfo[]>([]);

  const localVideoRef = useRef<HTMLVideoElement>(null);
  const remoteVideoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const { toast } = useToast();

  useEffect(() => {
    // Get available devices (only in browser)
    if (isBrowser()) {
      getDevices();
    }

    // Initialize current user as participant
    setParticipants([{
      id: userId,
      name: userName,
      isMuted: false,
      isVideoOn: true,
      isHost: true,
    }]);

    return () => {
      // Cleanup
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, [userId, userName]);

  const getDevices = async () => {
    if (!isBrowser()) return;
    try {
      const devices = await navigator.mediaDevices.enumerateDevices();
      setCameras(devices.filter(device => device.kind === 'videoinput'));
      setMicrophones(devices.filter(device => device.kind === 'audioinput'));

      // Set defaults
      const defaultCamera = devices.find(device => device.kind === 'videoinput');
      const defaultMic = devices.find(device => device.kind === 'audioinput');

      if (defaultCamera) setSelectedCamera(defaultCamera.deviceId);
      if (defaultMic) setSelectedMicrophone(defaultMic.deviceId);
    } catch (error) {
      console.error('Error getting devices:', error);
    }
  };

  const startLocalStream = async () => {
    if (!isBrowser()) {
      toast({
        title: 'Unavailable',
        description: 'Media devices are not available in this environment.',
        variant: 'destructive',
      });
      return;
    }

    try {
      const constraints = {
        video: isVideoOn ? { deviceId: selectedCamera ? { exact: selectedCamera } : undefined } : false,
        audio: !isMuted ? { deviceId: selectedMicrophone ? { exact: selectedMicrophone } : undefined } : false,
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      streamRef.current = stream;

      if (localVideoRef.current) {
        localVideoRef.current.srcObject = stream;
      }

      setIsConnected(true);
      toast({
        title: 'Connected to meeting',
        description: 'You are now in the video conference.',
      });
    } catch (error) {
      console.error('Error starting stream:', error);
      toast({
        title: 'Connection failed',
        description: 'Unable to access camera or microphone.',
        variant: 'destructive',
      });
    }
  };

  const stopLocalStream = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }

    if (localVideoRef.current) {
      localVideoRef.current.srcObject = null;
    }

    setIsConnected(false);
  };

  const toggleMute = () => {
    if (streamRef.current) {
      const audioTracks = streamRef.current.getAudioTracks();
      audioTracks.forEach(track => {
        track.enabled = isMuted;
      });
    }
    setIsMuted(!isMuted);
  };

  const toggleVideo = async () => {
    if (!isBrowser()) return;

    if (!isVideoOn) {
      // Turn video on
      try {
        const constraints = {
          video: { deviceId: selectedCamera ? { exact: selectedCamera } : undefined }
        };
        const stream = await navigator.mediaDevices.getUserMedia(constraints);
        const videoTrack = stream.getVideoTracks()[0];

        if (streamRef.current) {
          const existingAudioTrack = streamRef.current.getAudioTracks()[0];
          if (existingAudioTrack) {
            streamRef.current.addTrack(videoTrack);
          } else {
            streamRef.current = new MediaStream([videoTrack]);
          }
        } else {
          streamRef.current = new MediaStream([videoTrack]);
        }

        if (localVideoRef.current) {
          localVideoRef.current.srcObject = streamRef.current;
        }
      } catch (error) {
        console.error('Error turning video on:', error);
        return;
      }
    } else {
      // Turn video off
      if (streamRef.current) {
        const videoTracks = streamRef.current.getVideoTracks();
        videoTracks.forEach(track => {
          track.stop();
          streamRef.current!.removeTrack(track);
        });
      }
    }

    setIsVideoOn(!isVideoOn);
  };

  const toggleScreenShare = async () => {
    if (!isBrowser()) return;

    try {
      if (!isScreenSharing) {
        const screenStream = await navigator.mediaDevices.getDisplayMedia({
          video: true,
          audio: false,
        });

        // Replace video track with screen share
        if (streamRef.current) {
          const videoTracks = streamRef.current.getVideoTracks();
          videoTracks.forEach(track => {
            streamRef.current!.removeTrack(track);
            track.stop();
          });

          const screenTrack = screenStream.getVideoTracks()[0];
          streamRef.current.addTrack(screenTrack);

          if (localVideoRef.current) {
            localVideoRef.current.srcObject = streamRef.current;
          }
        }

        setIsScreenSharing(true);
        toast({
          title: "Screen sharing started",
          description: "Others can now see your screen.",
        });
      } else {
        // Stop screen sharing and restore camera
        if (streamRef.current) {
          const screenTracks = streamRef.current.getVideoTracks();
          screenTracks.forEach(track => {
            streamRef.current!.removeTrack(track);
            track.stop();
          });

          // Try to restore camera
          if (isVideoOn) {
            const cameraStream = await navigator.mediaDevices.getUserMedia({
              video: { deviceId: selectedCamera ? { exact: selectedCamera } : undefined }
            });
            const cameraTrack = cameraStream.getVideoTracks()[0];
            streamRef.current.addTrack(cameraTrack);
          }
        }

        setIsScreenSharing(false);
        toast({
          title: "Screen sharing stopped",
          description: "Returned to camera view.",
        });
      }
    } catch (error) {
      console.error('Error toggling screen share:', error);
      toast({
        title: "Screen sharing failed",
        description: "Unable to share screen.",
        variant: "destructive",
      });
    }
  };

  const joinMeeting = () => {
    if (meetingId.trim()) {
      setIsJoinDialogOpen(false);
      startLocalStream();
    }
  };

  const leaveMeeting = () => {
    stopLocalStream();
    onClose?.();
  };

  if (isJoinDialogOpen) {
    return (
      <Dialog open={isJoinDialogOpen} onOpenChange={setIsJoinDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Join Video Conference</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label htmlFor="meetingId">Meeting ID</Label>
              <Input
                id="meetingId"
                value={meetingId}
                onChange={(e) => setMeetingId(e.target.value)}
                placeholder="Enter meeting ID"
              />
            </div>
            <div>
              <Label htmlFor="meetingPassword">Password (Optional)</Label>
              <Input
                id="meetingPassword"
                type="password"
                value={meetingPassword}
                onChange={(e) => setMeetingPassword(e.target.value)}
                placeholder="Enter meeting password"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Camera</Label>
                <Select value={selectedCamera} onValueChange={setSelectedCamera}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select camera" />
                  </SelectTrigger>
                  <SelectContent>
                    {cameras.map((camera) => (
                      <SelectItem key={camera.deviceId} value={camera.deviceId}>
                        {camera.label || `Camera ${camera.deviceId.slice(0, 8)}`}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Microphone</Label>
                <Select value={selectedMicrophone} onValueChange={setSelectedMicrophone}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select microphone" />
                  </SelectTrigger>
                  <SelectContent>
                    {microphones.map((mic) => (
                      <SelectItem key={mic.deviceId} value={mic.deviceId}>
                        {mic.label || `Microphone ${mic.deviceId.slice(0, 8)}`}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <Button onClick={joinMeeting} className="w-full" disabled={!meetingId.trim()}>
              Join Meeting
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <div className="fixed inset-0 bg-black z-50 flex flex-col">
      {/* Header */}
      <div className="flex items-center justify-between p-4 bg-gray-900 text-white">
        <div className="flex items-center gap-4">
          <h2 className="text-lg font-semibold">Video Conference</h2>
          <Badge variant="secondary">{participants.length} participants</Badge>
        </div>
        <Button variant="ghost" size="sm" onClick={leaveMeeting}>
          <PhoneOff className="h-4 w-4 mr-2" />
          Leave
        </Button>
      </div>

      {/* Video Area */}
      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 p-4">
        {/* Local Video */}
        <Card className="relative">
          <CardContent className="p-0">
            <video
              ref={localVideoRef}
              autoPlay
              muted
              playsInline
              className="w-full h-64 bg-gray-900 rounded-lg object-cover"
            />
            <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-sm">
              {userName} (You)
            </div>
          </CardContent>
        </Card>

        {/* Remote Video or Placeholder */}
        <Card className="relative">
          <CardContent className="p-0">
            {participants.length > 1 ? (
              <video
                ref={remoteVideoRef}
                autoPlay
                playsInline
                className="w-full h-64 bg-gray-900 rounded-lg object-cover"
              />
            ) : (
              <div className="w-full h-64 bg-gray-900 rounded-lg flex items-center justify-center">
                <div className="text-center text-gray-400">
                  <Users className="h-12 w-12 mx-auto mb-2" />
                  <p>Waiting for others to join...</p>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Controls */}
      <div className="flex items-center justify-center gap-4 p-4 bg-gray-900">
        <Button
          variant={isMuted ? "destructive" : "secondary"}
          size="lg"
          onClick={toggleMute}
          className="rounded-full w-12 h-12 p-0"
        >
          {isMuted ? <MicOff className="h-5 w-5" /> : <Mic className="h-5 w-5" />}
        </Button>

        <Button
          variant={isVideoOn ? "secondary" : "destructive"}
          size="lg"
          onClick={toggleVideo}
          className="rounded-full w-12 h-12 p-0"
        >
          {isVideoOn ? <Video className="h-5 w-5" /> : <VideoOff className="h-5 w-5" />}
        </Button>

        <Button
          variant={isScreenSharing ? "default" : "secondary"}
          size="lg"
          onClick={toggleScreenShare}
          className="rounded-full w-12 h-12 p-0"
        >
          <Share className="h-5 w-5" />
        </Button>

        <Button
          variant="secondary"
          size="lg"
          className="rounded-full w-12 h-12 p-0"
        >
          <Settings className="h-5 w-5" />
        </Button>
      </div>

      {/* Participants List */}
      <div className="absolute top-16 right-4">
        <Card className="w-64">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">Participants ({participants.length})</CardTitle>
          </CardHeader>
          <CardContent className="space-y-2">
            {participants.map((participant) => (
              <div key={participant.id} className="flex items-center gap-2">
                <div className="w-8 h-8 bg-gray-300 rounded-full flex items-center justify-center text-sm font-medium">
                  {participant.name.charAt(0).toUpperCase()}
                </div>
                <div className="flex-1">
                  <p className="text-sm font-medium">{participant.name}</p>
                  <div className="flex gap-1">
                    {participant.isMuted && <MicOff className="h-3 w-3 text-red-500" />}
                    {!participant.isVideoOn && <VideoOff className="h-3 w-3 text-red-500" />}
                    {participant.isHost && <Badge variant="secondary" className="text-xs">Host</Badge>}
                  </div>
                </div>
              </div>
            ))}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

