 */
export const SECURITY_HEADERS = {
  // Enforce HTTPS for 1 year (including subdomains)
  'Strict-Transport-Security': 'max-age=31536000; includeSubDomains; preload',
  
  // Prevent MIME type sniffing
  'X-Content-Type-Options': 'nosniff',
  
